/*
 * Localized agent-guide copy (part D) for the landing-page agent detail pages.
 * Split across part files to stay under the repo's changed-file blob guard.
 * Each entry spreads the English guide first (type-complete) then overrides the
 * rendered fields + rich payload with the translation. Machine-translated;
 * native review welcome.
 */
import type { InfoPageCopy } from './info-page-i18n';
import type { LandingLocaleCode } from './i18n';

type Guides = NonNullable<InfoPageCopy['agentGuides']>;


export function localizedAgentGuidesPartD(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'fr': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code pour le design — Open Design",
        description: "Comment les designers utilisent Claude Code pour le design d’interfaces et de sites web, et comment Open Design en fait un véritable agent de design — local-first, BYOK, avec une bibliothèque organisée de skills et de design systems.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code pour le design.",
        lead: "Claude Code est l’agent de code en terminal d’Anthropic. On l’utilise déjà pour construire des interfaces, des design systems et des landing pages. Open Design le branche sur un véritable workflow de design — apportez votre clé Anthropic ou votre abonnement Claude, gardez chaque fichier en local.",
        rich: {"heroCtaLead": "Open Design transforme Claude Code en un agent de design open source et local-first — votre clé Anthropic ou votre abonnement Claude, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Claude Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code est largement considéré comme l’agent de code au meilleur goût en frontend — il raisonne sur les interfaces avec une précision inhabituelle, nommant des valeurs hex exactes, des espacements et des échelles typographiques, et il refactorise l’UI à travers une grande base de code sans perdre le fil. Mais tel quel, il dérive encore vers un rendu générique tant que vous ne lui fournissez pas un design system, des skills et de vraies références. Voici un guide pratique et complet pour utiliser Claude Code dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow structuré avec Open Design.", "Il couvre ce qu’est réellement Claude Code, pourquoi il excelle en frontend, comment le configurer à partir de zéro, le workflow CLAUDE.md et Skills, l’aller-retour officiel avec Figma, sa comparaison avec Codex et Cursor, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Boucle de rétroaction de design avec Claude Code : un agent en terminal prenant des décisions de design précises, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : Claude Code raisonne sur des décisions d’UI précises dans le terminal, les affiche et les vérifie dans un vrai navigateur, et converge vers vos références."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-claude-code", "label": "Ce qu’est réellement Claude Code"}, {"id": "why-design", "label": "Pourquoi Claude Code est bon en design"}, {"id": "setup", "label": "Configurer Claude Code pour le design (à partir de zéro)"}, {"id": "skills-workflow", "label": "Le workflow CLAUDE.md et Skills"}, {"id": "figma", "label": "Aller-retour Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Claude Code dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Ce qu’est réellement Claude Code", "blocks": [{"kind": "p", "text": "Claude Code est l’outil de code agentique d’Anthropic. Il lit votre base de code, modifie des fichiers, exécute des commandes et s’intègre à vos outils de développement — il planifie, écrit et vérifie le travail à partir de tâches en langage naturel, plutôt que de se contenter de compléter des lignes."}, {"kind": "p", "text": "Il se décline sur plusieurs surfaces qui partagent toutes le même moteur : une CLI en terminal, des extensions IDE pour VS Code, Cursor et JetBrains, une application desktop avec revue visuelle des diffs, et une expérience web pour les tâches de longue durée. Vos fichiers CLAUDE.md, vos réglages et vos serveurs MCP s’appliquent à toutes."}, {"kind": "steps", "items": [{"label": "Fichier d’instructions", "body": "Claude Code lit un fichier CLAUDE.md à la racine de votre projet au début de chaque session — l’endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue."}, {"label": "Skills", "body": "Les Agent Skills regroupent des instructions, scripts et ressources réutilisables que Claude charge à la demande, y compris la skill officielle Frontend Design d’Anthropic pour le goût."}, {"label": "Plan et sous-agents", "body": "Il peut planifier avant d’agir et lancer des sous-agents qui travaillent en parallèle sur différentes parties d’une tâche, ce qui maintient la cohérence des grands refactors d’UI."}]}, {"kind": "ul", "items": ["Éditeur : Anthropic", "Identifiant : clé API Anthropic (BYOK, via la Console) ou abonnement Claude (Pro / Max)", "Surfaces : CLI en terminal, extensions VS Code / Cursor / JetBrains, application desktop, web"]}]}, {"id": "why-design", "heading": "Pourquoi Claude Code est bon en design", "blocks": [{"kind": "p", "text": "Parmi les agents de code, Claude Code a une réputation de goût pour le travail en frontend. Quelques raisons l’expliquent."}, {"kind": "steps", "items": [{"label": "Des décisions précises, pas vagues", "body": "Claude Code a tendance à s’engager sur des choix concrets — valeurs hex exactes, échelles d’espacement, rampes typographiques et hiérarchie des composants — au lieu de rester évasif, ce qui distingue une vraie interface d’une maquette de remplissage."}, {"label": "Un raisonnement conscient de la base de code", "body": "Avec un large contexte de travail, il refactorise l’UI à travers de nombreux fichiers à la fois, en réutilisant vos composants et tokens existants au lieu de réinventer des styles isolés."}, {"label": "Une skill frontend officielle", "body": "Anthropic fournit une skill Frontend Design qui amène Claude à définir d’abord une direction de design et l’éloigne délibérément des polices système génériques et des dégradés violets prévisibles."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle qu’Anthropic formule à propos de ses propres modèles : Claude n’a pas de goût par défaut — laissé à lui-même, il converge vers le centre statistique du web design (Inter, dégradés violets, ombres douces). Il produit de bons designs quand vous lui donnez des contraintes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Claude Code pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Claude Code capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer CLAUDE.md, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer CLAUDE.md → ajouter la skill Frontend Design → activer la vérification en navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans CLAUDE.md et orientez Claude vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Ajoutez la vérification en navigateur", "body": "Branchez un MCP Playwright ou Chrome pour que Claude rende dans un vrai navigateur et contrôle ses sorties sur les différents breakpoints, au lieu de simplement confirmer que le build passe."}]}]}, {"id": "skills-workflow", "heading": "Le workflow CLAUDE.md et Skills", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Claude Code consiste à lui donner de vraies références ainsi que votre contexte de design, puis à itérer jusqu’à ce que l’UI corresponde — avec CLAUDE.md et les Skills qui portent les contraintes pour ne pas avoir à les réexpliquer à chaque prompt."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique, même avec un agent puissant.", "Gardez votre design system et vos conventions dans CLAUDE.md, et indiquez à Claude où se trouvent les tokens et les primitives canoniques.", "Ajoutez la skill Frontend Design pour que Claude s’engage sur une véritable direction esthétique avant d’écrire du code.", "Branchez la vérification en navigateur pour que Claude rende, redimensionne aux breakpoints et compare aux références — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Déposez une image de référence dans la session et formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Faites tourner un serveur de dev en parallèle, gardez des prompts courts et ciblés, committez les bonnes itérations / annulez les mauvaises (en prévenant Claude quand vous revenez en arrière) pour que chaque passe parte d’une base propre. Utilisez le mode plan pour les refactors plus importants afin de pouvoir relire l’approche avant toute modification de fichier."}]}, {"id": "figma", "heading": "Claude Code + Figma : aller-retour design ↔ code", "blocks": [{"kind": "p", "text": "En février 2026, Anthropic et Figma ont livré une intégration bidirectionnelle de premier ordre via le serveur Figma MCP. Elle fonctionne dans les deux sens."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Sélectionnez une frame dans Figma ou collez un lien dans Claude Code, récupérez le contexte de design et demandez-lui d’implémenter la maquette avec votre bibliothèque de composants existante. Code Connect garde les sorties alignées sur vos vrais composants."}, {"label": "Code → Design", "body": "Construisez et prévisualisez une fonctionnalité dans le navigateur, puis dites « Send this to Figma » pour capturer l’UI en cours d’exécution sous forme de calques Figma éditables — écran entier ou élément sélectionné."}]}, {"kind": "p", "text": "Installez-le une fois avec claude plugin install figma@claude-plugins-official (le MCP Dev Mode requiert un plan Figma payant). Le même Figma MCP est disponible pour Claude Code, Codex, Cursor et VS Code — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Claude Code", "Décisions de design précises (hex, espacement, typographie) et raisonnement UX conscient de la base de code", "Le raisonnement frontend et les refactors à large contexte"], ["Codex", "Forte finition visuelle et compréhension d’images ; builds async en sandbox", "Les builds async délégués et les règles AGENTS.md portables"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "Malgré la réputation de goût de Claude Code, la critique la plus fréquente à l’égard du design généré par IA est qu’il a l’air générique — polices Inter, dégradés violets sur blanc, ombres douces, coins arrondis surdimensionnés, une esthétique qui « crie qu’une IA a fait ça ». Anthropic elle-même attribue cela à une convergence distributionnelle : les choix sûrs dominent les données d’entraînement du web. Parmi les autres problèmes signalés : des mises en page mobiles cassées et des instructions qui fuient dans les textes de l’UI."}, {"kind": "steps", "items": [{"label": "Installez la skill Frontend Design", "body": "Elle force Claude à s’engager sur une vraie direction et évite explicitement les polices et dégradés surexploités par l’IA."}, {"label": "Activez la vérification en navigateur", "body": "Faites en sorte que Claude rende et se contrôle lui-même sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans CLAUDE.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Claude Code dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Claude Code comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Claude Code bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Claude Code comme agent.", "Authentifiez-vous avec votre clé API Anthropic (BYOK) ou votre abonnement Claude — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Claude Code, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Claude Code est-il bon pour le travail de design ?", "text": "Oui — il est largement considéré comme l’agent de code au meilleur goût en frontend, prenant des décisions précises et conscientes de la base de code sur les valeurs hex, l’espacement et les échelles typographiques. Avec la skill Frontend Design, un design system et de vraies images de référence dans le contexte, il produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Ai-je besoin d’un abonnement Claude pour concevoir avec Claude Code ?", "text": "Vous pouvez utiliser soit une clé API Anthropic (BYOK, via la Console), soit un abonnement Claude (Pro / Max). Dans les deux cas, Open Design ne fait jamais transiter vos identifiants — ils sont utilisés directement par votre agent sur votre machine."}, {"name": "Claude Code ou Codex pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code et pour son raisonnement frontend ; Codex offre une forte finition visuelle et excelle dans les builds délégués en sandbox. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Claude Code à Figma ?", "text": "Installez le plugin Figma officiel avec claude plugin install figma@claude-plugins-official. Vous pouvez ensuite implémenter des frames Figma en code à partir du contexte de design, et renvoyer une UI en cours d’exécution vers des frames Figma éditables avec « Send this to Figma ». Le MCP Dev Mode requiert un plan Figma payant."}, {"name": "Que sont les Skills et CLAUDE.md ?", "text": "CLAUDE.md est un fichier markdown à la racine de votre projet que Claude Code lit au début de chaque session — l’endroit où encoder vos conventions de design. Les Skills regroupent des instructions et ressources réutilisables que Claude charge à la demande, y compris la skill officielle Frontend Design d’Anthropic. Open Design fournit une bibliothèque organisée des deux pour vous éviter la configuration projet par projet."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Installez la skill Frontend Design, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans CLAUDE.md et activez la vérification en navigateur. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à Anthropic ?", "text": "Non. Claude Code est un produit d’Anthropic ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. Claude et Claude Code sont des marques d’Anthropic."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Anthropic sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Claude Code, à la manière ouverte.", "ctaBody": "Apportez votre propre clé Anthropic ou votre abonnement Claude, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Claude Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex pour le design : créer des UI avec OpenAI Codex — Open Design",
        description: "Le guide pratique pour concevoir des UI et des frontends avec OpenAI Codex — installation, intégration Figma, skills, et comment éviter le rendu « IA générique ». Open Design fait de Codex un agent de design gratuit, local-first et open source.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex pour le design.",
        lead: "Codex est l’agent de code d’OpenAI. Avec son plugin Product Design et son intégration Figma, il est devenu un véritable outil de design. Open Design branche Codex sur un workflow de design open source — votre clé OpenAI ou votre abonnement ChatGPT, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Codex en un agent de design open source et local-first — votre clé OpenAI, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Codex dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex a démarré comme générateur de code, mais en 2026 il est devenu un outil crédible pour concevoir de vraies interfaces — à condition de lui donner les bonnes références, les bonnes skills et une boucle de vérification. Voici un guide pratique et complet pour utiliser Codex dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est Codex aujourd’hui, pourquoi il est soudain bon en frontend, comment le configurer à partir de zéro, la boucle capture-vers-UI, l’aller-retour officiel avec Figma, sa comparaison avec Cursor et Claude Code, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Boucle de rétroaction de design avec Codex : un agent en terminal, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : Codex construit l’UI dans le terminal, la rend et la vérifie dans un vrai navigateur, et itère par rapport à vos références."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-codex", "label": "Ce qu’est réellement OpenAI Codex"}, {"id": "why-design", "label": "Pourquoi Codex est bon en design désormais"}, {"id": "setup", "label": "Configurer Codex pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture-vers-UI"}, {"id": "figma", "label": "Aller-retour Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Codex dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Ce qu’est réellement OpenAI Codex (et ce qu’il n’est pas)", "blocks": [{"kind": "p", "text": "D’abord, une mise au point qui désarçonne presque tous ceux qui cherchent « Codex ». Le Codex d’OpenAI d’origine était un modèle de complétion de code de 2021 qui propulsait les premiers GitHub Copilot et a été déprécié en 2023. Ce n’est pas le sujet de cette page. Le Codex d’aujourd’hui est l’outil de code agentique d’OpenAI — il planifie, écrit, exécute et vérifie du code à partir de tâches en langage naturel."}, {"kind": "p", "text": "Le Codex moderne se décline sur quatre surfaces : une CLI en terminal (réécrite en Rust, sous licence Apache-2.0), une extension IDE pour VS Code, Cursor et Windsurf, une expérience cloud/web pour les tâches async déléguées, et une application desktop avec un navigateur intégré et Computer Use."}, {"kind": "steps", "items": [{"label": "Modèle par défaut", "body": "À la mi-2026, le modèle recommandé est gpt-5.5, gpt-5.4 étant le modèle qu’OpenAI a explicitement entraîné pour le frontend et l’usage de l’ordinateur."}, {"label": "Fichier d’instructions", "body": "Codex lit un fichier AGENTS.md dans votre projet (un standard inter-outils) pour les règles de projet — l’endroit naturel pour encoder vos conventions de design."}, {"label": "Sandbox", "body": "Il s’exécute dans un sandbox au niveau noyau (workspace-write par défaut), de sorte qu’un agent qui modifie votre UI ne peut pas sortir du projet."}]}, {"kind": "ul", "items": ["Éditeur : OpenAI", "Identifiant : clé API OpenAI (BYOK) ou abonnement ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licence de la CLI : Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Pourquoi Codex est bon en design désormais", "blocks": [{"kind": "p", "text": "Trois choses ont convergé début 2026 pour faire de Codex un véritable outil de design plutôt qu’un générateur de code générique."}, {"kind": "steps", "items": [{"label": "Un modèle entraîné pour le frontend", "body": "OpenAI a livré GPT-5.4, son premier modèle mainline entraîné pour le frontend et l’usage de l’ordinateur, avec une bien meilleure compréhension d’images tout au long du workflow de design et une auto-vérification renforcée. Il peut même générer des mood boards et des options visuelles avant de s’engager sur les assets finaux."}, {"label": "Une skill frontend officielle", "body": "Le catalogue openai/skills fournit une frontend-skill organisée qui impose un vrai goût : des mises en page sans cartes, des héros pleine largeur, une hiérarchie qui met la marque d’abord, un mouvement sobre, deux familles typographiques et une couleur d’accent au maximum — et amène Codex à écrire une thèse visuelle avant de construire."}, {"label": "La vérification en navigateur", "body": "Avec la skill Playwright, Codex ouvre un vrai navigateur, redimensionne aux breakpoints et compare ses sorties à la référence au lieu de simplement vérifier que le build passe."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon derrière ces trois points : Codex n’a pas de goût par défaut. Il produit de bons designs quand vous lui donnez des contraintes — un design system, une skill esthétique et des références concrètes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Codex pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Codex capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer, installer la skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer AGENTS.md → installer la skill frontend → activer la vérification en navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans AGENTS.md ou un DESIGN.md et orientez Codex vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Choisissez le bon niveau de raisonnement", "body": "OpenAI note que les niveaux de raisonnement faibles à moyens produisent souvent de meilleurs résultats frontend que le réglage le plus élevé."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Codex consiste à transformer une image de référence en une UI fonctionnelle et responsive, puis à itérer jusqu’à ce qu’elle corresponde. Les recommandations d’OpenAI elles-mêmes se résument à cinq étapes."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à Codex où se trouvent les tokens et les primitives canoniques.", "Activez la skill interactive Playwright pour que Codex rende dans un vrai navigateur et redimensionne aux breakpoints.", "Itérez en faisant comparer à Codex son implémentation avec les captures — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Fournissez les images en glissant une capture dans le terminal ou via le flag image, puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Faites tourner un serveur de dev dans un second terminal, gardez des prompts courts et ciblés, committez les bonnes itérations / annulez les mauvaises (en prévenant Codex quand vous revenez en arrière) pour que chaque passe parte d’une base propre."}]}, {"id": "figma", "heading": "Codex + Figma : aller-retour design ↔ code", "blocks": [{"kind": "p", "text": "En février 2026, OpenAI et Figma ont annoncé un partenariat officiel, transformant la précédente bêta du Figma MCP en une intégration bidirectionnelle de premier ordre. Elle fonctionne dans les deux sens."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Copiez le « link to selection » d’une frame dans Figma, collez-le dans Codex avec get_design_context, et demandez-lui d’implémenter la maquette avec votre bibliothèque de composants existante."}, {"label": "Code → Design", "body": "L’outil generate_figma_design (« Code to Canvas ») retransforme une UI en cours d’exécution en frames Figma éditables — écran entier, élément sélectionné ou fichier complet."}]}, {"kind": "p", "text": "Le Figma MCP s’exécute comme un serveur distant et est exempté des limites de débit. Ajoutez-le une fois et il est disponible pour Codex, Claude Code, Cursor, VS Code et plus encore — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Codex", "Forte finition visuelle après GPT-5.4 + frontend-skill ; compréhension d’images", "Les builds async délégués, les exécutions en sandbox, les règles AGENTS.md portables"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par Codex est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page mobiles cassées, des instructions qui fuient dans les textes de l’UI et des limites d’usage atteintes rapidement."}, {"kind": "steps", "items": [{"label": "Installez une skill frontend", "body": "Une skill esthétique organisée force Codex à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Activez la vérification Playwright", "body": "Faites en sorte que Codex rende et se contrôle lui-même sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans AGENTS.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Codex dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Codex comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Codex bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Codex comme agent.", "Authentifiez-vous avec votre clé API OpenAI (BYOK) ou votre abonnement ChatGPT — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Codex, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "OpenAI Codex peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill frontend, un design system et de vraies images de référence dans le contexte, Codex (surtout sur GPT-5.4) produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "S’agit-il du plugin Product Design d’OpenAI Codex ?", "text": "Non. Open Design est un projet open source indépendant qui intègre Codex comme agent. Il complète l’outillage propre d’OpenAI avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement ChatGPT pour concevoir avec Codex ?", "text": "Vous pouvez utiliser soit une clé API OpenAI (BYOK), soit votre abonnement ChatGPT. La connexion ChatGPT offre généralement des limites plus généreuses ; Open Design ne fait jamais transiter vos identifiants, dans les deux cas."}, {"name": "Codex ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code ; Codex offre une forte finition visuelle après GPT-5.4 et excelle dans les builds délégués en sandbox. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Codex à Figma ?", "text": "Ajoutez le serveur Figma MCP officiel (codex mcp add figma --url https://mcp.figma.com/mcp). Vous pouvez ensuite implémenter des frames Figma en code avec get_design_context et renvoyer une UI en cours d’exécution vers des frames Figma éditables avec generate_figma_design."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Installez une skill frontend, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans AGENTS.md et activez la vérification Playwright. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à OpenAI ?", "text": "Non. Codex est un produit d’OpenAI ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. OpenAI et Codex sont des marques d’OpenAI."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants OpenAI sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Codex, à la manière ouverte.", "ctaBody": "Apportez votre propre clé OpenAI, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Codex dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor pour les designers — Open Design",
        description: "Comment les designers utilisent Cursor pour le design d’interfaces et de sites web — le Design Mode, Figma-vers-code, le Figma MCP — et comment Open Design en fait un agent de design open source et local-first.",
        breadcrumb: "Cursor Agent",
        label: "Agent · Cursor",
        heading: "Cursor pour les designers.",
        lead: "Cursor est l’éditeur de code IA, désormais doté d’un Design Mode visuel. Les designers l’utilisent pour modifier l’UI en pointant et en dessinant, et pour transformer Figma en code. Open Design branche Cursor Agent sur un workflow de design open source qui garde vos fichiers en local.",
        rich: {"heroCtaLead": "Open Design transforme Cursor en un agent de design open source et local-first — votre compte Cursor ou vos clés de modèle, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser Cursor dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor est l’éditeur de code IA-first qui a fait de « construire et regarder le rendu » la façon par défaut de livrer de l’UI. Avec le mode Agent, les éditions inline, un aperçu intégré à l’éditeur et Figma via MCP, il est devenu un véritable outil de design — à condition de lui donner les bonnes références, les bonnes règles et une boucle de vérification. Voici un guide pratique et complet pour utiliser Cursor dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est réellement Cursor, pourquoi sa boucle serrée d’itération est bonne pour le design, comment le configurer à partir de zéro, la boucle capture-et-aperçu-vers-UI, l’aller-retour Figma via MCP, sa comparaison avec Codex et Claude Code, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Convergence de design avec Cursor : l’éditeur à gauche, un hub organisé de skills et de design systems au centre avec la marque Cursor au milieu, et une UI rendue à droite", "caption": "L’idée centrale : Cursor modifie et affiche l’UI dans l’éditeur, tandis qu’un hub de design organisé lui fournit le système, les skills et les références qui font paraître les sorties intentionnelles."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-cursor", "label": "Ce qu’est réellement Cursor"}, {"id": "why-design", "label": "Pourquoi Cursor est bon en design"}, {"id": "setup", "label": "Configurer Cursor pour le design (à partir de zéro)"}, {"id": "preview-workflow", "label": "Le workflow aperçu-vers-UI"}, {"id": "figma", "label": "Cursor + Figma via MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec Cursor dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Ce qu’est réellement Cursor", "blocks": [{"kind": "p", "text": "Cursor est un éditeur de code IA-first conçu par Anysphere. C’est un fork de VS Code, il conserve donc l’éditeur, les extensions et les raccourcis clavier familiers, mais reconstruit le workflow autour d’un agent IA capable de lire tout votre projet, de modifier plusieurs fichiers, d’exécuter des commandes et d’itérer avec vous dans la boucle."}, {"kind": "p", "text": "Pour le travail de design, les surfaces importantes sont le mode Agent (vous décrivez un résultat et Cursor planifie et modifie à travers les fichiers), les éditions inline et les complétions Tab pour des ajustements rapides, un aperçu / navigateur intégré à l’éditeur pour voir l’UI en cours d’exécution sans quitter la fenêtre, et le support MCP qui lui permet d’intégrer du contexte externe comme un fichier Figma en direct."}, {"kind": "steps", "items": [{"label": "Règles de projet", "body": "Cursor lit des fichiers d’instructions de projet — des règles `.mdc` versionnées sous `.cursor/rules`, et un simple `AGENTS.md` — pour que vous puissiez encoder vos conventions de design là où l’agent les lit à chaque exécution."}, {"label": "Modèles", "body": "Cursor est flexible côté modèles : il est livré avec des modèles de pointe via votre abonnement et prend aussi en charge l’apport de vos propres clés de modèle, vous choisissez donc le moteur derrière le même workflow d’éditeur."}, {"label": "MCP", "body": "Il parle le Model Context Protocol, de sorte que des serveurs externes — le plus pertinent étant le serveur Figma MCP — deviennent un contexte de premier ordre pour l’agent."}]}, {"kind": "ul", "items": ["Éditeur : Anysphere", "Identifiant : compte / abonnement Cursor (Hobby / Pro / Business) ou vos propres clés de modèle (BYOK)", "Forme : éditeur de code IA-first (fork de VS Code) avec un agent et un aperçu intégrés à l’éditeur"]}]}, {"id": "why-design", "heading": "Pourquoi Cursor est bon en design", "blocks": [{"kind": "p", "text": "L’avantage de Cursor en design n’est pas une fonctionnalité unique — c’est la rapidité de la boucle construire-et-voir. Trois choses le font ressembler à un outil de design plutôt qu’à un générateur de code générique."}, {"kind": "steps", "items": [{"label": "Une boucle d’itération serrée", "body": "Vous donnez un prompt, Cursor modifie à travers les fichiers, et l’aperçu intégré à l’éditeur affiche le résultat immédiatement — vous ajustez ainsi l’espacement, la hiérarchie et le mouvement en quelques secondes au lieu de faire des allers-retours entre un terminal et un navigateur séparés."}, {"label": "L’édition visuelle directe", "body": "Au-delà du chat, Cursor vous laisse sélectionner des éléments dans l’aperçu et ajuster les styles, de sorte que les petites corrections visuelles ressemblent à des éditions de design plutôt qu’à de l’archéologie de code."}, {"label": "Règles de projet et contexte MCP", "body": "Avec `.cursor/rules` (ou `AGENTS.md`) et le serveur Figma MCP, l’agent travaille par rapport à vos tokens, composants et vraies specs de design au lieu de deviner."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle que tout agent enseigne : Cursor n’a pas de goût par défaut. Il produit de bons designs quand vous lui donnez des contraintes — un design system, une skill esthétique et des références concrètes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Cursor pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un Cursor capable de construire, prévisualiser et vérifier l’UI par rapport à votre design system."}, {"kind": "ol", "items": ["Installez Cursor depuis cursor.com et connectez-vous avec votre compte Cursor, ou configurez vos propres clés de modèle (BYOK) dans les Réglages.", "Ouvrez votre projet et choisissez un modèle dans le panneau chat / Agent.", "Ajoutez des règles de projet : créez `.cursor/rules/*.mdc` pour des conventions structurées et délimitées par glob, ou un simple `AGENTS.md` pour des instructions simples et lisibles.", "Connectez le serveur Figma MCP (optionnel) pour que l’agent puisse lire le contexte de design en direct.", "Faites tourner votre serveur de dev et utilisez l’aperçu intégré à l’éditeur pour voir et vérifier l’UI au fil de vos itérations."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier, configurer les règles, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier → configurer les règles de projet → ajouter une skill → activer la vérification par aperçu."}, {"kind": "p", "text": "Un fichier de règles de projet minimal amène l’agent à concevoir pour une marque au lieu de retomber sur un rendu générique. Placez-le là où Cursor le lit à chaque exécution :"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans `.cursor/rules` ou `AGENTS.md` et orientez Cursor vers eux, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Gardez des prompts courts", "body": "La boucle serrée de Cursor récompense les demandes ciblées — itérez un composant ou un état à la fois et observez l’aperçu entre chaque passe."}]}]}, {"id": "preview-workflow", "heading": "Le workflow aperçu-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Cursor consiste à transformer une référence en une UI fonctionnelle et responsive, puis à itérer dans l’éditeur jusqu’à ce qu’elle corresponde — en observant l’aperçu en direct tout du long au lieu de deviner."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à Cursor où se trouvent les tokens et les primitives canoniques.", "Gardez l’aperçu intégré à l’éditeur ouvert et votre serveur de dev en route pour que chaque édition s’affiche immédiatement aux breakpoints qui vous importent.", "Itérez en comparant l’UI rendue avec les références — et utilisez la sélection directe d’éléments dans l’aperçu pour les petites corrections visuelles."]}, {"kind": "p", "text": "Fournissez les références en attachant une image au chat, puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Committez les bonnes itérations et annulez les mauvaises (en prévenant Cursor quand vous revenez en arrière) pour que chaque passe parte d’une base propre — la même discipline qui empêche toute boucle d’agent de dériver."}]}, {"id": "figma", "heading": "Cursor + Figma : design ↔ code via MCP", "blocks": [{"kind": "p", "text": "Cursor se connecte à Figma via le serveur Figma MCP officiel, qui donne à l’agent un accès structuré à un fichier Figma en direct au lieu d’une capture à plat. Cela retire le tâtonnement du handoff."}, {"kind": "steps", "items": [{"label": "Design → Code", "body": "Copiez le lien d’une frame dans Figma, collez-le dans Cursor et demandez-lui d’implémenter la maquette. Le serveur MCP expose un vrai contexte de design — composants, variables, données de mise en page, tokens — pour que le code généré corresponde à la source au lieu de l’approximer."}, {"label": "Restez aligné", "body": "Avec des design tokens, des styles et des composants utilisés de manière cohérente dans Figma (et Code Connect là où c’est disponible), les sorties de Cursor restent mappées sur votre vrai design system plutôt que de réinventer des primitives."}]}, {"kind": "p", "text": "Configurez le serveur Figma MCP distant une fois et il est disponible pour Cursor en tant que contexte de premier ordre. Comme MCP est un standard ouvert, le même serveur est réutilisable à travers Cursor, Claude Code, Codex et VS Code — exactement le genre de capacité portable et multi-agent qu’Open Design est conçu pour orchestrer."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct dans l’éditeur et édition directe des éléments", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"], ["Codex", "Forte finition visuelle avec une skill frontend ; compréhension d’images et exécutions en sandbox", "Les builds async délégués et les règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : les trois retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par Cursor est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page qui cassent sur mobile et des instructions qui fuient dans les textes de l’UI."}, {"kind": "steps", "items": [{"label": "Ajoutez une skill de design", "body": "Une skill esthétique organisée force Cursor à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Utilisez l’aperçu pour vérifier", "body": "Rendez et auto-contrôlez sur les différents breakpoints dans l’aperçu intégré à l’éditeur pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans `.cursor/rules`", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Cursor dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Cursor comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend Cursor bon soit présent dès la première exécution, et non assemblé à la main à chaque fois."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Cursor comme agent.", "Authentifiez-vous avec votre compte Cursor ou vos propres clés de modèle (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Cursor, la même clé — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Cursor peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill de design, un design system et de vraies images de référence dans le contexte, Cursor produit une UI responsive de qualité production, et son aperçu intégré à l’éditeur vous laisse la vérifier et l’affiner visuellement. Sans ce contexte, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Est-ce un produit officiel de Cursor ?", "text": "Non. Open Design est un projet open source indépendant qui intègre Cursor comme agent. Il complète Cursor avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement Cursor pour concevoir avec Cursor ?", "text": "Vous pouvez utiliser un compte / abonnement Cursor ou apporter vos propres clés de modèle (BYOK). Open Design ne fait jamais transiter vos identifiants, dans les deux cas — ils sont utilisés directement par votre agent."}, {"name": "Cursor ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code ; l’avantage de Cursor est sa boucle serrée construire-et-voir avec un aperçu en direct au sein de l’éditeur. Beaucoup d’équipes utilisent les deux — Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Cursor à Figma ?", "text": "Ajoutez le serveur Figma MCP officiel dans Cursor, puis collez un lien de frame Figma dans le chat et demandez à Cursor de l’implémenter. Le serveur expose de vrais composants, variables et données de mise en page pour que le code généré corresponde à la maquette source."}, {"name": "Comment éviter l’esthétique générique « AI slop » ?", "text": "Ajoutez une skill de design, fournissez de vrais tokens de design et des captures de référence, encodez les règles de marque dans `.cursor/rules` ou `AGENTS.md`, et vérifiez sur les différents breakpoints dans l’aperçu. Open Design les livre sous forme de bibliothèque organisée pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à Cursor ou Anysphere ?", "text": "Non. Cursor est un produit d’Anysphere ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie. Cursor et Anysphere sont des marques d’Anysphere, Inc."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Cursor ou de modèle sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Cursor, à la manière ouverte.", "ctaBody": "Apportez votre propre compte Cursor ou vos clés de modèle, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Cursor dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode pour le design — créer des UI avec l’agent open source",
        description: "Comment concevoir des UI et des frontends avec OpenCode — fichiers design.md, skills UI/UX, le Figma MCP — et comment Open Design fait d’OpenCode un agent de design gratuit, local-first et open source.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode pour le design.",
        lead: "OpenCode est l’agent de code IA en terminal, open source. Les designers lui ajoutent des skills de design et des fichiers DESIGN.md pour générer de vraies UI. Open Design en fait un workflow structuré et open source — apportez vos clés de fournisseur, gardez tout en local.",
        rich: {"heroCtaLead": "Open Design transforme OpenCode en un agent de design open source et local-first — n’importe quel modèle de votre choix avec votre propre clé de fournisseur, vos fichiers, et autour, une bibliothèque organisée de skills et de design systems.", "heroCtaActions": [{"label": "Utiliser OpenCode dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode est un agent de code IA open source, pensé d’abord pour le terminal et délibérément agnostique au modèle : vous apportez votre propre clé de fournisseur et exécutez le modèle de votre choix derrière le même workflow. Cette ouverture en fait une base naturelle pour le travail de design — mais, comme tout agent, il ne produit de bonnes UI que si vous lui donnez les bonnes références, les bonnes skills et une boucle de vérification. Voici un guide pratique et complet pour utiliser OpenCode dans un travail d’UI, de frontend et de design system, et pour l’intégrer à un workflow de design structuré avec Open Design.", "Il couvre ce qu’est réellement OpenCode, pourquoi un agent ouvert et agnostique au modèle convient au design, comment le configurer à partir de zéro, la boucle capture-vers-UI, comment AGENTS.md et MCP l’étendent, sa comparaison avec Codex, Claude Code et Cursor, les pièges qui rendent les sorties d’IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte et local-first — un appariement naturel, puisque les deux projets sont open source et s’exécutent sur votre propre machine."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Boucle de rétroaction de design avec OpenCode : un agent TUI en terminal, un navigateur affichant l’UI et un espace de travail, avec une flèche de rétroaction qui boucle", "caption": "La boucle centrale : OpenCode construit l’UI dans le terminal, la rend et la vérifie dans un vrai navigateur, et itère par rapport à vos références — sur le modèle de votre choix."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-opencode", "label": "Ce qu’est réellement OpenCode"}, {"id": "why-design", "label": "Pourquoi un agent ouvert et tout-modèle convient au design"}, {"id": "setup", "label": "Configurer OpenCode pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture-vers-UI"}, {"id": "extend", "label": "AGENTS.md, MCP et sessions partageables"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Les pièges et le rendu « AI slop »"}, {"id": "open-design", "label": "Concevoir avec OpenCode dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Ce qu’est réellement OpenCode", "blocks": [{"kind": "p", "text": "OpenCode est un agent de code IA open source conçu pour le terminal, maintenu par l’équipe derrière SST (Anomaly Innovations). Il lit votre dépôt, exécute des commandes, modifie des fichiers et dialogue avec un grand modèle de langage — mais, contrairement aux agents liés à un éditeur, il ne fournit pas son propre modèle. Vous le pointez vers le fournisseur et le modèle de votre choix et apportez votre propre clé."}, {"kind": "p", "text": "Il s’exécute comme une UI en terminal (TUI), avec une application desktop et des extensions IDE par-dessus le même moteur. Sous le capot, il utilise une architecture client/serveur, de sorte que l’agent qui fait le travail est découplé de la surface depuis laquelle vous le pilotez. Deux agents intégrés — build et plan — se basculent avec la touche Tab."}, {"kind": "steps", "items": [{"label": "Agnostique au modèle", "body": "Les modèles et fournisseurs proviennent de models.dev, un catalogue ouvert. Vous les configurez dans opencode.json avec une chaîne provider/model-id et pouvez désactiver les fournisseurs que vous ne voulez pas charger — le même workflow de design s’exécute ainsi sur Anthropic, OpenAI, Google, OpenRouter, des modèles locaux et plus encore."}, {"label": "Fichier d’instructions", "body": "OpenCode lit un fichier AGENTS.md dans votre projet (le standard inter-outils, également compatible avec CLAUDE.md) pour les règles de projet — l’endroit naturel pour encoder vos conventions de design. Exécutez /init pour en générer un."}, {"label": "Extensible", "body": "Il prend en charge l’intégration LSP, les serveurs MCP, les thèmes, les raccourcis clavier et les commandes personnalisées, ainsi que des liens de session partageables pour la collaboration."}]}, {"kind": "ul", "items": ["Mainteneur : SST / Anomaly Innovations (projet open source)", "Identifiant : votre/vos propre(s) clé(s) API de fournisseur de modèle — BYOK, sans verrouillage par l’éditeur", "Licence : MIT, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent ouvert et tout-modèle convient au travail de design", "blocks": [{"kind": "p", "text": "OpenCode n’a pas un unique « modèle de design » comme en a un agent d’éditeur — et c’est tout l’intérêt. Parce qu’il est agnostique au modèle et ouvert, vous pouvez exécuter le même workflow de design sur le modèle actuellement le meilleur en frontend, en changer plus tard, ou vous rabattre sur un modèle local, le tout sans modifier votre configuration."}, {"kind": "p", "text": "Mais le choix du modèle seul n’achète pas le goût. Comme tout agent de code, OpenCode produit une UI générique tant que vous ne lui donnez pas de contraintes. Une bonne sortie de design provient de trois entrées que vous fournissez."}, {"kind": "steps", "items": [{"label": "Un design system", "body": "De vrais tokens, primitives et conventions que l’agent réutilise, pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique."}, {"label": "Une skill esthétique", "body": "Une skill organisée qui impose un vrai goût — mouvement sobre, hiérarchie qui met la marque d’abord, deux familles typographiques et une couleur d’accent au maximum — et amène l’agent à s’engager sur une direction avant de construire."}, {"label": "Des références concrètes", "body": "De vraies images de référence et plusieurs états (desktop et mobile, survol, vide, chargement), pas un unique visuel héros."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Schéma montrant un design system, une skill et une image de référence convergeant vers une bonne sortie de design", "caption": "Le goût vient de trois entrées que vous fournissez : un design system, une skill et de vraies images de référence — indépendamment du modèle que vous exécutez."}, {"kind": "p", "text": "La leçon : OpenCode vous donne la liberté du modèle, mais le goût vient toujours d’un contexte de design organisé. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent — tous deux sont open source et local-first (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer OpenCode pour le design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet, d’une machine vierge à un OpenCode capable de construire et de vérifier des UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, authentifier avec votre clé de fournisseur, configurer AGENTS.md, ajouter une skill, vérifier", "caption": "La séquence de configuration : installer → authentifier (votre clé de fournisseur) → configurer AGENTS.md → ajouter une skill → vérifier dans un vrai navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Mettez vos tokens, primitives et conventions dans AGENTS.md (ou un DESIGN.md référencé depuis lui) pour que les sorties correspondent à une marque au lieu de retomber sur un rendu générique. L’option instructions dans opencode.json peut pointer vers des fichiers de règles supplémentaires via des globs."}, {"label": "Choisissez un modèle capable", "body": "Parce qu’OpenCode est agnostique au modèle, choisissez le fournisseur/modèle actuellement le plus fort en frontend pour la passe de design — et gardez le reste de votre workflow inchangé."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec n’importe quel agent consiste à transformer une image de référence en une UI fonctionnelle et responsive, puis à itérer jusqu’à ce qu’elle corresponde. La même structure en cinq étapes s’applique dans OpenCode."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (desktop et mobile, survol, vide, chargement), pas seulement un visuel héros.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique.", "Préparez un design system et indiquez à OpenCode où se trouvent les tokens et les primitives canoniques (dans AGENTS.md).", "Faites tourner un serveur de dev et faites rendre l’agent dans un vrai navigateur, en redimensionnant aux breakpoints pour contrôler le résultat.", "Itérez en faisant comparer à OpenCode son implémentation avec les captures — au lieu de simplement confirmer que ça build."]}, {"kind": "p", "text": "Référencez des fichiers avec @ dans le TUI pour une recherche floue de votre répertoire de travail, exécutez des commandes shell en ligne avec un ! en tête, et déclenchez des actions avec les commandes /. Puis formulez le prompt avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, committez les bonnes itérations et annulez les mauvaises (en prévenant OpenCode quand vous revenez en arrière), pour que chaque passe parte d’une base propre."}]}, {"id": "extend", "heading": "AGENTS.md, MCP et sessions partageables", "blocks": [{"kind": "p", "text": "Trois points d’extension rendent OpenCode pratique pour un travail de design durable, et tous trois se projettent proprement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Règles AGENTS.md", "body": "Les règles de projet vivent dans un AGENTS.md à la racine du dépôt (ou des règles globales dans ~/.config/opencode/AGENTS.md). C’est le foyer durable de vos conventions de design, lu à chaque exécution, et il est compatible avec les fichiers CLAUDE.md qu’utilisent d’autres agents."}, {"label": "Serveurs MCP", "body": "OpenCode prend en charge à la fois les serveurs MCP locaux (command) et distants (URL), configurés sous la clé mcp — la façon portable d’apporter du contexte de design et des outils externes qui fonctionnent à travers les agents, pas seulement OpenCode."}, {"label": "Sessions partageables", "body": "La commande /share crée un lien public vers une conversation pour la collaboration ou la revue, et /unshare le révoque — utile pour obtenir des retours sur une passe de design."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agent — exactement le genre de chose qu’Open Design est conçu pour orchestrer, plutôt que de recréer projet par projet."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équilibré :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["OpenCode", "Open source et agnostique au modèle ; exécutez n’importe quel fournisseur derrière un seul workflow en terminal", "La liberté BYOK, le changement de modèle, les configurations entièrement ouvertes et local-first"], ["Codex", "Forte finition visuelle avec une skill frontend ; compréhension d’images", "L’async délégué, les builds en sandbox, les règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactors à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions inline", "Le travail d’UI en boucle serrée d’itération au sein d’un IDE"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle, ce qui est précisément pourquoi un agent ouvert comme OpenCode s’accorde si bien avec une couche de design ouverte."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « AI slop »", "blocks": [{"kind": "p", "text": "La critique la plus fréquente à l’égard du design généré par IA est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page mobiles cassées et des instructions qui fuient dans les textes de l’UI. Aucun de ces problèmes n’est propre à OpenCode ; c’est ce qui arrive quand un agent, quel qu’il soit, s’exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez une skill esthétique", "body": "Une skill de design organisée force l’agent à s’engager sur une vraie direction au lieu du rendu par défaut."}, {"label": "Vérifiez dans un vrai navigateur", "body": "Rendez et auto-contrôlez sur les différents breakpoints pour que les mises en page ne cassent pas en silence sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures de référence sont le plus grand levier sur la qualité des sorties."}, {"label": "Encodez les règles dans AGENTS.md", "body": "Mettez des règles de style comme « pas de hero cards, deux familles typographiques au maximum, hiérarchie qui met la marque d’abord » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design organisé — quel que soit le modèle que vous exécutez. Maintenir ce contexte à la main, projet par projet, est le labeur qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec OpenCode dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite OpenCode comme un adaptateur de première partie et l’entoure d’une bibliothèque organisée de skills et de design systems, d’un pipeline de rendu structuré et d’une UI desktop locale — pour que le contexte de design qui rend tout agent bon soit présent dès la première exécution, et non assemblé à la main à chaque fois. Les deux projets sont open source et local-first, ce qui rend l’appariement naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez OpenCode comme agent.", "Authentifiez-vous avec votre propre clé API de fournisseur de modèle (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez n’importe quel fournisseur et modèle, plus un design system et une skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent OpenCode, la même liberté de modèle — auxquels s’ajoute un véritable workflow de design open source, portable, autour de lui. C’est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "OpenCode peut-il vraiment faire du travail de design ?", "text": "Oui — avec une skill esthétique, un design system et de vraies images de référence dans le contexte, OpenCode produit une UI responsive de qualité production et peut la vérifier dans un navigateur. Parce qu’il est agnostique au modèle, vous exécutez celui qui est actuellement le meilleur en frontend. Sans ce contexte organisé, il a tendance à retomber sur un rendu générique, et c’est l’écart que comble Open Design."}, {"name": "Quel modèle utiliser avec OpenCode pour le design ?", "text": "Celui que vous voulez — OpenCode est agnostique au fournisseur via models.dev, vous pouvez donc exécuter Anthropic, OpenAI, Google, OpenRouter ou des modèles locaux derrière le même workflow et en changer à tout moment. La qualité de la sortie de design dépend bien plus de votre skill, de votre design system et de vos références que du modèle seul."}, {"name": "Open Design est-il fait par l’équipe OpenCode (SST) ?", "text": "Non. Open Design est un projet open source indépendant qui intègre OpenCode comme agent. Il complète OpenCode avec une bibliothèque de skills et de design systems ouverte et local-first."}, {"name": "Ai-je besoin d’un abonnement spécial pour concevoir avec OpenCode ?", "text": "Non — OpenCode est BYOK. Vous apportez votre propre clé API de fournisseur de modèle, et Open Design ne fait jamais transiter vos identifiants. Il n’y a pas de verrouillage par l’éditeur."}, {"name": "OpenCode, Codex ou Claude Code pour le design frontend ?", "text": "Tous sont solides, et beaucoup d’équipes les combinent. L’avantage d’OpenCode est d’être entièrement open source et agnostique au modèle ; Codex excelle dans les builds délégués en sandbox ; Claude Code est reconnu pour ses décisions de design précises et conscientes de la base de code. Open Design vous laisse changer d’agent sans changer votre workflow de design."}, {"name": "Comment étendre OpenCode pour le contexte de design ?", "text": "Encodez les règles dans AGENTS.md, ajoutez des serveurs MCP sous la clé mcp pour des outils portables et du contexte de design, et utilisez les sessions partageables pour la revue. Open Design fournit une bibliothèque organisée de skills et de design systems pour vous éviter la configuration projet par projet."}, {"name": "Open Design est-il affilié à OpenCode ou SST ?", "text": "Non. OpenCode est un projet open source maintenu par SST (Anomaly Innovations) ; Open Design est un projet open source indépendant qui le prend en charge comme adaptateur de première partie."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants de fournisseur de modèle sont utilisés directement par votre agent, jamais routés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec OpenCode, à la manière ouverte.", "ctaBody": "Apportez votre propre clé de fournisseur de modèle, gardez chaque fichier en local et obtenez une bibliothèque de design organisée autour de l’agent ouvert que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser OpenCode dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'gemini': {
        ...en['gemini']!,
        title: "Gemini CLI pour le design — Open Design",
        description: "Comment on utilise Gemini CLI de Google pour le design d’interfaces et le web — sa compréhension multimodale des images, son contexte de 1 M de tokens, GEMINI.md et MCP — et comment Open Design transforme Gemini CLI en agent de design open source, local d’abord.",
        breadcrumb: "Gemini CLI",
        label: "Agent · Gemini CLI",
        heading: "Gemini CLI pour le design.",
        lead: "Gemini CLI est l’agent de terminal open source de Google. Ses modèles multimodaux lisent les captures d’écran et son contexte de 1 M de tokens contient tout un design system, ce qui en fait un véritable outil de design — dès lors que vous lui donnez des références, des conventions et une boucle de vérification. Open Design l’intègre dans un workflow de design open source : votre compte Google ou votre clé API, vos fichiers, en local d’abord.",
        rich: {"heroCtaLead": "Open Design transforme Gemini CLI en agent de design open source, local d’abord — votre compte Google ou votre clé API Gemini, vos fichiers, avec une bibliothèque sélectionnée de skills et de design systems tout autour.", "heroCtaActions": [{"label": "Utiliser Gemini CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Gemini CLI est l’agent IA open source de Google pour le terminal. Deux éléments le rendent particulièrement intéressant pour le design : ses modèles sont fortement multimodaux, si bien qu’il lit une capture d’écran et raisonne sur la mise en page, les espacements et la hiérarchie ; et sa fenêtre de contexte de 1 M de tokens peut contenir un design system et une base de code entiers à la fois. Associé aux bonnes références, aux bonnes conventions et à une boucle de vérification, il construit des interfaces réelles et responsives — et il est gratuit pour démarrer avec un compte Google. Voici un guide pratique et de bout en bout pour utiliser Gemini CLI sur des travaux d’interface, de frontend et de design system, et pour l’intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu’est réellement Gemini CLI, pourquoi ses modèles multimodaux et son immense contexte conviennent au design, comment le configurer à partir de zéro, la boucle capture d’écran vers interface, comment GEMINI.md et MCP l’étendent, comment il se compare à Codex, Claude Code et Cursor, les pièges qui font paraître les rendus IA génériques, et comment Open Design comble l’écart en tant que couche de design ouverte, locale d’abord — un duo naturel, puisque les deux sont open source et tournent sur votre propre machine."], "heroImage": {"src": "/agents/gemini-design/gemini-design-hero.webp", "alt": "Boucle de feedback de design avec Gemini CLI : un agent de terminal lisant une image de référence, un navigateur affichant l’interface et un espace de travail, avec une flèche de retour qui boucle", "caption": "La boucle centrale : Gemini CLI lit vos références dans le terminal, construit et vérifie l’interface dans un vrai navigateur, puis itère par rapport à elles — avec tout un design system en contexte."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-gemini-cli", "label": "Ce qu’est réellement Gemini CLI"}, {"id": "why-design", "label": "Pourquoi multimodal + immense contexte conviennent au design"}, {"id": "setup", "label": "Configurer Gemini CLI pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d’écran vers interface"}, {"id": "extend", "label": "GEMINI.md, MCP et extensions"}, {"id": "vs", "label": "Gemini CLI vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Pièges et le rendu « bouillie IA »"}, {"id": "open-design", "label": "Concevoir avec Gemini CLI dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-gemini-cli", "heading": "Ce qu’est réellement Gemini CLI", "blocks": [{"kind": "p", "text": "Gemini CLI est un agent IA open source (Apache-2.0) que Google propose pour le terminal. Il lit votre dépôt, modifie des fichiers, exécute des commandes shell, récupère des pages web et peut ancrer ses réponses avec Google Search — planifiant et vérifiant le travail à partir de tâches en langage naturel plutôt que de simplement compléter des lignes. Le même moteur alimente aussi l’agent Gemini Code Assist au sein de VS Code."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés se distinguent. Ses modèles sont nativement multimodaux : vous pouvez donc lui transmettre une capture d’écran et il raisonne sur la mise en page réelle. Et sa fenêtre de contexte atteint jusqu’à 1 M de tokens, assez grande pour contenir tout votre design system, votre bibliothèque de composants et votre jeu de références à la fois, au lieu de les résumer et de les perdre."}, {"kind": "steps", "items": [{"label": "Fichiers de contexte", "body": "Gemini CLI lit un fichier GEMINI.md pour le contexte projet persistant — l’endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue. Les réglages personnels et d’équipe viennent s’y superposer."}, {"label": "Outils intégrés + MCP", "body": "Il fournit d’emblée des outils de fichiers, de shell, de récupération web et Google Search, et prend en charge les serveurs MCP (configurés dans ~/.gemini/settings.json) pour ajouter du contexte externe, comme un fichier Figma en direct."}, {"label": "Gratuit pour démarrer", "body": "Se connecter avec un compte Google personnel donne un généreux palier gratuit de requêtes Gemini ; vous pouvez aussi apporter une clé API Gemini ou utiliser Vertex AI."}]}, {"kind": "ul", "items": ["Éditeur : Google", "Identifiant : compte Google (palier gratuit) ou clé API Gemini depuis AI Studio (BYOK) ou Vertex AI", "Licence : Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Pourquoi les modèles multimodaux et un immense contexte conviennent au design", "blocks": [{"kind": "p", "text": "L’avantage de Gemini CLI pour le design vient de deux propriétés du modèle — mais, comme pour tout agent, le goût reste à fournir."}, {"kind": "steps", "items": [{"label": "Forte compréhension multimodale", "body": "Parce que les modèles Gemini sont nativement multimodaux, l’agent lit bien les captures d’écran de référence — comparant son rendu à une image plutôt que de deviner à partir d’une description en prose."}, {"label": "Une fenêtre de contexte de 1 M de tokens", "body": "Un grand contexte signifie que tout le design system, les tokens et de nombreux états de référence tiennent à la fois, si bien que l’agent réutilise vos primitives réelles au lieu d’inventer des styles ponctuels."}, {"label": "Des conventions dans GEMINI.md", "body": "Un GEMINI.md (plus le serveur MCP Figma) oriente l’agent vers vos tokens, vos composants et vos vraies specs, de sorte qu’il travaille pour une marque plutôt que sur un look par défaut."}]}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-taste-triangle.webp", "alt": "Schéma montrant un design system, un skill et une image de référence convergeant vers un bon rendu de design", "caption": "Le goût provient de trois entrées que vous fournissez : un design system, un skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle de tout agent : Gemini CLI n’a pas de goût par défaut. Il produit du bon design quand vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design empaquette précisément ces entrées, et c’est pourquoi les deux s’accordent (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Gemini CLI pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le parcours complet d’une machine vierge jusqu’à un Gemini CLI capable de construire et de vérifier des interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Gemini CLI (Node 20+)\nnpm install -g @google/gemini-cli\n# or run without installing: npx https://github.com/google-gemini/gemini-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngemini            # sign in with your Google account, or set GEMINI_API_KEY\n\n# 3. Generate project context\n/init             # scaffolds a GEMINI.md for this project\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it under \"mcpServers\" in ~/.gemini/settings.json"}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s’authentifier, configurer GEMINI.md, ajouter un skill, vérifier", "caption": "La séquence de configuration : installer → s’authentifier → configurer GEMINI.md → ajouter un skill → activer la vérification dans le navigateur."}, {"kind": "steps", "items": [{"label": "Encoder vos règles de design", "body": "Placez vos tokens, vos primitives et vos conventions dans GEMINI.md et orientez Gemini vers eux, pour que le rendu corresponde à une marque au lieu de retomber sur un look générique."}, {"label": "Ajouter la vérification dans le navigateur", "body": "Branchez un MCP Playwright ou navigateur pour que Gemini effectue son rendu dans un vrai navigateur et contrôle son résultat sur les différents points de rupture, au lieu de seulement confirmer que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d’écran vers interface", "blocks": [{"kind": "p", "text": "La boucle de design la plus rentable avec Gemini CLI consiste à transformer une image de référence en interface fonctionnelle et responsive, puis à itérer jusqu’à la correspondance — en s’appuyant sur le modèle multimodal pour comparer le rendu à la référence."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (ordinateur et mobile, survol, vide, chargement), pas seulement une image héro.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique, même avec un modèle puissant.", "Gardez votre design system et vos conventions dans GEMINI.md, et indiquez à Gemini où se trouvent les tokens et les primitives canoniques.", "Lancez un serveur de développement et faites effectuer le rendu à Gemini dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en demandant à Gemini de comparer son implémentation aux captures d’écran — pas seulement de confirmer qu’elle compile."]}, {"kind": "p", "text": "Référencez une image avec @ pour la joindre au prompt, puis donnez des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "gemini\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from GEMINI.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, validez les bonnes itérations et annulez les mauvaises (en prévenant Gemini quand vous annulez), pour que chaque passe s’appuie sur une base propre."}]}, {"id": "extend", "heading": "GEMINI.md, MCP et extensions", "blocks": [{"kind": "p", "text": "Trois points d’extension rendent Gemini CLI exploitable pour un travail de design durable, et tous trois s’appliquent proprement à un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Contexte GEMINI.md", "body": "Les règles du projet vivent dans un GEMINI.md à la racine du dépôt (avec des couches globale et d’équipe). C’est le foyer durable de vos conventions de design, lu à chaque exécution."}, {"label": "Serveurs MCP", "body": "Configurez les serveurs MCP dans ~/.gemini/settings.json — la manière portable d’apporter du contexte de design et des outils externes, et tout particulièrement le serveur MCP Figma, qui fonctionnent d’un agent à l’autre, pas seulement avec Gemini."}, {"label": "Extensions et outils intégrés", "body": "Les extensions de Gemini CLI et ses outils intégrés Google Search, fichiers, shell et récupération web lui permettent de rassembler des références et d’exécuter la boucle de vérification sans quitter le terminal."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agents — exactement le genre de chose qu’Open Design est conçu pour orchestrer, plutôt que de la recréer projet par projet."}]}, {"id": "vs", "heading": "Gemini CLI vs Codex vs Claude Code vs Cursor pour le design", "blocks": [{"kind": "p", "text": "Il n’y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé honnête :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Gemini CLI", "Forte compréhension multimodale des images et contexte de 1 M de tokens ; open source avec un palier gratuit", "Le travail à forte dose de captures d’écran et le maintien de tout un design system en contexte"], ["Codex", "Forte finition visuelle avec un skill frontend ; builds asynchrones en sandbox", "Les builds asynchrones délégués et les règles portables AGENTS.md"], ["Claude Code", "Décisions de design précises (hex, espacement, typographie) et UX consciente de la base de code", "Le raisonnement frontend et les refactorisations à grand contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et édits en ligne", "Le travail d’interface itérer-et-observer serré au sein d’un IDE"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C’est le vrai problème à résoudre — et il a la forme d’un outil de design, pas d’un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter le rendu « bouillie IA »", "blocks": [{"kind": "p", "text": "Le reproche le plus courant fait au design généré par IA, c’est qu’il a l’air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres spectaculaires, une ambiance Inter-et-violet qui « crie qu’une IA a fait ça ». Parmi les autres problèmes signalés : des mises en page mobiles cassées et des instructions qui s’infiltrent dans le texte de l’interface. Aucun de ces travers n’est propre à Gemini CLI ; c’est ce qui arrive quand un agent, quel qu’il soit, tourne sans contexte de design soigné."}, {"kind": "steps", "items": [{"label": "Ajouter un skill esthétique", "body": "Un skill de design soigné force l’agent à s’engager dans une vraie direction au lieu du look par défaut."}, {"label": "Vérifier dans un vrai navigateur", "body": "Servez-vous du modèle multimodal pour effectuer le rendu et l’auto-contrôle sur les différents points de rupture, afin que les mises en page ne cassent pas silencieusement sur mobile."}, {"label": "Fournir tokens et références", "body": "De vrais tokens de design et des captures d’écran de référence sont le plus grand levier sur la qualité du rendu."}, {"label": "Encoder les règles dans GEMINI.md", "body": "Placez des règles du style « pas de cartes héro, deux polices au maximum, hiérarchie centrée sur la marque » là où l’agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque parade revient à donner à l’agent un contexte de design soigné. Maintenir ce contexte à la main, projet par projet, c’est précisément la corvée qu’Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Gemini CLI dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Gemini CLI comme un adaptateur de première partie et l’enveloppe dans une bibliothèque sélectionnée de skills et de design systems, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de design qui rend Gemini bon soit présent dès la première exécution, sans être assemblé à la main à chaque fois. Les deux sont open source et locaux d’abord, ce qui rend l’association naturelle."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Gemini CLI comme agent.", "Authentifiez-vous avec votre compte Google ou votre clé API Gemini (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nos serveurs.", "Choisissez un design system et un skill, puis générez des présentations, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et chaque fichier DESIGN.md vit dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Le même agent Gemini CLI, la même clé — plus un véritable workflow de design portable et open source tout autour. C’est local d’abord et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Gemini CLI peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un design system et de vraies images de référence en contexte, Gemini CLI produit des interfaces responsives de qualité production, et ses puissants modèles multimodaux vérifient le rendu par rapport aux références. Sans ce contexte, il a tendance à retomber sur un look générique, et c’est l’écart que comble Open Design."}, {"name": "Dois-je payer pour faire du design avec Gemini CLI ?", "text": "Non — se connecter avec un compte Google donne un généreux palier gratuit, et vous pouvez aussi apporter une clé API Gemini (BYOK) ou utiliser Vertex AI. Open Design ne fait transiter vos identifiants dans aucun cas."}, {"name": "Qu’est-ce qui rend Gemini CLI bon pour le design en particulier ?", "text": "Deux choses : ses modèles sont fortement multimodaux, donc il lit bien les captures d’écran de référence, et son contexte de 1 M de tokens peut contenir tout un design system et un jeu de références à la fois. Les deux aident — mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Gemini CLI ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est réputé pour des décisions de design précises et conscientes de la base de code ; l’avantage de Gemini CLI, c’est la compréhension multimodale plus un immense contexte et un palier gratuit. De nombreuses équipes utilisent les deux — Open Design vous permet de changer d’agent sans changer votre workflow de design."}, {"name": "Comment connecter Gemini CLI à Figma ?", "text": "Ajoutez le serveur MCP Figma sous mcpServers dans ~/.gemini/settings.json. Gemini peut alors tirer un vrai contexte de design — composants, variables, données de mise en page — pour que le code généré corresponde à la source au lieu de l’approximer."}, {"name": "Open Design est-il affilié à Google ?", "text": "Non. Gemini CLI est un produit de Google ; Open Design est un projet open source indépendant qui le prend en charge en tant qu’adaptateur de première partie. Gemini est une marque déposée de Google."}, {"name": "Mes fichiers et mes identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local d’abord et Apache-2.0. Vos fichiers, vos artefacts et votre DESIGN.md restent dans votre propre dépôt, et vos identifiants Google sont utilisés directement par votre agent, jamais acheminés via les serveurs d’Open Design."}], "ctaTitle": "Concevez avec Gemini CLI, à la manière ouverte.", "ctaBody": "Apportez votre propre compte Google ou clé API Gemini, gardez chaque fichier en local et obtenez une bibliothèque de design soignée autour de l’agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Gemini CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l’application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'copilot': {
        ...en['copilot']!,
        title: "GitHub Copilot CLI pour le design — Open Design",
        description: "Comment on utilise GitHub Copilot CLI pour le design d'interfaces et de sites web — son agent de code natif du terminal, ses fichiers d'instructions personnalisés, sa prise en charge de MCP et son choix multi-modèle — et comment Open Design transforme Copilot CLI en un agent de design open source et local-first.",
        breadcrumb: "GitHub Copilot CLI",
        label: "Agent · GitHub Copilot CLI",
        heading: "GitHub Copilot CLI pour le design.",
        lead: "GitHub Copilot CLI est l'agent de code natif du terminal de GitHub. Il planifie et modifie l'ensemble de votre dépôt, choisit parmi des modèles de pointe comme Claude et GPT, et lit les instructions de votre dépôt — ce qui en fait un véritable outil de design dès lors que vous lui fournissez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open source : votre abonnement GitHub Copilot, vos fichiers, en local-first.",
        rich: {"heroCtaLead": "Open Design transforme GitHub Copilot CLI en un agent de design open source et local-first — votre abonnement GitHub Copilot, vos fichiers, une bibliothèque de skills et de design systems soigneusement sélectionnée tout autour.", "heroCtaActions": [{"label": "Utiliser Copilot CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["GitHub Copilot CLI est l'agent de code natif du terminal de GitHub — le même harnais agentique qui propulse l'agent de code Copilot, porté sur votre ligne de commande. Deux choses le rendent intéressant pour le design en particulier : il lit les instructions de votre dépôt et le fichier AGENTS.md, de sorte que vos conventions de design accompagnent l'agent à chaque exécution ; et il vous laisse choisir, tâche par tâche, parmi des modèles de pointe d'Anthropic, OpenAI et Google, ce qui vous permet de prendre celui qui raisonne le mieux sur une interface donnée. Associé aux bonnes références, conventions et à une boucle de vérification, il construit de véritables interfaces réactives — et il fonctionne avec l'abonnement Copilot que vous possédez peut-être déjà. Voici un guide pratique et de bout en bout pour utiliser Copilot CLI dans le travail d'UI, de frontend et de design system, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Copilot CLI, pourquoi les instructions de dépôt et le choix du modèle conviennent au design, comment l'installer de zéro, la boucle capture d'écran-vers-UI, comment les instructions personnalisées et MCP l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les pièges qui rendent les rendus de l'IA génériques, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — votre abonnement et vos identifiants restent sur votre machine, vos artefacts restent dans votre propre dépôt."], "heroImage": {"src": "/agents/copilot-design/copilot-design-hero.webp", "alt": "Boucle de feedback de design de GitHub Copilot CLI : un agent dans le terminal lisant une image de référence, un navigateur affichant l'UI et un espace de travail, avec une flèche de feedback qui boucle en retour", "caption": "La boucle centrale : Copilot CLI lit vos références dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère par rapport à elles — avec vos conventions de design dans les instructions du dépôt."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-copilot", "label": "Ce qu'est réellement GitHub Copilot CLI"}, {"id": "why-design", "label": "Pourquoi instructions + choix du modèle conviennent au design"}, {"id": "setup", "label": "Configurer Copilot CLI pour le design (de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "Instructions personnalisées, MCP et extensions"}, {"id": "vs", "label": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Les pièges et le rendu « bouillie d'IA »"}, {"id": "open-design", "label": "Concevoir avec Copilot CLI dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-copilot", "heading": "Ce qu'est réellement GitHub Copilot CLI", "blocks": [{"kind": "p", "text": "GitHub Copilot CLI est l'agent de code natif du terminal de GitHub. Il lit votre dépôt, modifie des fichiers, exécute des commandes shell et travaille directement avec votre contexte GitHub — issues, pull requests et dépôts — en s'authentifiant avec votre compte GitHub existant. Il est propulsé par le même harnais agentique que l'agent de code Copilot de GitHub, il planifie donc des tâches complexes et itère au lieu de se contenter de compléter des lignes. Il a atteint la disponibilité générale en février 2026, après une préversion publique ouverte en septembre 2025."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés ressortent. Il lit les fichiers d'instructions personnalisés — règles à l'échelle du dépôt dans .github/copilot-instructions.md ainsi que AGENTS.md — de sorte que vos conventions de design sont incluses automatiquement à chaque exécution. Et il prend en charge plusieurs fournisseurs de modèles de fondation, ce qui vous permet de changer de modèle tâche par tâche avec la commande /model, en fonction de celui qui raisonne le mieux sur une interface donnée."}, {"kind": "steps", "items": [{"label": "Fichiers d'instructions", "body": "Copilot CLI lit les instructions du dépôt dans .github/copilot-instructions.md, les fichiers spécifiques à un chemin sous .github/instructions, et AGENTS.md — l'endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue."}, {"label": "Outils intégrés + MCP", "body": "Il intègre le serveur MCP de GitHub et exécute des outils de fichiers et de shell, et vous pouvez ajouter des serveurs MCP personnalisés avec /mcp add (stockés dans mcp-config.json sous ~/.copilot) pour du contexte externe comme un fichier Figma en direct."}, {"label": "Choix du modèle", "body": "Utilisez la commande /model pour choisir parmi des modèles de pointe d'Anthropic, OpenAI et Google — en changeant tâche par tâche, le tout sur votre abonnement Copilot existant."}]}, {"kind": "ul", "items": ["Éditeur : GitHub", "Identifiant : un abonnement GitHub Copilot actif (Pro, Pro+, Business ou Enterprise)", "Installation : npm install -g @github/copilot, puis exécutez copilot"]}]}, {"id": "why-design", "heading": "Pourquoi les instructions de dépôt et le choix du modèle conviennent au design", "blocks": [{"kind": "p", "text": "L'avantage de Copilot CLI pour le design vient de deux propriétés — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Des conventions qui voyagent avec le dépôt", "body": "Parce que Copilot CLI lit automatiquement .github/copilot-instructions.md et AGENTS.md, vos tokens, vos primitives et vos règles de revue sont dans le contexte à chaque exécution — l'agent travaille sur une marque plutôt que sur un look par défaut."}, {"label": "Choisir le bon modèle par tâche", "body": "Le choix de modèles d'Anthropic, OpenAI et Google signifie que vous pouvez vous tourner vers celui qui raisonne le mieux sur une mise en page donnée, puis en changer pour la tâche suivante — sans modifier votre workflow."}, {"label": "De vraies specs via MCP", "body": "Le serveur MCP GitHub intégré, plus un serveur MCP Figma, dirigent l'agent vers vos tokens, vos composants et vos vraies specs, afin qu'il construise à partir de la source au lieu d'approximer."}]}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-taste-triangle.webp", "alt": "Diagramme montrant un design system, un skill et une image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois entrées que vous fournissez : un design system, un skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle que tout agent enseigne : Copilot CLI n'a pas de goût par défaut. Il produit du bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design empaquette exactement ces entrées, ce qui explique pourquoi les deux s'accordent (voir plus bas)."}]}, {"id": "setup", "heading": "Configurer Copilot CLI pour le travail de design, de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet d'une machine vierge à un Copilot CLI capable de construire et de vérifier des interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Copilot CLI (Node.js required)\nnpm install -g @github/copilot\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ncopilot           # run /login and follow the prompts to sign in\n\n# 3. Choose a model for the task\n#    inside the session:\n/model            # pick a frontier model from Anthropic, OpenAI, or Google\n\n# 4. Add custom instructions and the Figma MCP server (optional)\n#    write .github/copilot-instructions.md or AGENTS.md\n/mcp add          # add the Figma MCP server for design handoff"}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, choisir un modèle, configurer les instructions, vérifier", "caption": "La séquence de configuration : installer → s'authentifier → choisir un modèle → écrire les instructions → activer la vérification dans le navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Placez vos tokens, vos primitives et vos conventions dans .github/copilot-instructions.md ou AGENTS.md, afin que le rendu corresponde à une marque au lieu de retomber sur un look générique."}, {"label": "Ajoutez la vérification dans le navigateur", "body": "Branchez un MCP Playwright ou navigateur pour que Copilot effectue le rendu dans un vrai navigateur et vérifie son résultat sur les différents points de rupture, au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus rentable avec Copilot CLI consiste à transformer une image de référence en une interface réactive fonctionnelle et à itérer jusqu'à ce qu'elle corresponde — en s'appuyant sur un modèle multimodal solide pour comparer le rendu à la référence."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (bureau et mobile, survol, vide, chargement), pas seulement une image héro.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique même avec un modèle solide.", "Conservez votre design system et vos conventions dans .github/copilot-instructions.md ou AGENTS.md, et indiquez à Copilot où vivent les tokens et les primitives canoniques.", "Lancez un serveur de développement et faites en sorte que Copilot effectue le rendu dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en faisant comparer par Copilot son implémentation aux captures d'écran — pas simplement confirmer que ça se compile."]}, {"kind": "p", "text": "Dirigez Copilot vers vos images de référence et donnez des contraintes concrètes ; il prévisualise chaque modification de fichier ou commande pour votre approbation avant de l'exécuter :"}, {"kind": "code", "lang": "bash", "code": "copilot\n# in the prompt:\n> Implement the design in reference-desktop.png and reference-mobile.png\n  in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens described in\n  .github/copilot-instructions.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, validez les bonnes itérations et annulez les mauvaises (en indiquant à Copilot quand vous annulez), afin que chaque passe s'appuie sur une base propre."}]}, {"id": "extend", "heading": "Instructions personnalisées, MCP et extensions", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Copilot CLI pratique pour un travail de design durable, et tous trois s'inscrivent proprement dans un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Instructions personnalisées", "body": "Les règles du dépôt vivent dans .github/copilot-instructions.md (avec des fichiers spécifiques à un chemin sous .github/instructions et AGENTS.md). Ce sont le foyer durable de vos conventions de design, incluses automatiquement à chaque exécution."}, {"label": "Serveurs MCP", "body": "Copilot CLI intègre le serveur MCP de GitHub et vous laisse ajouter des serveurs personnalisés via /mcp add (stockés dans mcp-config.json sous ~/.copilot) — la façon portable d'apporter du contexte de design, le plus pertinent étant le serveur MCP Figma, qui fonctionne avec tous les agents, pas seulement Copilot."}, {"label": "Agents spécialisés et outils intégrés", "body": "Les modes spécialisés de Copilot CLI — pour l'exploration de la base de code, l'exécution des builds et des tests, la revue des changements et la planification — plus ses outils de fichiers et de shell lui permettent de rassembler des références et d'exécuter la boucle de vérification sans quitter le terminal."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de les recréer projet par projet."}]}, {"id": "vs", "heading": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Copilot CLI", "Choix multi-modèle (Anthropic, OpenAI, Google) et intégration GitHub profonde sur votre abonnement Copilot", "Choisir le meilleur modèle par tâche et un travail piloté par les instructions, lié à votre dépôt GitHub"], ["Codex", "Forte finition visuelle avec un skill frontend ; builds asynchrones en bac à sable", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX consciente de la base de code", "Raisonnement frontend et refactorisations à grand contexte"], ["Cursor", "Boucle construire-et-voir visuelle avec aperçu en direct et éditions inline", "Travail d'UI serré, itérer-et-observer, au sein d'un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; open source avec une offre gratuite", "Travail riche en captures d'écran et maintien d'un design system entier dans le contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « bouillie d'IA »", "blocks": [{"kind": "p", "text": "La plainte la plus courante au sujet du design généré par IA est qu'il a l'air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres dramatiques, une ambiance Inter-et-violet qui « hurle qu'une IA a fait ça ». Parmi les autres problèmes rapportés figurent des mises en page mobiles cassées et des instructions qui fuient dans le texte de l'interface. Aucun de ceux-ci n'est propre à Copilot CLI ; ce sont ce qui arrive lorsqu'un agent, quel qu'il soit, fonctionne sans contexte de design soigneusement sélectionné."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill de design soigneusement sélectionné force l'agent à s'engager dans une direction réelle au lieu du look par défaut."}, {"label": "Vérifiez dans un vrai navigateur", "body": "Effectuez le rendu et l'auto-contrôle sur les différents points de rupture avec un MCP navigateur, afin que les mises en page ne se cassent pas silencieusement sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures d'écran de référence sont le plus grand levier sur la qualité du rendu."}, {"label": "Encodez les règles dans les instructions personnalisées", "body": "Placez des règles de style telles que « pas de cartes héro, deux polices au maximum, hiérarchie centrée sur la marque » dans .github/copilot-instructions.md ou AGENTS.md, là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque mesure d'atténuation consiste à donner à l'agent un contexte de design soigneusement sélectionné. Maintenir ce contexte à la main, projet par projet, c'est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Copilot CLI dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite GitHub Copilot CLI comme un adaptateur de première partie et l'enveloppe dans une bibliothèque de skills et de design systems soigneusement sélectionnée, un pipeline de rendu structuré et une UI de bureau locale — de sorte que le contexte de design qui rend Copilot bon est là dès la première exécution, et non assemblé à la main à chaque fois. Open Design est indépendant, open source (Apache-2.0) et local-first, ce qui explique pourquoi l'association fonctionne : l'agent fait le travail, vos fichiers et vos identifiants restent les vôtres."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez GitHub Copilot CLI comme agent.", "Authentifiez-vous avec votre abonnement GitHub Copilot — les identifiants restent sur votre machine et ne transitent jamais par nous.", "Choisissez un design system et un skill, puis générez des présentations, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, et non dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Copilot CLI, même abonnement — plus un véritable workflow de design portable et open source tout autour. Open Design est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "GitHub Copilot CLI peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un design system et de vraies images de référence dans le contexte, Copilot CLI produit une UI réactive de qualité production, et vous pouvez choisir le modèle qui vérifie le mieux le rendu par rapport aux références. Sans ce contexte, il a tendance à retomber sur un look générique, ce qui est l'écart que comble Open Design."}, {"name": "Ai-je besoin d'un abonnement pour concevoir avec Copilot CLI ?", "text": "Oui — Copilot CLI fonctionne avec un abonnement GitHub Copilot actif (Pro, Pro+, Business ou Enterprise) ; il n'est pas en bring-your-own-key. Vous vous authentifiez avec votre compte GitHub. Open Design ne fait jamais transiter vos identifiants — votre abonnement est utilisé directement par votre agent."}, {"name": "Qu'est-ce qui rend Copilot CLI bon pour le design en particulier ?", "text": "Deux choses : il lit automatiquement les instructions du dépôt et AGENTS.md, de sorte que vos conventions de design voyagent avec le dépôt ; et il vous laisse basculer, tâche par tâche, parmi des modèles de pointe d'Anthropic, OpenAI et Google. Les deux aident — mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Copilot CLI ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est connu pour ses décisions de design précises et conscientes de la base de code ; l'avantage de Copilot CLI est le choix de modèles entre fournisseurs et l'intégration GitHub profonde sur un abonnement que vous possédez peut-être déjà. Beaucoup d'équipes utilisent les deux — Open Design vous laisse changer d'agent sans changer votre workflow de design."}, {"name": "Comment connecter Copilot CLI à Figma ?", "text": "Ajoutez le serveur MCP Figma avec la commande /mcp add ; les paramètres sont stockés dans mcp-config.json sous ~/.copilot. Copilot peut alors récupérer un vrai contexte de design — composants, variables, données de mise en page — afin que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à GitHub ou Microsoft ?", "text": "Non. GitHub Copilot CLI est un produit de GitHub ; Open Design est un projet open source indépendant qui le prend en charge en tant qu'adaptateur de première partie. GitHub Copilot est une marque de GitHub, Inc. et Microsoft."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants GitHub Copilot sont utilisés directement par votre agent, jamais acheminés via les serveurs d'Open Design."}], "ctaTitle": "Concevez avec GitHub Copilot CLI, de façon ouverte.", "ctaBody": "Apportez votre abonnement GitHub Copilot, gardez chaque fichier en local et obtenez une bibliothèque de design soigneusement sélectionnée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Copilot CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'qwen': {
        ...en['qwen']!,
        title: "Qwen Code pour le design — Open Design",
        description: "Comment on utilise le CLI open source Qwen Code d'Alibaba pour le design d'interfaces et de sites web — ses modèles Qwen3-Coder, sa grande fenêtre de contexte, QWEN.md et MCP — et comment Open Design transforme Qwen Code en un agent de design open source et local-first.",
        breadcrumb: "Qwen Code",
        label: "Agent · Qwen Code",
        heading: "Qwen Code pour le design.",
        lead: "Qwen Code est l'agent de terminal open source d'Alibaba, adapté de Gemini CLI et optimisé pour les modèles Qwen3-Coder. Sa grande fenêtre de contexte peut contenir un design system entier d'un coup, ce qui en fait un véritable outil de design — dès lors que vous lui fournissez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open source : votre clé API DashScope ou Qwen, vos fichiers, en local-first.",
        rich: {"heroCtaLead": "Open Design transforme Qwen Code en un agent de design open source et local-first — votre clé API DashScope ou Qwen, vos fichiers, une bibliothèque de skills et de design systems soigneusement sélectionnée tout autour.", "heroCtaActions": [{"label": "Utiliser Qwen Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qwen Code est l'agent d'IA open source d'Alibaba pour le terminal. Il est adapté de Gemini CLI de Google, avec des adaptations au niveau du parser et des prompts qui lui permettent de tirer le meilleur des modèles Qwen3-Coder. Deux choses le rendent intéressant pour le design en particulier : c'est un solide modèle de code agentique, il planifie donc, modifie des fichiers et exécute la boucle de build et de vérification à partir d'une tâche en langage naturel ; et sa grande fenêtre de contexte peut contenir un design system et une base de code entiers d'un coup. Associé aux bonnes références, conventions et à une boucle de vérification, il construit de véritables interfaces réactives — et il est open source et BYOK, vous apportez donc votre propre clé. Voici un guide pratique et de bout en bout pour utiliser Qwen Code dans le travail d'UI, de frontend et de design system, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Qwen Code, pourquoi un solide modèle de code plus un grand contexte conviennent au design, comment l'installer de zéro, la boucle référence-vers-UI, comment QWEN.md et MCP l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les pièges qui rendent les rendus de l'IA génériques, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — une association naturelle, puisque les deux sont open source et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/qwen-design/qwen-design-hero.webp", "alt": "Boucle de feedback de design de Qwen Code : un agent dans le terminal lisant une image de référence, un navigateur affichant l'UI et un espace de travail, avec une flèche de feedback qui boucle en retour", "caption": "La boucle centrale : Qwen Code lit vos références dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère par rapport à elles — avec un design system entier dans le contexte."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-qwen", "label": "Ce qu'est réellement Qwen Code"}, {"id": "why-design", "label": "Pourquoi un solide modèle de code + grand contexte conviennent au design"}, {"id": "setup", "label": "Configurer Qwen Code pour le design (de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow référence-vers-UI"}, {"id": "extend", "label": "QWEN.md, MCP et extensions"}, {"id": "vs", "label": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Les pièges et le rendu « bouillie d'IA »"}, {"id": "open-design", "label": "Concevoir avec Qwen Code dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qwen", "heading": "Ce qu'est réellement Qwen Code", "blocks": [{"kind": "p", "text": "Qwen Code est un agent d'IA open source (Apache-2.0) qu'Alibaba propose pour le terminal. Il lit votre dépôt, modifie des fichiers, exécute des commandes shell et exploite le web — planifiant et vérifiant le travail à partir de tâches en langage naturel plutôt que de simplement compléter des lignes. Il est adapté de Gemini CLI de Google, avec des adaptations au niveau du parser et des prompts conçues pour libérer le potentiel des modèles Qwen3-Coder sur les tâches de code agentique."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés ressortent. C'est un codeur agentique compétent, il peut donc prendre une référence et un brief clair et construire, exécuter et auto-corriger une UI réactive. Et les modèles Qwen3-Coder embarquent une grande fenêtre de contexte, suffisamment large pour contenir votre design system, votre bibliothèque de composants et votre ensemble de références d'un coup, au lieu de les résumer."}, {"kind": "steps", "items": [{"label": "Fichiers de contexte", "body": "Qwen Code lit un fichier QWEN.md pour un contexte de projet persistant — l'endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue. Les paramètres personnels et de projet se superposent par-dessus."}, {"label": "Outils intégrés + MCP", "body": "Il intègre d'emblée des outils de fichiers, de shell et web, et prend en charge les serveurs MCP (configurés sous mcpServers dans ~/.qwen/settings.json) pour ajouter du contexte externe comme un fichier Figma en direct."}, {"label": "BYOK pour commencer", "body": "Vous apportez votre propre clé — une clé API DashScope (Alibaba Cloud Model Studio), ou tout endpoint compatible OpenAI ou ModelScope — et la configurez dans settings.json."}]}, {"kind": "ul", "items": ["Éditeur : Alibaba", "Identifiant : clé API DashScope / Qwen (BYOK), ou endpoint compatible OpenAI / ModelScope", "Licence : Apache-2.0, open source (adapté de Gemini CLI)"]}]}, {"id": "why-design", "heading": "Pourquoi un solide modèle de code et un grand contexte conviennent au design", "blocks": [{"kind": "p", "text": "L'avantage de Qwen Code pour le design vient de deux propriétés — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Code agentique solide", "body": "Les modèles Qwen3-Coder sont optimisés pour les tâches agentiques, l'agent planifie donc, modifie, exécute le build et s'auto-corrige — transformant une référence et un brief clairs en balisage réactif plutôt qu'une supposition en une passe."}, {"label": "Une grande fenêtre de contexte", "body": "Le grand contexte de Qwen3-Coder signifie que tout le design system, les tokens et de nombreux états de référence tiennent d'un coup, de sorte que l'agent réutilise vos vraies primitives au lieu d'inventer des styles ponctuels."}, {"label": "Conventions dans QWEN.md", "body": "Un QWEN.md (plus le serveur MCP Figma) dirige l'agent vers vos tokens, vos composants et vos vraies specs, afin qu'il travaille sur une marque plutôt que sur un look par défaut."}]}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-taste-triangle.webp", "alt": "Diagramme montrant un design system, un skill et une image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois entrées que vous fournissez : un design system, un skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle que tout agent enseigne : Qwen Code n'a pas de goût par défaut. Il produit du bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design empaquette exactement ces entrées, ce qui explique pourquoi les deux s'accordent (voir plus bas)."}]}, {"id": "setup", "heading": "Configurer Qwen Code pour le travail de design, de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet d'une machine vierge à un Qwen Code capable de construire et de vérifier des interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qwen Code (Node 22+)\nnpm install -g @qwen-code/qwen-code@latest\n# or: brew install qwen-code\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nqwen              # run /auth, or set a key in ~/.qwen/settings.json\n\n# 3. Configure a DashScope (OpenAI-compatible) key in settings.json\n#    baseUrl: https://dashscope.aliyuncs.com/compatible-mode/v1\n#    model:   qwen3-coder-plus   (set DASHSCOPE_API_KEY)\n\n# 4. Add a QWEN.md and wire the Figma MCP server (optional)\n#    add MCP under \"mcpServers\" in ~/.qwen/settings.json"}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, configurer QWEN.md, ajouter un skill, vérifier", "caption": "La séquence de configuration : installer → s'authentifier → configurer QWEN.md → ajouter un skill → activer la vérification dans le navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Placez vos tokens, vos primitives et vos conventions dans QWEN.md et dirigez-y Qwen Code, afin que le rendu corresponde à une marque au lieu de retomber sur un look générique."}, {"label": "Ajoutez la vérification dans le navigateur", "body": "Branchez un MCP Playwright ou navigateur pour que Qwen Code effectue le rendu dans un vrai navigateur et vérifie son résultat sur les différents points de rupture, au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow référence-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus rentable avec Qwen Code consiste à transformer une référence en une interface réactive fonctionnelle et à itérer jusqu'à ce qu'elle corresponde — en s'appuyant sur l'agent pour construire, effectuer le rendu et comparer son résultat à la référence."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et décrivez plusieurs états (bureau et mobile, survol, vide, chargement), pas seulement une image héro.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique même avec un modèle solide.", "Conservez votre design system et vos conventions dans QWEN.md, et indiquez à Qwen Code où vivent les tokens et les primitives canoniques.", "Lancez un serveur de développement et faites en sorte que Qwen Code effectue le rendu dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en faisant comparer par Qwen Code son implémentation aux références — pas simplement confirmer que ça se compile."]}, {"kind": "p", "text": "Référencez un fichier avec @ pour le joindre au prompt, puis donnez des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "qwen\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from QWEN.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, validez les bonnes itérations et annulez les mauvaises (en indiquant à Qwen Code quand vous annulez), afin que chaque passe s'appuie sur une base propre."}]}, {"id": "extend", "heading": "QWEN.md, MCP et extensions", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Qwen Code pratique pour un travail de design durable, et tous trois s'inscrivent proprement dans un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Contexte QWEN.md", "body": "Les règles du projet vivent dans un QWEN.md à la racine du dépôt (avec des couches globale et projet). C'est le foyer durable de vos conventions de design, lu à chaque exécution."}, {"label": "Serveurs MCP", "body": "Configurez les serveurs MCP sous mcpServers dans ~/.qwen/settings.json — la façon portable d'apporter du contexte de design et des outils externes, le plus pertinent étant le serveur MCP Figma, qui fonctionnent avec tous les agents, pas seulement Qwen Code."}, {"label": "Skills et outils intégrés", "body": "Les skills de Qwen Code et ses outils intégrés de fichiers, de shell et web lui permettent de rassembler des références et d'exécuter la boucle de vérification sans quitter le terminal."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de les recréer projet par projet."}]}, {"id": "vs", "heading": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Qwen Code", "Code agentique solide sur les modèles ouverts Qwen3-Coder avec un grand contexte ; open source et BYOK", "Des builds open source, flexibles côté clé, qui maintiennent un design system entier dans le contexte"], ["Codex", "Forte finition visuelle avec un skill frontend ; builds asynchrones en bac à sable", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX consciente de la base de code", "Raisonnement frontend et refactorisations à grand contexte"], ["Cursor", "Boucle construire-et-voir visuelle avec aperçu en direct et éditions inline", "Travail d'UI serré, itérer-et-observer, au sein d'un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; l'agent dont Qwen Code est adapté", "Travail riche en captures d'écran et très grand contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « bouillie d'IA »", "blocks": [{"kind": "p", "text": "La plainte la plus courante au sujet du design généré par IA est qu'il a l'air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres dramatiques, une ambiance Inter-et-violet qui « hurle qu'une IA a fait ça ». Parmi les autres problèmes rapportés figurent des mises en page mobiles cassées et des instructions qui fuient dans le texte de l'interface. Aucun de ceux-ci n'est propre à Qwen Code ; ce sont ce qui arrive lorsqu'un agent, quel qu'il soit, fonctionne sans contexte de design soigneusement sélectionné."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill de design soigneusement sélectionné force l'agent à s'engager dans une direction réelle au lieu du look par défaut."}, {"label": "Vérifiez dans un vrai navigateur", "body": "Faites en sorte que l'agent effectue le rendu et l'auto-contrôle sur les différents points de rupture, afin que les mises en page ne se cassent pas silencieusement sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures d'écran de référence sont le plus grand levier sur la qualité du rendu."}, {"label": "Encodez les règles dans QWEN.md", "body": "Placez des règles de style telles que « pas de cartes héro, deux polices au maximum, hiérarchie centrée sur la marque » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque mesure d'atténuation consiste à donner à l'agent un contexte de design soigneusement sélectionné. Maintenir ce contexte à la main, projet par projet, c'est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Qwen Code dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Qwen Code comme un adaptateur de première partie et l'enveloppe dans une bibliothèque de skills et de design systems soigneusement sélectionnée, un pipeline de rendu structuré et une UI de bureau locale — de sorte que le contexte de design qui rend Qwen Code bon est là dès la première exécution, et non assemblé à la main à chaque fois. Les deux sont open source et local-first, ce qui fait de l'association une combinaison naturelle."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Qwen Code comme agent.", "Authentifiez-vous avec votre clé API DashScope ou Qwen (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nous.", "Choisissez un design system et un skill, puis générez des présentations, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, et non dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Qwen Code, même clé — plus un véritable workflow de design portable et open source tout autour. Il est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Qwen Code peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un design system et de vraies images de référence dans le contexte, Qwen Code produit une UI réactive de qualité production, et sa boucle agentique construit, effectue le rendu et vérifie le résultat par rapport aux références. Sans ce contexte, il a tendance à retomber sur un look générique, ce qui est l'écart que comble Open Design."}, {"name": "Dois-je payer pour concevoir avec Qwen Code ?", "text": "Qwen Code est gratuit et open source, mais il est en BYOK — vous apportez une clé API DashScope (Alibaba Cloud Model Studio), un endpoint compatible OpenAI ou ModelScope. Alibaba propose aussi un forfait de code à prix fixe. Open Design ne fait jamais transiter vos identifiants, dans un cas comme dans l'autre."}, {"name": "Qu'est-ce qui rend Qwen Code bon pour le design en particulier ?", "text": "Deux choses : les modèles Qwen3-Coder sont optimisés pour le code agentique, l'agent construit donc et auto-corrige une UI réactive, et leur grand contexte peut contenir un design system et un ensemble de références entiers d'un coup. Les deux aident — mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Qwen Code est-il identique à Gemini CLI ?", "text": "Non. Qwen Code est adapté de Gemini CLI de Google — même lignée open source — avec des adaptations au niveau du parser et des prompts qui l'optimisent pour les modèles Qwen3-Coder. Open Design prend en charge les deux, vous pouvez donc changer d'agent sans changer votre workflow de design."}, {"name": "Comment connecter Qwen Code à Figma ?", "text": "Ajoutez le serveur MCP Figma sous mcpServers dans ~/.qwen/settings.json. Qwen Code peut alors récupérer un vrai contexte de design — composants, variables, données de mise en page — afin que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à Alibaba ou Qwen ?", "text": "Non. Qwen Code est un produit d'Alibaba ; Open Design est un projet open source indépendant qui le prend en charge en tant qu'adaptateur de première partie. Qwen est une marque d'Alibaba."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants DashScope ou Qwen sont utilisés directement par votre agent, jamais acheminés via les serveurs d'Open Design."}], "ctaTitle": "Concevez avec Qwen Code, de façon ouverte.", "ctaBody": "Apportez votre propre clé API DashScope ou Qwen, gardez chaque fichier en local et obtenez une bibliothèque de design soigneusement sélectionnée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Qwen Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'grok': {
        ...en['grok']!,
        title: "Grok Build pour le design — Open Design",
        description: "Comment on utilise Grok Build de xAI (Grok Build) pour le design d'interfaces et de sites web — son mode planification, AGENTS.md et MCP, ses modèles Grok capables de lire les images et son grand contexte — et comment Open Design transforme Grok Build en un agent de design open source et local-first.",
        breadcrumb: "Grok Build",
        label: "Agent · Grok Build",
        heading: "Grok Build pour le design.",
        lead: "Grok Build est l'agent de code de terminal de xAI. Il planifie un travail en plusieurs étapes avant de toucher à vos fichiers, lit les images aux côtés du code et exécute la boucle de build et de vérification dans votre dépôt — ce qui en fait un véritable outil de design dès lors que vous lui fournissez des références, des conventions et une étape de vérification. Open Design l'intègre dans un workflow de design open source : votre connexion SuperGrok ou clé API xAI, vos fichiers, en local-first.",
        rich: {"heroCtaLead": "Open Design transforme Grok Build en un agent de design open source et local-first — votre connexion SuperGrok ou clé API xAI, vos fichiers, une bibliothèque de skills et de design systems soigneusement sélectionnée tout autour.", "heroCtaActions": [{"label": "Utiliser Grok Build dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Grok Build — l'agent de code de terminal de xAI, livré sous le nom de Grok Build — est un outil agentique qui vit dans votre terminal. Deux choses le rendent intéressant pour le design en particulier : il planifie le travail à risque avant d'agir, de sorte que vous pouvez examiner une approche proposée avant que le moindre fichier ne change ; et ses modèles Grok acceptent l'entrée d'images, il peut donc raisonner sur une capture d'écran de référence aux côtés du code qu'il écrit. Associé aux bonnes références, conventions et à une boucle de vérification, il construit de véritables interfaces réactives — authentifié directement via votre compte SuperGrok ou X Premium+, sans avoir à jongler avec des clés API. Voici un guide pratique et de bout en bout pour utiliser Grok Build dans le travail d'UI, de frontend et de design system, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Grok Build, pourquoi le mode planification et les modèles capables de lire les images conviennent au design, comment l'installer de zéro, la boucle capture d'écran-vers-UI, comment AGENTS.md et MCP l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les pièges qui rendent les rendus de l'IA génériques, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — vos identifiants et vos artefacts ne quittant jamais votre machine."], "heroImage": {"src": "/agents/grok-design/grok-design-hero.webp", "alt": "Boucle de feedback de design de Grok Build : un agent dans le terminal planifiant à partir d'une image de référence, un navigateur affichant l'UI et un espace de travail, avec une flèche de feedback qui boucle en retour", "caption": "La boucle centrale : Grok Build planifie à partir de vos références dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère par rapport à elles — avec vos conventions dans AGENTS.md."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-grok", "label": "Ce qu'est réellement Grok Build"}, {"id": "why-design", "label": "Pourquoi mode planification + entrée d'images conviennent au design"}, {"id": "setup", "label": "Configurer Grok Build pour le design (de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "AGENTS.md, MCP et sous-agents"}, {"id": "vs", "label": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Les pièges et le rendu « bouillie d'IA »"}, {"id": "open-design", "label": "Concevoir avec Grok Build dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-grok", "heading": "Ce qu'est réellement Grok Build", "blocks": [{"kind": "p", "text": "Grok Build est l'agent de code de terminal de xAI, livré sous le nom de Grok Build. Il lit votre dépôt, modifie des fichiers, exécute des commandes shell et planifie un travail d'ingénierie en plusieurs étapes à partir de tâches en langage naturel plutôt que de simplement compléter des lignes. Il est bâti autour des modèles Grok de xAI — exposés sur l'API xAI sous la famille de modèles grok-build — et s'authentifie via votre compte xAI, de sorte que l'agent et les modèles proviennent du même éditeur."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés ressortent. Il dispose d'un mode planification qui ébauche une approche structurée que vous pouvez approuver, commenter ou réécrire avant que le moindre changement ne soit appliqué — une porte utile lorsque vous itérez sur une UI. Et ses modèles Grok acceptent l'entrée d'images, vous pouvez donc lui remettre une capture d'écran de référence et il raisonne sur la mise en page réelle au lieu de deviner à partir d'une description en prose."}, {"kind": "steps", "items": [{"label": "Fichiers de contexte", "body": "Grok Build lit un fichier AGENTS.md pour un contexte de projet persistant — l'endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue. Il suit la même convention ouverte AGENTS.md que Codex et d'autres agents utilisent."}, {"label": "Outils, MCP + sous-agents", "body": "Il modifie des fichiers, exécute des commandes shell et prend en charge les serveurs MCP pour ajouter du contexte externe comme un fichier Figma en direct ; pour les tâches plus importantes, il peut déléguer à des sous-agents parallèles qui recherchent, construisent et examinent en même temps."}, {"label": "Connectez-vous avec votre compte", "body": "Vous vous authentifiez en vous connectant via votre navigateur avec un abonnement SuperGrok ou X Premium+ ; vous pouvez aussi apporter une clé API xAI pour un usage headless et en CI."}]}, {"kind": "ul", "items": ["Éditeur : xAI", "Identifiant : OAuth xAI SuperGrok (`grok login`), ou une clé API xAI (BYOK) pour un usage headless", "Modèles : modèles Grok de xAI (la famille grok-build sur l'API xAI), avec entrée d'images"]}]}, {"id": "why-design", "heading": "Pourquoi le mode planification et les modèles capables de lire les images conviennent au design", "blocks": [{"kind": "p", "text": "L'avantage de Grok Build pour le design vient de deux propriétés — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Raisonnement capable de lire les images", "body": "Parce que les modèles Grok acceptent l'entrée d'images, l'agent lit les captures d'écran de référence — comparant son rendu à une image au lieu de deviner à partir d'une description en prose."}, {"label": "Mode planification avant l'application des changements", "body": "Le mode planification ébauche une approche structurée que vous approuvez avant que les fichiers ne changent, de sorte que l'intention de design est examinée en amont au lieu d'être découverte après le diff."}, {"label": "Conventions dans AGENTS.md", "body": "Un AGENTS.md (plus le serveur MCP Figma) dirige l'agent vers vos tokens, vos composants et vos vraies specs, afin qu'il travaille sur une marque plutôt que sur un look par défaut."}]}, {"kind": "image", "src": "/agents/grok-design/grok-design-taste-triangle.webp", "alt": "Diagramme montrant un design system, un skill et une image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois entrées que vous fournissez : un design system, un skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle que tout agent enseigne : Grok Build n'a pas de goût par défaut. Il produit du bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design empaquette exactement ces entrées, ce qui explique pourquoi les deux s'accordent (voir plus bas)."}]}, {"id": "setup", "heading": "Configurer Grok Build pour le travail de design, de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet d'une machine vierge à un Grok Build capable de construire et de vérifier des interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Grok Build (Grok Build) on macOS/Linux\ncurl -fsSL https://x.ai/cli/install.sh | bash\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngrok login   # opens your browser; sign in with SuperGrok / X Premium+\n#   or, for headless / CI use, set an xAI API key:\n#   export XAI_API_KEY=xai-...\n\n# 3. Add project context\n#    create an AGENTS.md at the repo root with your design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to your MCP server configuration"}, {"kind": "image", "src": "/agents/grok-design/grok-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, configurer AGENTS.md, ajouter un skill, vérifier", "caption": "La séquence de configuration : installer → s'authentifier → configurer AGENTS.md → ajouter un skill → activer la vérification dans le navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Placez vos tokens, vos primitives et vos conventions dans AGENTS.md et dirigez-y Grok, afin que le rendu corresponde à une marque au lieu de retomber sur un look générique."}, {"label": "Ajoutez la vérification dans le navigateur", "body": "Branchez un MCP Playwright ou navigateur pour que Grok effectue le rendu dans un vrai navigateur et vérifie son résultat sur les différents points de rupture, au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus rentable avec Grok Build consiste à transformer une image de référence en une interface réactive fonctionnelle et à itérer jusqu'à ce qu'elle corresponde — en s'appuyant sur le mode planification pour convenir de l'approche et sur le modèle capable de lire les images pour comparer le rendu à la référence."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires dont vous disposez — et incluez plusieurs états (bureau et mobile, survol, vide, chargement), pas seulement une image héro.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique même avec un modèle solide.", "Conservez votre design system et vos conventions dans AGENTS.md, et indiquez à Grok où vivent les tokens et les primitives canoniques.", "Utilisez le mode planification pour examiner l'approche, puis lancez un serveur de développement et faites en sorte que Grok effectue le rendu dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en faisant comparer par Grok son implémentation aux captures d'écran — pas simplement confirmer que ça se compile."]}, {"kind": "p", "text": "Joignez vos images de référence et donnez des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "grok\n# in the prompt (attach reference-desktop.png and reference-mobile.png):\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Show me the plan first, then render it in the browser and iterate\n  until it matches the references across breakpoints."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, validez les bonnes itérations et annulez les mauvaises (en indiquant à Grok quand vous annulez), afin que chaque passe s'appuie sur une base propre."}]}, {"id": "extend", "heading": "AGENTS.md, MCP et sous-agents", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Grok Build pratique pour un travail de design durable, et tous trois s'inscrivent proprement dans un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Contexte AGENTS.md", "body": "Les règles du projet vivent dans un AGENTS.md à la racine du dépôt. C'est le foyer durable de vos conventions de design, lu à chaque exécution — et c'est le même format ouvert que les autres agents comprennent, de sorte que les règles voyagent avec vous."}, {"label": "Serveurs MCP", "body": "Configurez les serveurs MCP pour apporter du contexte de design et des outils externes, le plus pertinent étant le serveur MCP Figma — la façon portable d'injecter de vraies specs dans le code, qui fonctionne avec tous les agents, pas seulement Grok."}, {"label": "Sous-agents et outils intégrés", "body": "Grok Build peut lancer des sous-agents parallèles pour rechercher, construire et examiner en même temps, et ses outils de fichiers, de shell et de recherche lui permettent de rassembler des références et d'exécuter la boucle de vérification sans quitter le terminal."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de les recréer projet par projet."}]}, {"id": "vs", "heading": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Grok Build", "Revue en mode planification avant l'application des changements, modèles Grok capables de lire les images et sous-agents parallèles ; connexion avec votre compte SuperGrok", "Des builds d'UI examinés, planification d'abord, avec les modèles xAI dans la boucle"], ["Codex", "Forte finition visuelle avec un skill frontend ; builds asynchrones en bac à sable", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX consciente de la base de code", "Raisonnement frontend et refactorisations à grand contexte"], ["Cursor", "Boucle construire-et-voir visuelle avec aperçu en direct et éditions inline", "Travail d'UI serré, itérer-et-observer, au sein d'un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un très grand contexte ; open source avec une offre gratuite", "Travail riche en captures d'écran et maintien d'un design system entier dans le contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « bouillie d'IA »", "blocks": [{"kind": "p", "text": "La plainte la plus courante au sujet du design généré par IA est qu'il a l'air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres dramatiques, une ambiance Inter-et-violet qui « hurle qu'une IA a fait ça ». Parmi les autres problèmes rapportés figurent des mises en page mobiles cassées et des instructions qui fuient dans le texte de l'interface. Aucun de ceux-ci n'est propre à Grok Build ; ce sont ce qui arrive lorsqu'un agent, quel qu'il soit, fonctionne sans contexte de design soigneusement sélectionné."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill de design soigneusement sélectionné force l'agent à s'engager dans une direction réelle au lieu du look par défaut."}, {"label": "Vérifiez dans un vrai navigateur", "body": "Effectuez le rendu et l'auto-contrôle sur les différents points de rupture, afin que les mises en page ne se cassent pas silencieusement sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures d'écran de référence sont le plus grand levier sur la qualité du rendu."}, {"label": "Encodez les règles dans AGENTS.md", "body": "Placez des règles de style telles que « pas de cartes héro, deux polices au maximum, hiérarchie centrée sur la marque » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque mesure d'atténuation consiste à donner à l'agent un contexte de design soigneusement sélectionné. Maintenir ce contexte à la main, projet par projet, c'est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Grok Build dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Grok Build comme un adaptateur de première partie et l'enveloppe dans une bibliothèque de skills et de design systems soigneusement sélectionnée, un pipeline de rendu structuré et une UI de bureau locale — de sorte que le contexte de design qui rend Grok bon est là dès la première exécution, et non assemblé à la main à chaque fois. Open Design est indépendant et Apache-2.0, et il s'exécute sur votre propre machine, ce qui fait de l'association une combinaison naturelle."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Grok Build comme agent.", "Authentifiez-vous avec votre compte SuperGrok ou une clé API xAI (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nous.", "Choisissez un design system et un skill, puis générez des présentations, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, et non dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Grok Build, mêmes identifiants — plus un véritable workflow de design portable et open source tout autour. Il est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Grok Build peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un design system et de vraies images de référence dans le contexte, Grok Build produit une UI réactive de qualité production, et ses modèles Grok capables de lire les images aident à vérifier le rendu par rapport aux références. Sans ce contexte, il a tendance à retomber sur un look générique, ce qui est l'écart que comble Open Design."}, {"name": "Comment authentifier Grok Build ?", "text": "Vous vous connectez via votre navigateur avec un abonnement SuperGrok ou X Premium+ (`grok login`), il n'y a donc pas de clé API à gérer. Pour un usage headless ou en CI, vous pouvez apporter une clé API xAI à la place. Open Design ne fait jamais transiter vos identifiants, dans un cas comme dans l'autre."}, {"name": "Qu'est-ce qui rend Grok Build bon pour le design en particulier ?", "text": "Deux choses : son mode planification vous laisse examiner l'approche avant que le moindre changement ne soit appliqué, et ses modèles Grok acceptent l'entrée d'images, il lit donc bien les captures d'écran de référence. Les deux aident — mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Grok Build ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est connu pour ses décisions de design précises et conscientes de la base de code ; l'avantage de Grok Build est la revue en mode planification et les modèles xAI capables de lire les images. Beaucoup d'équipes utilisent les deux — Open Design vous laisse changer d'agent sans changer votre workflow de design."}, {"name": "Comment connecter Grok Build à Figma ?", "text": "Ajoutez le serveur MCP Figma à votre configuration MCP. Grok peut alors récupérer un vrai contexte de design — composants, variables, données de mise en page — afin que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à xAI ?", "text": "Non. Grok Build est un produit de xAI ; Open Design est un projet open source indépendant qui le prend en charge en tant qu'adaptateur de première partie. Grok est une marque de xAI."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants xAI sont utilisés directement par votre agent, jamais acheminés via les serveurs d'Open Design."}], "ctaTitle": "Concevez avec Grok Build, de façon ouverte.", "ctaBody": "Apportez votre propre compte SuperGrok ou clé API xAI, gardez chaque fichier en local et obtenez une bibliothèque de design soigneusement sélectionnée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Grok Build dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'kimi': {
        ...en['kimi']!,
        title: "Kimi CLI pour le design — Open Design",
        description: "Comment on utilise Kimi CLI de Moonshot AI pour le design d'interfaces et de sites web — ses modèles agentiques Kimi K2, son grand contexte, AGENTS.md et MCP — et comment Open Design transforme Kimi CLI en un agent de design open source et local-first.",
        breadcrumb: "Kimi CLI",
        label: "Agent · Kimi CLI",
        heading: "Kimi CLI pour le design.",
        lead: "Kimi CLI est l'agent de terminal open source de Moonshot AI, propulsé par la série de modèles Kimi K2. Son solide code agentique et sa grande fenêtre de contexte lui permettent de contenir un design system entier et d'itérer par rapport aux références — dès lors que vous lui fournissez des conventions et une boucle de vérification, il devient un véritable outil de design. Open Design l'intègre dans un workflow de design open source : votre clé API Moonshot, vos fichiers, en local-first.",
        rich: {"heroCtaLead": "Open Design transforme Kimi CLI en un agent de design open source et local-first — votre clé API Moonshot, vos fichiers, une bibliothèque de skills et de design systems soigneusement sélectionnée tout autour.", "heroCtaActions": [{"label": "Utiliser Kimi CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kimi CLI est l'agent d'IA open source de Moonshot AI pour le terminal. Deux choses le rendent intéressant pour le design en particulier : il est propulsé par la série Kimi K2 — un modèle mixture-of-experts à mille milliards de paramètres méticuleusement optimisé pour le code agentique et l'usage d'outils ; et ce modèle embarque une grande fenêtre de contexte (256k tokens sur les versions récentes de K2), suffisamment large pour contenir un design system et une base de code entiers d'un coup. Associé aux bonnes références, conventions et à une boucle de vérification, il construit de véritables interfaces réactives — et vous pouvez commencer avec une connexion OAuth ou votre propre clé API Moonshot. Voici un guide pratique et de bout en bout pour utiliser Kimi CLI dans le travail d'UI, de frontend et de design system, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Kimi CLI, pourquoi ses modèles agentiques Kimi K2 et son grand contexte conviennent au design, comment l'installer de zéro, la boucle référence-vers-UI, comment AGENTS.md, MCP et les sous-agents l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les pièges qui rendent les rendus de l'IA génériques, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — une association naturelle, puisque les deux sont open source et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/kimi-design/kimi-design-hero.webp", "alt": "Boucle de feedback de design de Kimi CLI : un agent dans le terminal lisant une image de référence, un navigateur affichant l'UI et un espace de travail, avec une flèche de feedback qui boucle en retour", "caption": "La boucle centrale : Kimi CLI lit vos références dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère par rapport à elles — avec un design system entier dans le contexte."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-kimi", "label": "Ce qu'est réellement Kimi CLI"}, {"id": "why-design", "label": "Pourquoi K2 agentique + grand contexte conviennent au design"}, {"id": "setup", "label": "Configurer Kimi CLI pour le design (de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow référence-vers-UI"}, {"id": "extend", "label": "AGENTS.md, MCP et sous-agents"}, {"id": "vs", "label": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Les pièges et le rendu « bouillie d'IA »"}, {"id": "open-design", "label": "Concevoir avec Kimi CLI dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kimi", "heading": "Ce qu'est réellement Kimi CLI", "blocks": [{"kind": "p", "text": "Kimi CLI est un agent d'IA open source (Apache-2.0) que Moonshot AI propose pour le terminal. Il lit votre dépôt, modifie des fichiers, exécute des commandes shell, recherche des fichiers, récupère des pages web et choisit son étape suivante à partir du feedback qu'il reçoit — planifiant et vérifiant le travail à partir de tâches en langage naturel plutôt que de simplement compléter des lignes. C'est un outil Python, installé avec uv, et il pilote la famille de modèles Kimi K2 en coulisses."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés ressortent. Les modèles Kimi K2 sont explicitement optimisés pour le code agentique à long horizon et l'usage d'outils, de sorte que l'agent peut mener un build en plusieurs étapes jusqu'à un résultat fonctionnel. Et la fenêtre de contexte atteint jusqu'à 256k tokens sur les versions récentes de K2, suffisamment large pour contenir votre design system, votre bibliothèque de composants et votre ensemble de références d'un coup au lieu de les résumer."}, {"kind": "steps", "items": [{"label": "Fichiers de contexte", "body": "Kimi CLI lit un fichier AGENTS.md pour un contexte de projet persistant — l'endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue. Exécutez /init pour en générer un dans un projet qui n'en a pas."}, {"label": "MCP, ACP + sous-agents", "body": "Il gère les serveurs MCP de façon conversationnelle avec /mcp-config, expose une session via l'Agent Client Protocol (kimi acp) à Zed et JetBrains, et peut répartir des sous-agents intégrés coder, explore et plan dans des contextes isolés."}, {"label": "Connexion ou BYOK", "body": "Au premier lancement, /login vous laisse autoriser via OAuth (Kimi Code) ou saisir votre propre clé API Moonshot ; la plateforme de Kimi expose aussi des endpoints compatibles OpenAI et Anthropic."}]}, {"kind": "ul", "items": ["Éditeur : Moonshot AI", "Identifiant : clé API Moonshot (BYOK), ou connexion OAuth via Kimi Code", "Licence : Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Pourquoi les modèles agentiques K2 et un grand contexte conviennent au design", "blocks": [{"kind": "p", "text": "L'avantage de Kimi CLI pour le design vient de deux propriétés du modèle — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Code agentique à long horizon", "body": "Les modèles Kimi K2 sont optimisés pour l'usage d'outils et le travail en plusieurs étapes, de sorte que l'agent peut prendre une référence et un brief et réellement construire, exécuter et affiner l'UI au lieu de s'arrêter à un premier jet."}, {"label": "Une grande fenêtre de contexte", "body": "Jusqu'à 256k tokens sur les versions récentes de K2 signifie que tout le design system, les tokens et de nombreux états de référence tiennent d'un coup, de sorte que l'agent réutilise vos vraies primitives au lieu d'inventer des styles ponctuels."}, {"label": "Conventions dans AGENTS.md", "body": "Un AGENTS.md (plus un serveur MCP comme Figma) dirige l'agent vers vos tokens, vos composants et vos vraies specs, afin qu'il travaille sur une marque plutôt que sur un look par défaut."}]}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-taste-triangle.webp", "alt": "Diagramme montrant un design system, un skill et une image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois entrées que vous fournissez : un design system, un skill et de vraies images de référence."}, {"kind": "p", "text": "La leçon est la même que celle que tout agent enseigne : Kimi CLI n'a pas de goût par défaut. Il produit du bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design empaquette exactement ces entrées, ce qui explique pourquoi les deux s'accordent (voir plus bas)."}]}, {"id": "setup", "heading": "Configurer Kimi CLI pour le travail de design, de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet d'une machine vierge à un Kimi CLI capable de construire et de vérifier des interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kimi CLI (uses uv; Python 3.12–3.14, 3.13 recommended)\ncurl -LsSf https://code.kimi.com/install.sh | bash\n# or, if you already have uv:\nuv tool install --python 3.13 kimi-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nkimi              # then run /login: OAuth via Kimi Code, or paste a Moonshot API key\n\n# 3. Generate project context\n/init             # scaffolds an AGENTS.md for this project\n\n# 4. Wire an MCP server (optional, e.g. Figma for design handoff)\n/mcp-config       # add, edit, and authenticate MCP servers conversationally"}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, configurer AGENTS.md, ajouter un skill, vérifier", "caption": "La séquence de configuration : installer → s'authentifier → configurer AGENTS.md → ajouter un skill → activer la vérification dans le navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Placez vos tokens, vos primitives et vos conventions dans AGENTS.md et dirigez-y Kimi, afin que le rendu corresponde à une marque au lieu de retomber sur un look générique."}, {"label": "Ajoutez la vérification dans le navigateur", "body": "Branchez un MCP Playwright ou navigateur pour que Kimi effectue le rendu dans un vrai navigateur et vérifie son résultat sur les différents points de rupture, au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow référence-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus rentable avec Kimi CLI consiste à transformer du matériel de référence en une interface réactive fonctionnelle et à itérer jusqu'à ce qu'elle corresponde — en alimentant l'agent avec vos références et en lui faisant comparer son rendu à celles-ci dans un vrai navigateur."}, {"kind": "ol", "items": ["Partez des références les plus claires dont vous disposez — et incluez plusieurs états (bureau et mobile, survol, vide, chargement), pas seulement une image héro.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique même avec un agent solide.", "Conservez votre design system et vos conventions dans AGENTS.md, et indiquez à Kimi où vivent les tokens et les primitives canoniques.", "Lancez un serveur de développement et faites en sorte que Kimi effectue le rendu dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en faisant comparer par Kimi son implémentation aux références — pas simplement confirmer que ça se compile."]}, {"kind": "p", "text": "Dirigez Kimi vers vos références et le serveur de développement, puis donnez des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "kimi\n# in the prompt:\n> Implement the design in ./references (reference-desktop.png,\n  reference-mobile.png) using React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, validez les bonnes itérations et annulez les mauvaises (en indiquant à Kimi quand vous annulez), afin que chaque passe s'appuie sur une base propre. Kimi CLI peut aussi prendre un court enregistrement d'écran ou un clip de démonstration lorsqu'un flux est difficile à décrire avec des mots."}]}, {"id": "extend", "heading": "AGENTS.md, MCP et sous-agents", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Kimi CLI pratique pour un travail de design durable, et tous trois s'inscrivent proprement dans un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Contexte AGENTS.md", "body": "Les règles du projet vivent dans un AGENTS.md à la racine du dépôt. C'est le foyer durable de vos conventions de design, lu à chaque exécution — et c'est le même format portable que les autres agents utilisent."}, {"label": "Serveurs MCP", "body": "Ajoutez des serveurs MCP de façon conversationnelle avec /mcp-config — la façon portable d'apporter du contexte de design et des outils externes, le plus pertinent étant le serveur MCP Figma, qui fonctionnent avec tous les agents, pas seulement Kimi."}, {"label": "Sous-agents et marketplace de plugins", "body": "Répartissez des sous-agents intégrés coder, explore et plan dans des contextes isolés, et installez des skills, des serveurs MCP et des sources de données depuis la marketplace ou n'importe quel dépôt GitHub pour rassembler des références et exécuter la boucle de vérification."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de les recréer projet par projet."}]}, {"id": "vs", "heading": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["Kimi CLI", "Modèles agentiques Kimi K2 optimisés pour le code à long horizon et l'usage d'outils, avec un grand contexte ; open source et BYOK", "Builds en plusieurs étapes et maintien économique d'un design system entier dans le contexte"], ["Codex", "Forte finition visuelle avec un skill frontend ; builds asynchrones en bac à sable", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX consciente de la base de code", "Raisonnement frontend et refactorisations à grand contexte"], ["Cursor", "Boucle construire-et-voir visuelle avec aperçu en direct et éditions inline", "Travail d'UI serré, itérer-et-observer, au sein d'un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; offre gratuite", "Travail riche en captures d'écran et très grand contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « bouillie d'IA »", "blocks": [{"kind": "p", "text": "La plainte la plus courante au sujet du design généré par IA est qu'il a l'air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres dramatiques, une ambiance Inter-et-violet qui « hurle qu'une IA a fait ça ». Parmi les autres problèmes rapportés figurent des mises en page mobiles cassées et des instructions qui fuient dans le texte de l'interface. Aucun de ceux-ci n'est propre à Kimi CLI ; ce sont ce qui arrive lorsqu'un agent, quel qu'il soit, fonctionne sans contexte de design soigneusement sélectionné."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill de design soigneusement sélectionné force l'agent à s'engager dans une direction réelle au lieu du look par défaut."}, {"label": "Vérifiez dans un vrai navigateur", "body": "Faites en sorte que Kimi effectue le rendu et l'auto-contrôle sur les différents points de rupture, afin que les mises en page ne se cassent pas silencieusement sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des captures d'écran de référence sont le plus grand levier sur la qualité du rendu."}, {"label": "Encodez les règles dans AGENTS.md", "body": "Placez des règles de style telles que « pas de cartes héro, deux polices au maximum, hiérarchie centrée sur la marque » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque mesure d'atténuation consiste à donner à l'agent un contexte de design soigneusement sélectionné. Maintenir ce contexte à la main, projet par projet, c'est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Kimi CLI dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite Kimi CLI comme un adaptateur de première partie et l'enveloppe dans une bibliothèque de skills et de design systems soigneusement sélectionnée, un pipeline de rendu structuré et une UI de bureau locale — de sorte que le contexte de design qui rend Kimi bon est là dès la première exécution, et non assemblé à la main à chaque fois. Les deux sont open source et local-first, ce qui fait de l'association une combinaison naturelle."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Kimi CLI comme agent.", "Authentifiez-vous avec votre clé API Moonshot (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nous.", "Choisissez un design system et un skill, puis générez des présentations, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, et non dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Kimi CLI, même clé — plus un véritable workflow de design portable et open source tout autour. Il est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "Kimi CLI peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un design system et de vraies images de référence dans le contexte, Kimi CLI produit une UI réactive de qualité production, et ses modèles agentiques Kimi K2 peuvent effectuer le rendu et vérifier le résultat par rapport aux références. Sans ce contexte, il a tendance à retomber sur un look générique, ce qui est l'écart que comble Open Design."}, {"name": "Dois-je payer pour concevoir avec Kimi CLI ?", "text": "Vous apportez vos propres identifiants : autorisez via la connexion OAuth Kimi Code ou collez une clé API Moonshot (BYOK), facturée par la plateforme de Moonshot. Open Design ne fait jamais transiter vos identifiants, dans un cas comme dans l'autre."}, {"name": "Qu'est-ce qui rend Kimi CLI bon pour le design en particulier ?", "text": "Deux choses : les modèles Kimi K2 sont optimisés pour le code agentique à long horizon et l'usage d'outils, de sorte que l'agent peut construire et affiner jusqu'à un résultat fonctionnel, et la fenêtre de contexte atteint jusqu'à 256k tokens, suffisamment pour contenir un design system et un ensemble de références entiers d'un coup. Les deux aident — mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Kimi CLI ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est connu pour ses décisions de design précises et conscientes de la base de code ; l'avantage de Kimi CLI est ses modèles agentiques Kimi K2 et un grand contexte avec une économie BYOK. Beaucoup d'équipes utilisent les deux — Open Design vous laisse changer d'agent sans changer votre workflow de design."}, {"name": "Comment connecter Kimi CLI à Figma ?", "text": "Exécutez /mcp-config dans Kimi CLI pour ajouter et authentifier le serveur MCP Figma. Kimi peut alors récupérer un vrai contexte de design — composants, variables, données de mise en page — afin que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à Moonshot AI ?", "text": "Non. Kimi CLI est un produit de Moonshot AI ; Open Design est un projet open source indépendant qui le prend en charge en tant qu'adaptateur de première partie. Kimi est une marque de Moonshot AI."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Moonshot sont utilisés directement par votre agent, jamais acheminés via les serveurs d'Open Design."}], "ctaTitle": "Concevez avec Kimi CLI, de façon ouverte.", "ctaBody": "Apportez votre propre clé API Moonshot, gardez chaque fichier en local et obtenez une bibliothèque de design soigneusement sélectionnée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Kimi CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'deepseek': {
        ...en['deepseek']!,
        title: "DeepSeek TUI pour le design — Open Design",
        description: "Comment on utilise un agent de code de terminal propulsé par DeepSeek pour le design d'interfaces et de sites web — ses solides modèles de code, son contexte de 1M tokens, son efficacité de coût, ses fichiers de contexte et MCP — et comment Open Design transforme le DeepSeek TUI en un agent de design open source et local-first.",
        breadcrumb: "DeepSeek TUI",
        label: "Agent · DeepSeek TUI",
        heading: "DeepSeek TUI pour le design.",
        lead: "DeepSeek TUI est un agent de code de terminal piloté par les modèles de DeepSeek. Ses modèles de code solides et économiques et son contexte de 1M tokens peuvent contenir un design system et une base de code entiers d'un coup, ce qui en fait un véritable outil de design — dès lors que vous lui fournissez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open source : votre clé API DeepSeek, vos fichiers, en local-first.",
        rich: {"heroCtaLead": "Open Design transforme le DeepSeek TUI en un agent de design open source et local-first — votre clé API DeepSeek, vos fichiers, une bibliothèque de skills et de design systems soigneusement sélectionnée tout autour.", "heroCtaActions": [{"label": "Utiliser DeepSeek TUI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek TUI est un agent de code IA basé sur le terminal, propulsé par les modèles de DeepSeek. Deux choses le rendent intéressant pour le design en particulier : ses modèles de code sont solides et exceptionnellement économiques, vous pouvez donc itérer agressivement sans surveiller un compteur ; et sa fenêtre de contexte atteint jusqu'à 1M tokens, suffisamment large pour contenir un design system et une base de code entiers d'un coup au lieu de les résumer. Associé aux bonnes références, conventions et à une boucle de vérification, il construit de véritables interfaces réactives. Voici un guide pratique et de bout en bout pour utiliser un agent de terminal propulsé par DeepSeek dans le travail d'UI, de frontend et de design system, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement le DeepSeek TUI, pourquoi des modèles de code solides, un énorme contexte et un faible coût conviennent au design, comment l'installer de zéro, la boucle référence-vers-UI, comment les fichiers de contexte et MCP l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les pièges qui rendent les rendus de l'IA génériques, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — une association naturelle, puisque les deux sont ouverts et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/deepseek-design/deepseek-design-hero.webp", "alt": "Boucle de feedback de design de DeepSeek TUI : un agent dans le terminal lisant des références et des conventions, un navigateur affichant l'UI et un espace de travail, avec une flèche de feedback qui boucle en retour", "caption": "La boucle centrale : DeepSeek TUI lit vos références et conventions dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère par rapport à elles — avec un design system entier dans le contexte."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-deepseek", "label": "Ce qu'est réellement DeepSeek TUI"}, {"id": "why-design", "label": "Pourquoi des modèles de code solides + énorme contexte conviennent au design"}, {"id": "setup", "label": "Configurer DeepSeek TUI pour le design (de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow référence-vers-UI"}, {"id": "extend", "label": "Fichiers de contexte, MCP et outils"}, {"id": "vs", "label": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Les pièges et le rendu « bouillie d'IA »"}, {"id": "open-design", "label": "Concevoir avec DeepSeek TUI dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-deepseek", "heading": "Ce qu'est réellement DeepSeek TUI", "blocks": [{"kind": "p", "text": "Un DeepSeek TUI est un agent IA de terminal piloté au clavier qui exécute les modèles de DeepSeek. Il lit votre dépôt, modifie des fichiers, exécute des commandes shell, gère git et peut chercher sur le web — planifiant et vérifiant le travail à partir de tâches en langage naturel plutôt que de simplement compléter des lignes. DeepSeek lui-même est le fournisseur de modèles : une API compatible OpenAI (il expose aussi un endpoint au format Anthropic), de sorte qu'un large éventail d'agents de terminal communautaires peuvent être dirigés vers DeepSeek en définissant une URL de base et une clé. Plusieurs TUI open source proposent DeepSeek comme fournisseur de première classe."}, {"kind": "p", "text": "Pour le travail de design, trois propriétés ressortent. Les modèles de code de DeepSeek sont solides, de sorte que l'agent raisonne sur la mise en page, la structure et la hiérarchie des composants à partir d'une description claire. Sa fenêtre de contexte atteint jusqu'à 1M tokens, suffisamment large pour contenir votre design system et votre bibliothèque de composants entiers d'un coup. Et sa tarification est très basse par token, avec en plus la mise en cache de contexte par préfixe — de sorte qu'itérer sur un design coûte peu."}, {"kind": "steps", "items": [{"label": "Fichiers de contexte", "body": "Les agents de terminal lisent un fichier de contexte de projet (un fichier de style AGENTS.md, ou la propre convention de l'agent) pour des règles persistantes — l'endroit naturel pour encoder vos conventions de design, vos tokens et vos checklists de revue."}, {"label": "Outils + MCP", "body": "La plupart des DeepSeek TUI proposent des outils de fichiers, de shell, git et web, et prennent en charge les serveurs MCP pour ajouter du contexte externe comme un fichier Figma en direct — l'API de DeepSeek prend en charge l'appel d'outils, sur lequel ces agents s'appuient."}, {"label": "Apportez votre propre clé", "body": "Vous vous authentifiez avec une clé API DeepSeek de la plateforme DeepSeek. Parce que l'API est compatible OpenAI, diriger un agent vers DeepSeek tient généralement en deux lignes : URL de base et clé."}]}, {"kind": "ul", "items": ["Éditeur : DeepSeek (fournisseur de modèles et d'API)", "Identifiant : clé API DeepSeek (BYOK) de la plateforme DeepSeek", "Modèles : deepseek-v4-flash et deepseek-v4-pro (texte uniquement ; pas d'entrée d'images native)"]}]}, {"id": "why-design", "heading": "Pourquoi des modèles de code solides et un énorme contexte conviennent au design", "blocks": [{"kind": "p", "text": "L'avantage de DeepSeek TUI pour le design vient du modèle et de son économie — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Code solide et économique", "body": "Les modèles de code de DeepSeek sont capables et peu coûteux, de sorte que l'agent raisonne bien sur la mise en page et la structure et que vous pouvez itérer de nombreuses fois sans que le coût ne soit la contrainte."}, {"label": "Une fenêtre de contexte de 1M tokens", "body": "Un grand contexte signifie que tout le design system, les tokens et de nombreux états de référence tiennent d'un coup, de sorte que l'agent réutilise vos vraies primitives au lieu d'inventer des styles ponctuels — et la mise en cache de contexte garde les prompts répétés bon marché."}, {"label": "Conventions dans un fichier de contexte", "body": "Un fichier de contexte de projet (plus le serveur MCP Figma) dirige l'agent vers vos tokens, vos composants et vos vraies specs, afin qu'il travaille sur une marque plutôt que sur un look par défaut."}]}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-taste-triangle.webp", "alt": "Diagramme montrant un design system, un skill et une référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois entrées que vous fournissez : un design system, un skill et de vraies références."}, {"kind": "p", "text": "La leçon est la même que celle que tout agent enseigne : DeepSeek TUI n'a pas de goût par défaut. Il produit du bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design empaquette exactement ces entrées, ce qui explique pourquoi les deux s'accordent (voir plus bas)."}]}, {"id": "setup", "heading": "Configurer DeepSeek TUI pour le travail de design, de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet d'une machine vierge à un DeepSeek TUI capable de construire et de vérifier des interfaces. Les noms exacts d'installation et de commandes varient selon l'agent de terminal que vous choisissez, donc les étapes ci-dessous restent au niveau qui vaut pour tous."}, {"kind": "code", "lang": "bash", "code": "# 1. Get a DeepSeek API key from the DeepSeek platform\n#    https://platform.deepseek.com\nexport DEEPSEEK_API_KEY=sk-...\n\n# 2. Install a DeepSeek-capable terminal agent (follow its README),\n#    then point it at DeepSeek. The API is OpenAI-compatible:\n#      base URL: https://api.deepseek.com\n#      model:    deepseek-v4-flash (or deepseek-v4-pro)\n#    (an Anthropic-format endpoint also exists at /anthropic)\n\n# 3. Start it in your project and generate project context\ncd your-project\n#   create/scaffold a project context file with your design rules\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to the agent's MCP server configuration"}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : obtenir une clé, installer l'agent, configurer le fichier de contexte, ajouter un skill, vérifier", "caption": "La séquence de configuration : obtenir une clé → diriger l'agent vers DeepSeek → configurer un fichier de contexte → ajouter un skill → activer la vérification dans le navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de design", "body": "Placez vos tokens, vos primitives et vos conventions dans le fichier de contexte de l'agent et dirigez-y l'agent, afin que le rendu corresponde à une marque au lieu de retomber sur un look générique."}, {"label": "Ajoutez la vérification dans le navigateur", "body": "Branchez un MCP Playwright ou navigateur pour que l'agent effectue le rendu dans un vrai navigateur et vérifie son résultat sur les différents points de rupture, au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow référence-vers-UI", "blocks": [{"kind": "p", "text": "Les modèles de DeepSeek sont en texte uniquement — ils ne lisent pas les images nativement — donc la boucle de design la plus rentable consiste à transformer des références claires et des mises en page décrites en une interface réactive fonctionnelle, puis à vérifier le résultat dans un vrai navigateur plutôt que de demander au modèle de regarder une capture d'écran."}, {"kind": "ol", "items": ["Partez des références les plus claires dont vous disposez — et décrivez plusieurs états (bureau et mobile, survol, vide, chargement), pas seulement une image héro.", "Soyez précis dans le prompt ; des prompts vagues produisent une UI générique même avec un modèle solide. Détaillez l'espacement, la hiérarchie et les composants à réutiliser.", "Conservez votre design system et vos conventions dans le fichier de contexte, et indiquez à l'agent où vivent les tokens et les primitives canoniques.", "Lancez un serveur de développement et faites en sorte que l'agent effectue le rendu dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat — c'est là que se fait la vérification, puisque le modèle ne peut pas voir l'image lui-même.", "Itérez en faisant comparer par l'agent le DOM rendu et les styles calculés à votre spec décrite — pas simplement confirmer que ça se compile."]}, {"kind": "p", "text": "Décrivez la cible avec précision et donnez des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "# in the agent's prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Layout: two-column dashboard, 240px sidebar, 24px gutters,\n  card grid at 3/2/1 columns for desktop/tablet/mobile.\n  Reuse my existing design-system components and tokens from the\n  context file. Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate against the\n  spec across breakpoints until it matches."}, {"kind": "p", "text": "Gardez des prompts courts et ciblés, validez les bonnes itérations et annulez les mauvaises (en indiquant à l'agent quand vous annulez), afin que chaque passe s'appuie sur une base propre."}]}, {"id": "extend", "heading": "Fichiers de contexte, MCP et outils", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent un DeepSeek TUI pratique pour un travail de design durable, et tous trois s'inscrivent proprement dans un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Fichier de contexte de projet", "body": "Les règles du projet vivent dans un fichier de contexte à la racine du dépôt (avec des couches globale et équipe). C'est le foyer durable de vos conventions de design, lu à chaque exécution."}, {"label": "Serveurs MCP", "body": "Configurez les serveurs MCP dans l'agent — la façon portable d'apporter du contexte de design et des outils externes, le plus pertinent étant le serveur MCP Figma, qui fonctionnent avec tous les agents, pas seulement un seul. L'API de DeepSeek prend en charge l'appel d'outils sur lequel ces serveurs s'appuient."}, {"label": "Outils intégrés", "body": "Les DeepSeek TUI proposent des outils de fichiers, de shell, git et web pour que l'agent puisse rassembler des références et exécuter la boucle de vérification sans quitter le terminal."}]}, {"kind": "p", "text": "Ce sont des capacités portables et multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de les recréer projet par projet."}]}, {"id": "vs", "heading": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de vainqueur unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les combinent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force en design", "Idéal pour"], "rows": [["DeepSeek TUI", "Modèles de code solides et très économiques, à poids ouverts et avec un contexte de 1M tokens ; texte uniquement (pas de vision native)", "Itération à grand volume avec un budget serré et maintien d'un design system entier dans le contexte"], ["Codex", "Forte finition visuelle avec un skill frontend ; builds asynchrones en bac à sable", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX consciente de la base de code", "Raisonnement frontend et refactorisations à grand contexte"], ["Cursor", "Boucle construire-et-voir visuelle avec aperçu en direct et éditions inline", "Travail d'UI serré, itérer-et-observer, au sein d'un IDE"], ["Gemini CLI", "Compréhension multimodale native des images et un contexte de 1M tokens ; open source avec une offre gratuite", "Travail riche en captures d'écran où l'agent lit directement les références"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous retombent sur une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Les pièges, et comment éviter le rendu « bouillie d'IA »", "blocks": [{"kind": "p", "text": "La plainte la plus courante au sujet du design généré par IA est qu'il a l'air générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres dramatiques, une ambiance Inter-et-violet qui « hurle qu'une IA a fait ça ». Parmi les autres problèmes rapportés figurent des mises en page mobiles cassées et des instructions qui fuient dans le texte de l'interface. Aucun de ceux-ci n'est propre à DeepSeek TUI ; ce sont ce qui arrive lorsqu'un agent, quel qu'il soit, fonctionne sans contexte de design soigneusement sélectionné. Parce que DeepSeek est en texte uniquement, il est particulièrement important de vérifier dans un vrai navigateur plutôt que de faire confiance au modèle pour « regarder » le résultat."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill de design soigneusement sélectionné force l'agent à s'engager dans une direction réelle au lieu du look par défaut."}, {"label": "Vérifiez dans un vrai navigateur", "body": "Effectuez le rendu et l'auto-contrôle sur les différents points de rupture avec un outil navigateur — essentiel ici, puisque le modèle ne peut pas lire une capture d'écran lui-même — afin que les mises en page ne se cassent pas silencieusement sur mobile."}, {"label": "Fournissez tokens et références", "body": "De vrais tokens de design et des références concrètes et décrites sont le plus grand levier sur la qualité du rendu."}, {"label": "Encodez les règles dans le fichier de contexte", "body": "Placez des règles de style telles que « pas de cartes héro, deux polices au maximum, hiérarchie centrée sur la marque » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Remarquez que chaque mesure d'atténuation consiste à donner à l'agent un contexte de design soigneusement sélectionné. Maintenir ce contexte à la main, projet par projet, c'est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec DeepSeek TUI dans Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de design open source que le workflow ci-dessus ne cesse de réclamer. Il traite l'agent DeepSeek comme un adaptateur de première partie et l'enveloppe dans une bibliothèque de skills et de design systems soigneusement sélectionnée, un pipeline de rendu structuré et une UI de bureau locale — de sorte que le contexte de design qui rend DeepSeek bon est là dès la première exécution, et non assemblé à la main à chaque fois. Les deux sont ouverts et local-first, ce qui fait de l'association une combinaison naturelle."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez le DeepSeek TUI comme agent.", "Authentifiez-vous avec votre propre clé API DeepSeek (BYOK) — les identifiants restent sur votre machine et ne transitent jamais par nous.", "Choisissez un design system et un skill, puis générez des présentations, des prototypes et des landing pages avec un goût cohérent.", "Chaque artefact et fichier DESIGN.md vit dans votre propre dépôt, et non dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent DeepSeek, même clé — plus un véritable workflow de design portable et open source tout autour. Il est local-first et Apache-2.0, donc rien de votre travail ni de vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquentes", "faq": [{"name": "DeepSeek TUI peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un design system et des références concrètes dans le contexte, un agent de terminal propulsé par DeepSeek produit une UI réactive de qualité production, et vous vérifiez le résultat dans un vrai navigateur. Les modèles de DeepSeek sont en texte uniquement, donc la boucle de vérification remplace la lecture native des images. Sans ce contexte, il a tendance à retomber sur un look générique, ce qui est l'écart que comble Open Design."}, {"name": "Combien coûte la conception avec DeepSeek TUI ?", "text": "Peu — l'API de DeepSeek est parmi les moins chères par token, et la mise en cache de contexte par préfixe réduit encore le coût des prompts répétés, vous pouvez donc itérer agressivement. Vous apportez votre propre clé API DeepSeek (BYOK) ; Open Design ne fait jamais transiter vos identifiants."}, {"name": "Qu'est-ce qui rend DeepSeek bon pour le design en particulier ?", "text": "Des modèles de code solides et économiques, des poids ouverts, et un contexte de 1M tokens qui contient un design system et un ensemble de références entiers d'un coup. DeepSeek est en texte uniquement — il ne lit pas les images nativement — donc le goût vient toujours du design system, du skill et des références décrites que vous fournissez, vérifiés dans un navigateur."}, {"name": "DeepSeek TUI ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est connu pour ses décisions de design précises et conscientes de la base de code ; l'avantage de DeepSeek TUI est les poids ouverts, un coût très bas et un énorme contexte pour l'itération à grand volume. Beaucoup d'équipes utilisent les deux — Open Design vous laisse changer d'agent sans changer votre workflow de design."}, {"name": "Comment connecter DeepSeek TUI à Figma ?", "text": "Ajoutez le serveur MCP Figma dans la configuration MCP de votre agent de terminal. L'agent peut alors récupérer un vrai contexte de design — composants, variables, données de mise en page — afin que le code généré corresponde à la source au lieu de l'approximer. L'API de DeepSeek prend en charge l'appel d'outils sur lequel MCP s'appuie."}, {"name": "Open Design est-il affilié à DeepSeek ?", "text": "Non. DeepSeek est le fournisseur de modèles et d'API ; Open Design est un projet open source indépendant qui prend en charge les agents de terminal propulsés par DeepSeek en tant qu'adaptateur de première partie. DeepSeek est une marque de DeepSeek."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artefacts et DESIGN.md restent dans votre propre dépôt, et votre clé API DeepSeek est utilisée directement par votre agent, jamais acheminée via les serveurs d'Open Design."}], "ctaTitle": "Concevez avec DeepSeek TUI, de façon ouverte.", "ctaBody": "Apportez votre propre clé API DeepSeek, gardez chaque fichier en local et obtenez une bibliothèque de design soigneusement sélectionnée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser DeepSeek TUI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Mettre une étoile sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'trae-cli': {
        ...en['trae-cli']!,
        title: "Trae CLI pour le design — Open Design",
        description: "Comment les gens utilisent le Trae CLI de ByteDance (trae-agent) pour le design UI et web — son agent CLI open-source et model-agnostic, son principe bring-your-own LLM provider et son workflow piloté par config — et comment Open Design transforme Trae CLI en agent de design open-source et local-first via ACP.",
        breadcrumb: "Trae CLI",
        label: "Agent · Trae CLI",
        heading: "Trae CLI pour le design.",
        lead: "Trae CLI est l'agent terminal open-source de ByteDance (trae-agent). Il est agnostique quant au modèle — vous le dirigez vers le fournisseur de LLM en qui vous avez confiance — et il lit votre dépôt, édite des fichiers et exécute des commandes à partir de tâches en langage naturel, ce qui en fait un véritable outil de design une fois que vous lui donnez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open-source via ACP : votre propre clé de fournisseur, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Trae CLI en un agent de design local-first et open-source — votre propre clé de fournisseur LLM, vos fichiers, une bibliothèque de skill et de design-system soigneusement sélectionnée autour de celui-ci, piloté via ACP.", "heroCtaActions": [{"label": "Utiliser Trae CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Trae CLI est l'agent IA open-source de ByteDance pour le terminal, diffusé sous le projet trae-agent. Deux éléments le rendent particulièrement intéressant pour le design : il est agnostique quant au modèle, vous pouvez donc utiliser le fournisseur de LLM en qui vous avez confiance plutôt que d'être verrouillé chez un seul vendeur ; et c'est un agent transparent sous licence MIT qui lit votre codebase, édite des fichiers et exécute des commandes shell à partir de tâches en langage naturel. Associé aux bonnes références, conventions et à une boucle de vérification, il construit des UI réelles et responsives — et il est gratuit et ouvert pour commencer, vous ne fournissez qu'une clé de fournisseur. Ceci est un guide pratique de bout en bout pour utiliser Trae CLI pour l'UI, le frontend et le travail sur les design systems, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Trae CLI, pourquoi un agent ouvert et agnostique de modèle convient au design, comment le configurer de zéro, la boucle capture d'écran vers interface, comment son fichier de config et ses outils l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — un jumelage naturel, puisque les deux sont open-source et s'exécutent sur votre propre machine, avec Open Design pilotant Trae CLI via Agent Client Protocol (ACP)."], "heroImage": {"src": "/agents/trae-cli-design/trae-cli-design-hero.webp", "alt": "Boucle de feedback design Trae CLI : un agent terminal lisant une image de référence, un navigateur affichant l'UI et un espace de travail, avec une flèche de feedback bouclant en retour", "caption": "La boucle principale : Trae CLI lit vos références et conventions dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère en se basant sur elles."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-trae-cli", "label": "Ce qu'est réellement Trae CLI"}, {"id": "why-design", "label": "Pourquoi un agent ouvert et agnostique convient au design"}, {"id": "setup", "label": "Configurer Trae CLI pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "Configuration, outils et fournisseurs"}, {"id": "vs", "label": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Trae CLI dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-trae-cli", "heading": "Ce qu'est réellement Trae CLI", "blocks": [{"kind": "p", "text": "Trae CLI est l'agent en ligne de commande du projet open-source trae-agent de ByteDance. Il lit votre dépôt, visualise, crée et édite des fichiers, et exécute des commandes shell dans un environnement persistant — planifiant et vérifiant le travail à partir de tâches en langage naturel plutôt que de simplement compléter des lignes. Il est sous licence MIT et construit autour d'une architecture transparente et modulaire, ce qui le rend facile à inspecter et à étendre. Il est distinct de Trae IDE, l'éditeur IA de ByteDance basé sur VS Code, bien que les deux proviennent du même fournisseur."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés se distinguent. Il est agnostique du modèle — vous choisissez le fournisseur LLM, vous n'êtes donc jamais lié aux forces ou aux limites d'un seul modèle. Et il est entièrement ouvert et piloté par configuration, son comportement, ses outils et son fournisseur peuvent donc être fixés dans le contrôle de version aux côtés de votre projet plutôt que cachés derrière un service hébergé."}, {"kind": "steps", "items": [{"label": "Modes run et interactif", "body": "Trae CLI exécute une tâche unique avec `trae-cli run \"...\"` ou maintient une session continue avec `trae-cli interactive` — l'endroit naturel pour itérer sur une UI en suivant vos conventions de design."}, {"label": "Outils intégrés", "body": "Il fournit des outils d'édition de fichiers, d'exécution bash/shell et de raisonnement structuré dès le départ, il peut donc construire, lancer un serveur de développement et inspecter les erreurs d'exécution sans quitter le terminal."}, {"label": "Apportez votre propre fournisseur", "body": "Vous fournissez une clé API pour le fournisseur en qui vous avez confiance — OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, ou un modèle Ollama local — via des variables d'environnement ou un fichier de configuration."}]}, {"kind": "ul", "items": ["Fournisseur : ByteDance (projet open-source trae-agent)", "Identifiant : clé API d'un fournisseur LLM (BYOK) — par ex. OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, ou un modèle Ollama local", "Licence : MIT, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent ouvert et agnostique convient au design", "blocks": [{"kind": "p", "text": "L'avantage design de Trae CLI vient du fait qu'il est ouvert et flexible au niveau du fournisseur — mais, comme pour tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Agnostique vis-à-vis des modèles par conception", "body": "Parce que vous choisissez le fournisseur, vous pouvez router le travail de design vers le modèle qui raisonne le mieux aujourd'hui sur la mise en page et le code frontend, et le changer plus tard sans modifier votre workflow."}, {"label": "Ouvert et piloté par configuration", "body": "L'agent, ses outils et son fournisseur sont épinglés dans un fichier de configuration que vous pouvez commiter, de sorte qu'une équipe obtient le même comportement d'agent sur chaque machine au lieu de diverger par développeur."}, {"label": "Conventions dans votre dépôt", "body": "Dirigez l'agent vers vos tokens, composants et spécifications réelles — conservés dans votre projet — pour qu'il travaille avec une marque au lieu d'adopter par défaut un look générique."}]}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Trae CLI n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées et les transmet à Trae CLI via ACP, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Trae CLI pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine vierge jusqu'à un Trae CLI capable de construire et vérifier une UI. Trae CLI est installé depuis les sources avec uv, puis configuré avec le fournisseur LLM que vous souhaitez utiliser."}, {"kind": "code", "lang": "bash", "code": "# 1. Get Trae CLI (trae-agent) from source — needs uv\ngit clone https://github.com/bytedance/trae-agent.git\ncd trae-agent\nuv sync --all-extras\nsource .venv/bin/activate\n\n# 2. Authenticate by pointing it at your LLM provider key\n#    set it in the environment (or a trae_config.yaml file)\nexport OPENAI_API_KEY=...        # or ANTHROPIC_API_KEY, GOOGLE_API_KEY, etc.\n\n# 3. Run a task in your project\ntrae-cli run \"Create a hello world page\"\n#    or hold a session:\ntrae-cli interactive\n\n# 4. Check the resolved configuration (keys are masked)\ntrae-cli show-config"}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, configurer les conventions, ajouter un skill, vérifier", "caption": "La séquence de configuration : installation → authentification avec une clé fournisseur → configuration de vos conventions de design → ajout d'un skill → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Conservez vos tokens, primitives et conventions dans le dépôt et pointez Trae CLI vers eux, afin que le rendu corresponde à une marque plutôt que de recourir par défaut à un aspect générique."}, {"label": "Ajoutez une vérification par navigateur", "body": "Faites en sorte que Trae CLI lance un serveur de développement et effectue un rendu dans un véritable navigateur afin qu'il vérifie sa sortie sur tous les breakpoints au lieu de simplement confirmer que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Trae CLI consiste à transformer une image de référence en interface utilisateur fonctionnelle et responsive, puis à itérer jusqu'à ce qu'elle corresponde. Comme Trae CLI est agnostique au modèle, orientez-le vers un fournisseur dont le modèle gère bien vos références, et appuyez-vous sur un vrai navigateur pour vérifier le résultat."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et décrivez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un modèle performant.", "Conservez votre système de design et vos conventions dans le dépôt, et indiquez à Trae CLI où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et faire effectuer le rendu par Trae CLI dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en demandant à Trae CLI de comparer son implémentation aux références — pas seulement de confirmer que ça compile."]}, {"kind": "p", "text": "Lancer une session interactive et donner des contraintes concrètes plutôt qu'une demande en une ligne :"}, {"kind": "code", "lang": "bash", "code": "trae-cli interactive\n# in the session:\n> Implement the attached reference design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Trae CLI quand vous annulez), pour que chaque passe parte d'une base propre."}]}, {"id": "extend", "heading": "Configuration, outils et fournisseurs", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Trae CLI pratique pour un travail de design soutenu, et tous trois s'alignent parfaitement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Fichier de configuration", "body": "Trae CLI lit un fichier trae_config.yaml qui fixe votre fournisseur, modèle et paramètres — le lieu durable et versionnable de la façon dont l'agent s'exécute sur un projet."}, {"label": "Choix du fournisseur", "body": "Parce qu'il prend en charge de nombreux fournisseurs (OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, Ollama), vous routez le travail de design vers le modèle en qui vous avez confiance et le changez sans recâbler votre workflow."}, {"label": "Outils intégrés", "body": "Ses outils d'édition de fichiers, de shell et de raisonnement structuré lui permettent de rassembler le contexte, compiler, lancer un serveur de dev et exécuter la boucle de vérification sans quitter le terminal."}]}, {"kind": "p", "text": "Ce sont des capacités portables au niveau agent — exactement le genre de choses qu'Open Design est conçu pour orchestrer via ACP, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Trae CLI", "Open-source (MIT) et agnostique au modèle ; apportez votre propre clé de fournisseur, piloté par configuration et transparent", "Les équipes qui souhaitent un agent gratuit et inspectable ainsi que la liberté de choisir ou de changer de fournisseurs LLM"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; open-source avec une offre gratuite", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus fréquente concernant le design généré par IA est qu'il paraît générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres dramatiques, une ambiance Inter-and-purple qui « crie qu'une IA l'a fait ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui fuient dans le texte d'interface. Aucun de ces défauts n'est propre à Trae CLI ; ce sont les conséquences de tout agent qui tourne sans contexte de design soigné."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Faites en sorte que Trae CLI effectue un rendu et une auto-vérification sur tous les breakpoints afin que les layouts ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles dans votre dépôt", "body": "Placez les règles de style « pas de hero cards, maximum deux typographies, hiérarchie brand-first » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Trae CLI à l'intérieur d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Trae CLI comme un adaptateur first-party — en le pilotant via l'Agent Client Protocol (ACP) via son binaire trae-cli — et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale, de sorte que le contexte de conception qui rend Trae CLI performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Les deux sont open-source et local-first, ce qui fait de cette association un choix naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Trae CLI comme agent.", "Authentifiez-vous avec votre propre clé de fournisseur LLM (BYOK) — les identifiants restent sur votre machine et ne sont jamais proxiés via nous.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent CLI Trae, même clé de fournisseur — plus un véritable workflow de design open-source et portable autour de lui. Il est local-first et open-source, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Trae CLI peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un design system, et un vrai contexte de référence, Trae CLI produit des UI responsive de qualité production, et parce qu'il est model-agnostic vous pouvez router le travail vers le fournisseur qui raisonne le mieux sur votre frontend. Sans ce contexte, il tend à revenir par défaut à un look générique, ce qui est le manque qu'Open Design comble."}, {"name": "Dois-je payer pour concevoir avec Trae CLI ?", "text": "Trae CLI lui-même est gratuit et open-source (MIT). Vous apportez votre propre clé de fournisseur LLM, donc votre seul coût est celui facturé par ce fournisseur — ou rien si vous exécutez un modèle local via Ollama. Open Design ne proxyfie jamais vos identifiants de toute façon."}, {"name": "Qu'est-ce qui rend Trae CLI particulièrement adapté au design ?", "text": "Deux choses : il est agnostique au modèle, vous choisissez donc le fournisseur LLM le mieux adapté au travail frontend, et il est entièrement ouvert et piloté par configuration, son comportement est donc transparent et reproductible au sein d'une équipe. Mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Trae CLI ou Claude Code pour le design frontend ?", "text": "Les deux sont capables. Claude Code est reconnu pour ses décisions de conception spécifiques et conscientes du codebase ; l'avantage de Trae CLI est d'être open-source et flexible en termes de fournisseurs, vous n'êtes donc jamais verrouillé à un seul modèle. De nombreuses équipes utilisent les deux — Open Design vous permet de changer d'agents sans modifier votre workflow de conception."}, {"name": "De quoi Open Design a-t-il besoin pour exécuter Trae CLI ?", "text": "Open Design pilote le binaire trae-cli de Trae CLI via l'Agent Client Protocol (ACP) et utilise la clé de votre fournisseur LLM configuré. Vous sélectionnez Trae CLI comme agent, vous le dirigez vers un fournisseur, et Open Design fournit le contexte de conception soigné autour de lui."}, {"name": "Open Design est-il affilié à ByteDance ou Trae ?", "text": "Non. Trae CLI (trae-agent) est un produit de ByteDance ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur first-party. Trae est une marque déposée de ByteDance."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et open-source. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants de fournisseur LLM sont utilisés directement par votre agent, jamais routés via les serveurs Open Design."}], "ctaTitle": "Concevez avec Trae CLI, la voie ouverte.", "ctaBody": "Apportez votre propre clé de fournisseur LLM, conservez tous les fichiers en local et obtenez une bibliothèque de conception organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Trae CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'aider': {
        ...en['aider']!,
        title: "Aider pour le design — Open Design",
        description: "Comment les gens utilisent Aider — le pair-programmeur IA open-source et model-agnostic dans votre terminal — pour le design UI et web, avec éditions natives git, un fichier CONVENTIONS.md, la prise en charge des images et BYOK, et comment Open Design transforme Aider en agent de design open-source et local-first.",
        breadcrumb: "Aider",
        label: "Agent · Aider",
        heading: "Aider pour le design.",
        lead: "Aider est le pair-programmeur IA open-source qui vit dans votre terminal et travaille directement sur votre dépôt git. Il est agnostique au modèle — pointez-le vers Claude, GPT-4o, DeepSeek ou Gemini avec votre propre clé — et il modifie les fichiers, auto-commit et lit les images sur les modèles capables de vision. Cela en fait un véritable outil de design une fois que vous lui donnez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow design open-source : vos clés de fournisseur, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Aider en agent de conception open-source local-first — vos propres clés API de fournisseur, vos fichiers, une bibliothèque de skill et de système de conception soignée autour de lui.", "heroCtaActions": [{"label": "Utiliser Aider dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Aider est un outil open-source de pair-programming IA qui s'exécute dans votre terminal et travaille sur le code de votre dépôt git. Deux aspects le rendent particulièrement intéressant pour le design : il est agnostique au modèle, vous apportez donc votre propre clé pour presque n'importe quel LLM — Claude, GPT-4o, DeepSeek, Gemini ou un modèle local — et il est natif git, modifiant les fichiers sur place et committant chaque changement avec un message approprié pour que chaque itération soit révisable et réversible. Sur les modèles capables de vision, il peut aussi lire des images, une capture d'écran devient donc partie du prompt. Associé aux bonnes références, conventions et une boucle de vérification, il construit de vraies interfaces responsives. Ceci est un guide pratique de bout en bout pour utiliser Aider pour l'UI, le frontend et le travail sur design system, et pour l'intégrer dans un workflow design structuré avec Open Design.", "Il couvre ce qu'est réellement Aider, pourquoi un outil agnostique aux modèles et natif git convient au design, comment le configurer de zéro, la boucle capture d'écran vers UI, comment CONVENTIONS.md et les commandes d'Aider l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui font paraître la sortie IA générique, et comment Open Design comble le fossé en tant que couche de design ouverte et local-first — un appariement naturel, puisque les deux sont open-source et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/aider-design/aider-design-hero.webp", "alt": "Boucle de feedback design Aider : un agent terminal lisant une image de référence, un dépôt git avec des commits, un navigateur affichant l'interface, avec une flèche de feedback qui boucle en retour", "caption": "La boucle principale : Aider lit vos références dans le terminal, édite et commite l'UI dans votre dépôt git, et itère en se basant sur elles — avec le modèle que vous apportez."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-aider", "label": "Ce qu'est réellement Aider"}, {"id": "why-design", "label": "Pourquoi model-agnostic + git-native conviennent au design"}, {"id": "setup", "label": "Configurer Aider pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "CONVENTIONS.md, images et commandes"}, {"id": "vs", "label": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Aider dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-aider", "heading": "Ce qu'est réellement Aider", "blocks": [{"kind": "p", "text": "Aider est un outil open-source (Apache-2.0) de pair-programming IA qui s'exécute dans votre terminal. Il lit votre base de code existante, mappe tout le dépôt pour le contexte, modifie les fichiers sur place et commit automatiquement chaque changement avec un message approprié — vous pouvez donc diff, gérer et annuler le travail de l'IA avec les outils git que vous utilisez déjà. Il fonctionne avec plus de 100 langages de programmation et démarre de nouveaux projets ou s'appuie sur l'existant."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés se distinguent. Aider est agnostique du modèle : vous apportez votre propre clé et le connectez à presque n'importe quel LLM — Claude, GPT-4o, DeepSeek, Gemini, ou un modèle local — vous n'êtes donc jamais lié à un seul fournisseur. Et sur les modèles capables de vision comme GPT-4o et Claude, il peut lire des fichiers image, transformant une capture d'écran de référence en partie du prompt."}, {"kind": "steps", "items": [{"label": "Fichier de conventions", "body": "Aider lit un fichier CONVENTIONS.md que vous chargez avec /read CONVENTIONS.md (ou aider --read CONVENTIONS.md) — l'endroit naturel pour encoder vos conventions de design, tokens et checklists de revue comme contexte en lecture seule."}, {"label": "Modifications Git natives", "body": "Chaque modification est appliquée aux fichiers de votre dépôt et commitée automatiquement, de sorte que chaque itération de conception est vérifiable et réversible avec les outils git familiers."}, {"label": "Apportez votre propre modèle", "body": "Connectez OpenAI, Anthropic, DeepSeek, Gemini ou un modèle local avec votre propre clé API ; Aider n'est lié à aucun fournisseur unique ni backend hébergé."}]}, {"kind": "ul", "items": ["Fournisseur : Aider (Aider-AI, open source) — agnostique au modèle", "Identifiant : votre propre clé API fournisseur — BYOK (OpenAI, Anthropic, DeepSeek, Gemini, ou un modèle local)", "Licence : Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un outil agnostique et natif git convient au design", "blocks": [{"kind": "p", "text": "L'avantage design d'Aider vient de sa façon de travailler avec votre dépôt et votre choix de modèle — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Agnostique vis-à-vis des modèles, BYOK", "body": "Choisissez le modèle qui conçoit le mieux pour votre tâche et votre budget — Claude, GPT-4o, DeepSeek, Gemini — et changez librement sans modifier votre workflow, le tout avec votre propre clé."}, {"label": "Itération Git native", "body": "Les commits automatiques transforment chaque passe de design en un diff révisable que vous pouvez annuler, vous itérez donc sur une base propre plutôt qu'un tas de modifications non suivies."}, {"label": "Conventions dans CONVENTIONS.md", "body": "Un fichier CONVENTIONS.md (chargé en lecture seule) oriente l'agent vers vos tokens, composants et règles, de sorte qu'il travaille sur une marque plutôt qu'un style par défaut."}]}, {"kind": "image", "src": "/agents/aider-design/aider-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Aider n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Aider pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine vierge jusqu'à un Aider capable de construire et vérifier une UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Aider (recommended installer; Python 3.8–3.13)\npython -m pip install aider-install\naider-install\n# or with pipx: pipx install aider-chat\n\n# 2. Start it in your git project and bring your own key\ncd your-project\naider --model sonnet --api-key anthropic=<your-key>\n# or: aider --api-key openai=<your-key>   (also deepseek=, gemini=)\n\n# 3. Load your design conventions as read-only context\naider --read CONVENTIONS.md\n\n# 4. Add a reference image (on a vision-capable model)\n#    inside the chat: /add reference-desktop.png"}, {"kind": "image", "src": "/agents/aider-design/aider-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, apporter votre propre clé, charger CONVENTIONS.md, ajouter une référence, vérifier", "caption": "La séquence de configuration : installation → apportez votre propre clé → chargement de CONVENTIONS.md → ajout d'une référence → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Placez vos tokens, primitives et conventions dans CONVENTIONS.md et chargez-le en lecture seule, pour que la sortie corresponde à une marque plutôt qu'un style générique par défaut."}, {"label": "Ajoutez une vérification par navigateur", "body": "Lancer un serveur de développement et faire effectuer le rendu par Aider dans un vrai navigateur, en vérifiant sa sortie sur tous les points de rupture au lieu de confirmer uniquement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Aider consiste à transformer une image de référence en UI fonctionnelle et responsive et à itérer jusqu'à ce qu'elle corresponde — en utilisant un modèle capable de vision pour comparer la sortie à la référence, chaque passage étant commité dans git."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et incluez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un modèle performant.", "Conservez votre design system et vos conventions dans CONVENTIONS.md, et indiquez à Aider où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et vérifier le résultat rendu dans un vrai navigateur, en redimensionnant aux points de rupture.", "Itérez en demandant à Aider de comparer son implémentation aux captures d'écran — pas seulement de confirmer que ça compile."]}, {"kind": "p", "text": "Ajoutez une image avec /add (ou /paste depuis le presse-papiers) sur un modèle doté de vision, puis donnez des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "aider --model gpt-4o --read CONVENTIONS.md\n# in the chat:\n> /add reference-desktop.png\n> /add reference-mobile.png\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from CONVENTIONS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  I'll render it in the browser and tell you what to fix until it matches\n  the references across breakpoints."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés. Parce qu'Aider commite chaque changement, vous conservez les bonnes itérations et utilisez git (ou /undo) pour annuler les mauvaises — afin que chaque passe parte d'une base propre."}]}, {"id": "extend", "heading": "CONVENTIONS.md, images et commandes", "blocks": [{"kind": "p", "text": "Trois capacités rendent Aider pratique pour un travail de design continu, et toutes trois se transposent proprement dans un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Contexte CONVENTIONS.md", "body": "Chargez les conventions de codage et de design avec /read CONVENTIONS.md ou aider --read CONVENTIONS.md, ou définissez read: CONVENTIONS.md dans .aider.conf.yml pour le charger à chaque exécution. C'est le foyer durable de vos tokens, primitives et règles."}, {"label": "Images et pages web", "body": "Sur les modèles compatibles avec la vision, /add un fichier image ou /paste depuis le presse-papiers pour donner à Aider une référence réelle ; /web <url> extrait le texte d'une page dans le chat pour un contexte supplémentaire."}, {"label": "Commandes dans le chat", "body": "Des commandes comme /add pour intégrer des fichiers dans le contexte, /read pour des références en lecture seule, et /undo pour annuler le dernier commit lui permettent de rassembler les références et d'exécuter la boucle de vérification sans quitter le terminal."}]}, {"kind": "p", "text": "Ce sont des capacités portables et natives au dépôt — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Aider", "Open-source, agnostique au modèle (BYOK) et natif git ; les commits automatiques rendent chaque itération vérifiable et réversible", "Itération native sur votre base de code existante avec le modèle qui conçoit le mieux"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; open-source avec une offre gratuite", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à Aider ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Rendez et auto-vérifiez sur les breakpoints pour que les layouts ne cassent pas silencieusement sur mobile — sur un modèle capable de vision, renvoyez les captures d'écran."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles dans CONVENTIONS.md", "body": "Placez les règles de style « pas de hero cards, maximum deux typographies, hiérarchie brand-first » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Aider au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Aider comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Aider performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Les deux sont open-source et local-first, ce qui fait de cette association un choix naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Aider comme agent.", "Authentifiez-vous avec votre propre clé API de fournisseur (BYOK) — OpenAI, Anthropic, DeepSeek ou Gemini ; les identifiants restent sur votre machine et ne sont jamais relayés par nos serveurs.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt git, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Aider, même clé — plus un véritable workflow de conception portable et open-source autour. Il est local-first et open-source, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Aider peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies images de référence en contexte, Aider produit une interface utilisateur responsive de qualité production, et sur les modèles dotés de vision il lit les captures d'écran pour vérifier la sortie par rapport aux références. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Quels modèles puis-je utiliser avec Aider pour le design ?", "text": "Aider est agnostique au modèle. Vous apportez votre propre clé API et connectez presque n'importe quel LLM — Claude, GPT-4o, DeepSeek, Gemini ou un modèle local. Pour le travail de design basé sur l'image, utilisez un modèle capable de vision comme GPT-4o ou Claude. Open Design ne proxifie jamais vos identifiants."}, {"name": "Qu'est-ce qui rend Aider particulièrement adapté au design ?", "text": "Deux choses : il est agnostique au modèle, vous choisissez donc le modèle qui design le mieux pour votre tâche, et il est natif git, commitant chaque changement pour que chaque itération de design soit révisable et réversible. Les deux aident — mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Est-ce qu'Aider modifie mes fichiers et fait des commits git ?", "text": "Oui. Aider édite les fichiers directement dans votre dépôt et commit automatiquement chaque modification avec un message pertinent, ce qui vous permet de comparer, gérer et annuler le travail de l'IA avec les outils git que vous utilisez déjà."}, {"name": "Comment transmettre mes conventions de design à Aider ?", "text": "Créez un CONVENTIONS.md avec vos tokens, primitives et règles, puis chargez-le en lecture seule avec /read CONVENTIONS.md ou aider --read CONVENTIONS.md (ou définissez read: CONVENTIONS.md dans .aider.conf.yml pour le charger à chaque exécution). Aider travaille alors selon votre marque au lieu d'un style par défaut."}, {"name": "Open Design est-il affilié à Aider ?", "text": "Non. Aider est un projet open-source indépendant (Aider-AI) ; Open Design est un projet open-source indépendant distinct qui prend en charge Aider en tant qu'adaptateur de première partie. Les deux ne sont pas affiliés."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et open-source. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt git, et vos clés API de fournisseur sont utilisées directement par votre agent, jamais routées via les serveurs Open Design."}], "ctaTitle": "Concevoir avec Aider, à la manière open.", "ctaBody": "Apportez votre propre clé API de fournisseur, conservez tous les fichiers en local dans votre dépôt git et obtenez une bibliothèque de conception organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Aider dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'antigravity': {
        ...en['antigravity']!,
        title: "Antigravity pour le design — Open Design",
        description: "Comment les gens utilisent Google Antigravity — la plateforme de développement agent-first de Google propulsée par les modèles multimodaux Gemini 3.x, avec son Editor View, sa Manager Surface, son contrôle de navigateur intégré et ses Artifacts — pour le design UI et web, et comment Open Design transforme Antigravity en agent de design open-source et local-first.",
        breadcrumb: "Antigravity",
        label: "Agent · Antigravity",
        heading: "Antigravity pour le design.",
        lead: "Antigravity est la plateforme de développement agent-first de Google. Ses modèles Gemini 3.x lisent des captures d'écran et raisonnent sur la mise en page, son navigateur intégré permet aux agents de vérifier ce qu'ils construisent, et ses Artifacts transforment le travail de l'agent en livrables examinables — ce qui en fait un véritable outil de design une fois que vous lui donnez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open-source : votre compte Google, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Antigravity en agent de conception open-source local-first — votre compte Google, vos fichiers, une bibliothèque de skill et de système de conception soignée autour de lui.", "heroCtaActions": [{"label": "Utiliser Antigravity dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Antigravity est la plateforme de développement agent-first de Google, lancée aux côtés de Gemini 3. Trois choses la rendent intéressante spécifiquement pour le design : ses agents fonctionnent sur des modèles Gemini 3.x nativement multimodaux, donc ils lisent une capture d'écran et raisonnent sur la mise en page, l'espacement et la hiérarchie ; il embarque un navigateur intégré que l'agent peut piloter, donc il rend et vérifie sa propre UI au lieu de deviner ; et il produit des Artifacts — listes de tâches, plans d'implémentation, captures d'écran et enregistrements de navigateur — qui transforment le travail de l'agent en quelque chose que vous pouvez réellement examiner. Associé aux bonnes références, conventions et une boucle de vérification, il construit de vraies UI responsives — et c'est gratuit pour commencer avec un compte Google. Voici un guide pratique de bout en bout pour utiliser Antigravity pour le travail d'UI, frontend et de design-system, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Antigravity, pourquoi Gemini multimodal et un navigateur intégré conviennent au design, comment le configurer de zéro, la boucle capture d'écran vers interface, comment son contexte d'agent et son outillage l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — un jumelage naturel, puisque Open Design est open-source et s'exécute sur votre propre machine."], "heroImage": {"src": "/agents/antigravity-design/antigravity-design-hero.webp", "alt": "Boucle de retour de feedback design Antigravity : un IDE agent-first lisant une image de référence, un navigateur intégré rendant l'UI, et une surface Manager, avec une flèche de feedback bouclant en retour", "caption": "La boucle principale : un agent Antigravity lit vos références, construit et vérifie l'UI dans son navigateur intégré, et itère en se basant sur elles — en exposant le travail sous forme d'Artifacts vérifiables."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-antigravity", "label": "Ce qu'est réellement Antigravity"}, {"id": "why-design", "label": "Pourquoi Gemini multimodal + un navigateur intégré conviennent au design"}, {"id": "setup", "label": "Configurer Antigravity pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "Contexte de l'agent, outils et Artifacts"}, {"id": "vs", "label": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Antigravity dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-antigravity", "heading": "Ce qu'est réellement Antigravity", "blocks": [{"kind": "p", "text": "Antigravity est la plateforme de développement agent-first de Google — un IDE propulsé par IA conçu pour que des agents autonomes, et non des chatbots en sidebar, fassent le travail. Annoncé le 18 novembre 2025 aux côtés de Gemini 3 et disponible en preview publique gratuitement pour les particuliers, il vous permet de déléguer des tâches logicielles complexes multi-outils à un agent qui opère à travers l'éditeur, le terminal et un navigateur intégré. Ses agents fonctionnent principalement sur les modèles multimodaux Gemini 3.x de Google."}, {"kind": "p", "text": "Pour le travail de design, trois propriétés se distinguent. Ses agents lisent des captures d'écran et raisonnent sur la mise en page réelle, car Gemini 3.x est nativement multimodal. Il peut piloter un véritable navigateur, il rend donc et vérifie ce qu'il construit. Et il expose des Artifacts — listes de tâches, plans, captures d'écran et enregistrements du navigateur — vous examinez donc une production tangible plutôt que des logs bruts d'outils."}, {"kind": "steps", "items": [{"label": "Editor View + Manager Surface", "body": "L'Editor View est un IDE IA familier avec auto-complétion et commandes en ligne ; la Manager Surface vous permet de créer, orchestrer et observer plusieurs agents travaillant de manière asynchrone sur différents espaces de travail — l'endroit naturel pour exécuter une longue tâche de design."}, {"label": "Navigateur intégré + Artifacts", "body": "Les agents peuvent agir dans un navigateur intégré et émettre des Artifacts (captures d'écran, enregistrements navigateur, listes de tâches, plans) sur lesquels vous pouvez laisser des commentaires — une boucle de vérification native de la plateforme plutôt qu'ajoutée après coup."}, {"label": "Gratuit pour commencer", "body": "Se connecter avec un compte Google personnel offre des limites de débit généreuses sur Gemini 3.x ; la plateforme fonctionne sur macOS, Windows et Linux."}]}, {"kind": "ul", "items": ["Fournisseur : Google", "Identifiant : compte Google (Gmail personnel), gratuit pendant la préversion publique", "Binary: launch with agy; runs on macOS, Windows, and Linux"]}]}, {"id": "why-design", "heading": "Pourquoi Gemini multimodal et un navigateur intégré conviennent au design", "blocks": [{"kind": "p", "text": "L'avantage design d'Antigravity vient du modèle et de la plateforme ensemble — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Forte compréhension multimodale", "body": "Parce que Gemini 3.x est nativement multimodal, l'agent lit bien les captures d'écran de référence — comparant son rendu de sortie à une image plutôt que de deviner à partir d'une description textuelle."}, {"label": "Un navigateur intégré pour vérifier", "body": "L'agent pilote un vrai navigateur, il affiche donc l'UI, la vérifie dans différents états et détecte les mises en page cassées — et capture le résultat sous forme d'Artifact d'enregistrement de navigateur que vous pouvez examiner."}, {"label": "Conventions que l'agent lit", "body": "Encodez vos tokens, composants et règles de revue dans le contexte du projet de l'agent afin qu'il travaille selon votre marque plutôt qu'un rendu par défaut."}]}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Antigravity n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Antigravity pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine vierge jusqu'à un agent Antigravity capable de construire et vérifier une UI. Les menus exacts dans l'application peuvent évoluer durant la preview, donc ceci reste au niveau sur lequel vous pouvez compter."}, {"kind": "code", "lang": "bash", "code": "# 1. Download Antigravity for your OS (macOS, Windows, Linux)\n#    from the official download page: antigravity.google/download\n\n# 2. Launch it and sign in\nagy               # opens Antigravity; sign in with your Google account\n\n# 3. Accept the data-use policy, pick a theme, and open your project folder\n\n# 4. Start an agent task in the Editor View or the Manager Surface,\n#    selecting a Gemini 3.x model (e.g. Gemini 3.1 Pro)"}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : télécharger, se connecter avec Google, ouvrir le projet, ajouter des règles de design et un skill, activer la vérification dans le navigateur", "caption": "La séquence de configuration : téléchargement → connexion avec Google → ouverture de votre projet → ajout de règles de design et d'un skill → utilisation du navigateur intégré pour vérifier."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Placez vos tokens, primitives et conventions dans le contexte de projet de l'agent pour que la sortie corresponde à une marque plutôt qu'un style générique par défaut."}, {"label": "Utiliser le navigateur intégré", "body": "Faites en sorte que l'agent effectue un rendu dans le navigateur intégré d'Antigravity et vérifie sa sortie sur tous les breakpoints — vérifiant que l'interface utilisateur est correcte, pas seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Antigravity consiste à transformer une image de référence en UI fonctionnelle et responsive et à itérer jusqu'à ce qu'elle corresponde — en s'appuyant sur le modèle multimodal pour comparer la sortie à la référence, et sur le navigateur intégré pour la vérifier."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et incluez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un modèle performant.", "Conservez votre système de design et vos conventions dans le contexte projet de l'agent, et indiquez-lui où se trouvent les tokens et les primitives canoniques.", "Laissez l'agent faire le rendu dans le navigateur intégré d'Antigravity, en redimensionnant aux breakpoints pour vérifier le résultat.", "Itérez en demandant à l'agent de comparer son implémentation aux captures d'écran — pas seulement de confirmer que ça compile — et examinez les Artifacts d'enregistrement de navigateur et de captures d'écran qu'il produit."]}, {"kind": "p", "text": "Attachez vos images de référence et donnez des contraintes concrètes, puis laissez l'agent vérifier dans le navigateur :"}, {"kind": "code", "lang": "text", "code": "# In an Antigravity agent task, attach reference-desktop.png and\n# reference-mobile.png, then prompt:\n\nImplement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nRender it in the integrated browser and iterate until it matches\nthe references across breakpoints, and show me the screenshots."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à l'agent quand vous annulez), pour que chaque passe parte d'une base propre."}]}, {"id": "extend", "heading": "Contexte de l'agent, outils et Artifacts", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Antigravity pratique pour un travail de design soutenu, et tous trois s'alignent parfaitement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Contexte de projet", "body": "Les règles de projet persistantes sont le lieu durable pour vos conventions de design — tokens, primitives et listes de vérification de revue que l'agent lit à chaque tâche, afin que la sortie reste cohérente avec la marque."}, {"label": "Navigateur intégré + terminal", "body": "Les agents agissent dans l'éditeur, le terminal et un navigateur intégré, ils peuvent donc rassembler des références, lancer un serveur de dev et vérifier l'interface rendue sans quitter la plateforme."}, {"label": "Artifacts que vous examinez", "body": "Les listes de tâches, plans d'implémentation, captures d'écran et enregistrements de navigateur rendent le travail de l'agent lisible ; vous laissez des commentaires sur l'Artifact et l'agent intègre les corrections."}]}, {"kind": "p", "text": "Ce sont les capacités dont une boucle de design sérieuse a besoin — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Antigravity", "IDE agent-first avec Gemini 3.x multimodal, un navigateur intégré pour l'auto-vérification et des Artifacts révisables ; gratuit en preview", "Builds multi-agents asynchrones avec vérification intégrée du navigateur pour l'UI"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Agent terminal open-source sur Gemini multimodal avec un contexte de 1M tokens et un niveau gratuit", "Travail en terminal riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à Antigravity ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans le navigateur intégré", "body": "Utilisez le modèle multimodal et le navigateur intégré d'Antigravity pour rendre et auto-vérifier à travers les breakpoints afin que les layouts ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles dans le contexte du projet", "body": "Placez les règles de style « pas de hero cards, maximum deux typographies, hiérarchie brand-first » là où l'agent les lit à chaque tâche."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Antigravity au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Antigravity comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Antigravity performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Open Design est open-source et local-first, ce qui fait de cette association un choix naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Antigravity comme agent.", "Authentifiez-vous avec votre compte Google — les identifiants restent sur votre machine et ne sont jamais proxiés via nous.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Antigravity, même compte Google — plus un véritable workflow de design open-source et portable autour de lui. Open Design est local-first et Apache-2.0, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Antigravity peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies images de référence en contexte, Antigravity produit une interface utilisateur responsive de qualité production, et ses agents multimodaux Gemini 3.x vérifient la sortie dans le navigateur intégré. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Dois-je payer pour concevoir avec Antigravity ?", "text": "Antigravity est disponible en preview publique gratuitement pour les particuliers, avec des limites de débit généreuses sur Gemini 3.x lorsque vous vous connectez avec un compte Google personnel. Open Design ne proxie jamais vos identifiants non plus."}, {"name": "Qu'est-ce qui rend Antigravity particulièrement adapté au design ?", "text": "Trois éléments : ses agents s'exécutent nativement sur les modèles multimodaux Gemini 3.x qui lisent bien les captures d'écran de référence, il intègre un navigateur que l'agent peut piloter pour vérifier l'UI, et il expose des Artifacts — captures d'écran et enregistrements du navigateur — que vous pouvez examiner. Le goût provient toujours du design système, du skill et des références que vous fournissez."}, {"name": "Antigravity ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de conception spécifiques et conscientes du codebase ; l'avantage d'Antigravity est sa plateforme agent-first — Gemini 3.x multimodal, un navigateur intégré pour la vérification et des Artifacts vérifiables. De nombreuses équipes utilisent les deux — Open Design vous permet de changer d'agents sans modifier votre workflow de conception."}, {"name": "Comment vérifier ce que construit Antigravity ?", "text": "Antigravity embarque un navigateur intégré que ses agents peuvent piloter, donc ils rendent l'UI, la vérifient à travers les breakpoints, et capturent des captures d'écran et enregistrements de navigateur comme Artifacts. Examiner ces Artifacts — et faire en sorte que l'agent compare sa sortie à vos références — est la façon de garder le résultat conforme aux spécifications."}, {"name": "Open Design est-il affilié à Google ?", "text": "Non. Antigravity est un produit de Google ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur de première partie. Antigravity et Gemini sont des marques de Google."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Google sont utilisés directement par votre agent, jamais routés via les serveurs Open Design."}], "ctaTitle": "Concevoir avec Antigravity, à la manière open.", "ctaBody": "Apportez votre propre compte Google, conservez tous les fichiers en local et obtenez une bibliothèque de conception organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Antigravity dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'reasonix': {
        ...en['reasonix']!,
        title: "DeepSeek Reasonix pour la conception — Open Design",
        description: "Comment les gens utilisent DeepSeek Reasonix — l'agent de codage terminal communautaire natif DeepSeek — pour le design UI et web, et comment Open Design le transforme en agent de design open-source et local-first. BYOK avec votre propre clé API DeepSeek.",
        breadcrumb: "DeepSeek Reasonix",
        label: "Agent · DeepSeek Reasonix",
        heading: "DeepSeek Reasonix pour la conception.",
        lead: "DeepSeek Reasonix est un agent de codage terminal open-source construit par la communauté, propulsé par les modèles DeepSeek. Il lit votre dépôt, modifie les fichiers et exécute votre boucle de vérification à moindre coût — toute sa conception est construite autour du prefix cache de DeepSeek pour maintenir les longues sessions abordables. Avec des références, des conventions et une vérification navigateur, il devient un véritable outil de conception. Open Design l'intègre dans un workflow de conception open-source : votre propre clé API DeepSeek, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme DeepSeek Reasonix en agent de conception open-source local-first — votre propre clé API DeepSeek, vos fichiers, une bibliothèque de skill et de système de conception soignée autour de lui.", "heroCtaActions": [{"label": "Utiliser DeepSeek Reasonix dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek Reasonix est un agent de codage IA open-source construit par la communauté pour le terminal, propulsé par les modèles de DeepSeek. Ce n'est pas un produit officiel DeepSeek — il est maintenu par l'auteur GitHub esengine et la communauté, et il est spécifiquement conçu autour des mécaniques de prefix-cache de DeepSeek afin que les longues sessions itératives restent peu coûteuses. Il lit votre dépôt, modifie les fichiers, exécute les commandes et fonctionne à partir de tâches en langage naturel plutôt que simplement compléter des lignes. Vous apportez votre propre clé API DeepSeek (BYOK), et l'agent s'exécute sur des modèles DeepSeek tels que deepseek-v4-pro et deepseek-v4-flash. Voici un guide pratique de bout en bout pour utiliser DeepSeek Reasonix pour le travail d'interface utilisateur, de frontend et de système de conception, et pour l'intégrer dans un workflow de conception structuré avec Open Design.", "Il couvre ce qu'est réellement DeepSeek Reasonix, pourquoi un agent DeepSeek économique convient au design itératif, comment le configurer de zéro avec votre propre clé, la boucle référence vers interface, comment les skills et MCP l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — un jumelage naturel, puisque les deux sont open-source et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/reasonix-design/reasonix-design-hero.webp", "alt": "Boucle de rétroaction de conception DeepSeek Reasonix : un agent terminal lisant les références de conception, un navigateur affichant l'interface utilisateur et un espace de travail, avec une flèche de rétroaction bouclant en arrière", "caption": "La boucle principale : DeepSeek Reasonix travaille dans le terminal en se basant sur vos références et conventions, vous vérifiez l'UI dans un vrai navigateur, et il itère — à moindre coût, grâce au cache de préfixes DeepSeek."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-reasonix", "label": "Ce qu'est réellement DeepSeek Reasonix"}, {"id": "why-design", "label": "Pourquoi un agent DeepSeek économique convient au design"}, {"id": "setup", "label": "Configurer DeepSeek Reasonix pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow référence-vers-UI"}, {"id": "extend", "label": "Skills, MCP et config"}, {"id": "vs", "label": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec DeepSeek Reasonix dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-reasonix", "heading": "Ce qu'est réellement DeepSeek Reasonix", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix est un agent de codage IA open-source (MIT) pour le terminal, développé par l'auteur GitHub esengine et la communauté. Il est natif DeepSeek : conçu autour des mécaniques de prefix-cache de DeepSeek afin que les longues sessions itératives restent peu coûteuses. Il lit votre dépôt, modifie les fichiers avec un éditeur SEARCH/REPLACE à révision contrôlée, exécute des commandes shell et fonctionne à partir de tâches en langage naturel — planifiant et vérifiant plutôt que simplement complétant des lignes. Il est important de préciser qu'il s'agit d'un projet communautaire, et non d'un produit officiel de l'entreprise DeepSeek."}, {"kind": "p", "text": "Pour le travail de design, ce qui compte c'est qu'il s'agit d'un agent de codage capable et conscient du dépôt qui fonctionne sur de puissants modèles DeepSeek à faible coût. Les modèles DeepSeek qu'il utilise sont texte uniquement — ils ne lisent pas nativement les images — la boucle de design pratique est donc pilotée par référence et vérifiée dans un véritable navigateur, plutôt que l'agent « voyant » directement une capture d'écran. L'efficacité des coûts est l'avantage pertinent pour le design : vous pouvez itérer sur l'UI de nombreuses fois sans la facture qui décourage habituellement les boucles serrées."}, {"kind": "steps", "items": [{"label": "Natif DeepSeek, BYOK", "body": "Reasonix s'exécute sur les modèles DeepSeek tels que deepseek-v4-pro et deepseek-v4-flash. Vous apportez votre propre clé API DeepSeek — le credential réside dans votre environnement, pas dans la config de l'agent."}, {"label": "Édition contextuelle du dépôt", "body": "Il lit et modifie les fichiers de votre projet avec un éditeur à revue contrôlée et exécute des commandes shell, il peut donc construire et itérer sur du code d'interface réel dans votre propre dépôt."}, {"label": "Skills + MCP", "body": "Il prend en charge les skills rédigés en Markdown et les serveurs MCP, vous pouvez donc lui donner des conventions durables et connecter un contexte externe comme une source de design."}]}, {"kind": "ul", "items": ["Éditeur : communauté / l'auteur GitHub esengine (et non DeepSeek l'entreprise)", "Identifiant : votre propre clé API DeepSeek (BYOK), fournie via l'environnement", "Licence : MIT, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent DeepSeek économique convient au design", "blocks": [{"kind": "p", "text": "L'avantage de conception de DeepSeek Reasonix concerne moins une capacité unique spectaculaire que le fait de rendre le travail itératif d'interface utilisateur peu coûteux et reproductible — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Itération serrée et économique", "body": "Parce qu'il est conçu autour du cache de préfixe de DeepSeek, les longues sessions de design restent abordables — vous pouvez donc exécuter la boucle construire-vérifier-affiner de nombreuses fois au lieu de la rationner."}, {"label": "Réutilisation contextuelle du dépôt", "body": "Il modifie directement les fichiers de votre dépôt, ce qui lui permet de réutiliser vos composants et tokens existants plutôt que d'inventer des styles ponctuels, lorsque vous les lui indiquez."}, {"label": "Conventions dans skills", "body": "Les Skills Markdown et la configuration de projet vous permettent d'encoder les tokens, composants et règles de vérification, pour que l'agent travaille selon votre marque plutôt qu'avec un style par défaut."}]}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : DeepSeek Reasonix n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes décrites — ainsi qu'un navigateur pour vérifier. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer DeepSeek Reasonix pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin depuis une machine vierge jusqu'à un DeepSeek Reasonix capable de construire et vérifier une UI. Comme il s'agit d'un projet communautaire, suivez toujours les instructions d'installation dans le README du dépôt ; le schéma ci-dessous donne la forme générale."}, {"kind": "code", "lang": "bash", "code": "# 1. Install DeepSeek Reasonix (Node 22+) — see the repo README\nnpm install -g reasonix\n\n# 2. Bring your own DeepSeek API key (BYOK)\n#    Reasonix reads it from your environment, not from config files.\nexport DEEPSEEK_API_KEY=sk-...    # your DeepSeek key\n\n# 3. Start it in your project\ncd your-project\nreasonix                         # see README for the exact subcommands\n\n# 4. Add a design source via MCP (optional)\n#    e.g. a Figma MCP server, configured per the repo docs"}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, ajouter votre clé DeepSeek, configurer les conventions, ajouter un skill, vérifier dans un navigateur", "caption": "La séquence de configuration : installation → ajout de votre clé API DeepSeek → encodage des conventions → ajout d'un skill → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Placez vos tokens, primitives et conventions dans un skill ou une configuration de projet et orientez Reasonix vers eux, pour que la sortie corresponde à une marque plutôt qu'un style générique par défaut."}, {"label": "Ajoutez une vérification par navigateur", "body": "Étant donné que les modèles DeepSeek sont en texte uniquement, connectez un serveur MCP Playwright ou navigateur pour que l'agent effectue le rendu dans un véritable navigateur et vérifie sa sortie sur tous les breakpoints plutôt que de confirmer uniquement la réussite du build."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow référence-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec DeepSeek Reasonix consiste à transformer des références claires en UI fonctionnelle et responsive et à itérer jusqu'à ce qu'elle corresponde. Comme les modèles DeepSeek sont texte uniquement, les références sont fournies sous forme de descriptions et spécifications détaillées — non lues nativement comme images — et la correspondance est confirmée par le rendu dans un vrai navigateur."}, {"kind": "ol", "items": ["Traduisez vos références en spécifications concrètes — décrivez la mise en page, les espacements, la hiérarchie et les états (desktop et mobile, hover, vide, chargement) en mots, car le modèle lit le texte, pas les pixels.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un modèle performant.", "Conservez votre système de design et vos conventions dans un skill ou une configuration de projet, et indiquez à Reasonix où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et vérifier le résultat dans un vrai navigateur, en redimensionnant aux points de rupture — connectez un MCP navigateur pour que l'agent puisse s'auto-vérifier.", "Itérez en comparant l'interface rendue avec vos références dans le navigateur — pas seulement en confirmant qu'elle se construit."]}, {"kind": "p", "text": "Donnez à l'agent des contraintes concrètes dans le prompt plutôt qu'un brief vague :"}, {"kind": "code", "lang": "bash", "code": "reasonix\n# in the prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reference: a two-column hero, 48px vertical rhythm, brand teal\n  accent, system-ui type — desktop and mobile described in DESIGN.md.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in a browser and iterate until it matches the spec\n  across breakpoints."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Reasonix quand vous annulez), pour que chaque passe parte d'une base propre — et pour que la boucle économique et favorable au cache reste productive."}]}, {"id": "extend", "heading": "Skills, MCP et config", "blocks": [{"kind": "p", "text": "Quelques points d'extension rendent DeepSeek Reasonix pratique pour un travail de design soutenu, et ils se mappent proprement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Skills Markdown", "body": "Reasonix prend en charge les skills rédigés en Markdown — le lieu durable pour vos conventions de design, tokens et checklists de revue, appliqués à chaque exécution."}, {"label": "Serveurs MCP", "body": "Il intègre les serveurs MCP, le moyen portable d'intégrer du contexte de design et des outils externes — notamment une source de design comme un serveur Figma MCP — qui fonctionnent sur tous les agents, pas seulement Reasonix."}, {"label": "Configuration de projet et outils intégrés", "body": "La configuration par projet plus les outils intégrés de fichiers, shell et web lui permettent de rassembler le contexte et d'exécuter la boucle de vérification sans quitter le terminal. Consultez le README du dépôt pour les chemins de configuration exacts."}]}, {"kind": "p", "text": "Ce sont des capacités portables multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI pour la conception", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["DeepSeek Reasonix", "Open-source et propulsé par DeepSeek ; économique grâce à la mise en cache de préfixes, BYOK avec votre propre clé DeepSeek (construit par la communauté, modèles texte uniquement)", "Itération UI bon marché et à haut volume dans votre propre dépôt"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; open-source avec une offre gratuite", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à DeepSeek Reasonix ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé — et comme ses modèles sont texte uniquement, décrire les références avec précision importe encore plus."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Comme le modèle ne peut pas voir, effectuez le rendu et l'auto-vérification sur tous les breakpoints dans un véritable navigateur afin que les mises en page ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références décrites", "body": "De véritables tokens de design et des états de référence précisément décrits constituent le levier le plus important sur la qualité de sortie pour un agent text-only."}, {"label": "Encoder les règles dans un skill ou une config", "body": "Placez les règles de style « pas de hero cards, maximum deux typographies, hiérarchie brand-first » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec DeepSeek Reasonix au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite DeepSeek Reasonix comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Reasonix performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Les deux sont open-source et local-first, ce qui fait de cette association un choix naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez DeepSeek Reasonix comme agent.", "Authentifiez-vous avec votre propre clé API DeepSeek (BYOK) — les identifiants restent sur votre machine et ne sont jamais proxiés via nous.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent DeepSeek Reasonix, même clé — plus un véritable workflow de design open-source et portable autour de lui. Il est local-first et open-source, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "DeepSeek Reasonix peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un design system, et des références précisément décrites en contexte, DeepSeek Reasonix produit des UI responsive de qualité production dans votre propre dépôt, et vous vérifiez la sortie dans un vrai navigateur. Ses modèles DeepSeek sont text-only, donc la boucle est basée sur la référence-décrite-et-vérifiée plutôt que sur la lecture d'image. Sans ce contexte, il tend à revenir par défaut à un look générique, ce qui est le manque qu'Open Design comble."}, {"name": "Dois-je payer pour concevoir avec DeepSeek Reasonix ?", "text": "Vous apportez votre propre clé API DeepSeek, donc vous payez DeepSeek pour l'utilisation (BYOK) — mais l'agent est construit autour du cache de préfixe de DeepSeek pour maintenir ce coût bas sur de longues sessions. Reasonix lui-même est gratuit et sous licence MIT. Open Design ne proxifie jamais vos identifiants."}, {"name": "DeepSeek Reasonix est-il un produit officiel DeepSeek ?", "text": "Non. DeepSeek Reasonix est un projet open-source construit par la communauté, créé par l'auteur GitHub esengine — il fonctionne sur les modèles de DeepSeek et utilise une clé API DeepSeek, mais il n'est ni fabriqué ni approuvé par l'entreprise DeepSeek. DeepSeek est une marque de son propriétaire respectif."}, {"name": "DeepSeek Reasonix ou Claude Code pour la conception frontend ?", "text": "Les deux peuvent faire un vrai travail de conception. Claude Code est reconnu pour ses décisions de conception spécifiques et conscientes du codebase ; l'avantage de DeepSeek Reasonix est d'être open-source et économique, permettant des itérations rapides et à haut volume sur les modèles DeepSeek avec votre propre clé. De nombreuses équipes en utilisent plus d'un — Open Design vous permet de changer d'agents sans modifier votre workflow de conception."}, {"name": "Comment connecter DeepSeek Reasonix à une source de design comme Figma ?", "text": "Reasonix prend en charge les serveurs MCP, vous pouvez donc ajouter un MCP de source de design (tel qu'un serveur MCP Figma) selon la documentation du dépôt. L'agent peut alors extraire un véritable contexte de design — composants, variables, données de layout — sous forme de texte sur lequel il peut agir, de sorte que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à DeepSeek ?", "text": "Non. DeepSeek Reasonix est un projet communautaire qui fonctionne sur les modèles de DeepSeek ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur de première partie. Il n'est affilié ni à l'entreprise DeepSeek ni aux mainteneurs de Reasonix. DeepSeek est une marque de son propriétaire respectif."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et open-source. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et votre clé API DeepSeek est utilisée directement par votre agent, jamais routée via les serveurs Open Design."}], "ctaTitle": "Concevoir avec DeepSeek Reasonix, à la manière open.", "ctaBody": "Apportez votre propre clé API DeepSeek, conservez tous les fichiers en local et obtenez une bibliothèque de conception organisée autour de l'agent open-source que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser DeepSeek Reasonix dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'hermes': {
        ...en['hermes']!,
        title: "Hermes pour le design — Open Design",
        description: "Comment les gens utilisent Hermes de Nous Research — l'agent de codage terminal autonome et multi-provider — pour le design UI et web, et comment Open Design le transforme en agent de design open-source et local-first avec votre propre clé xAI, OpenAI ou Anthropic.",
        breadcrumb: "Hermes",
        label: "Agent · Hermes",
        heading: "Hermes pour le design.",
        lead: "Hermes est l'agent terminal autonome open-source de Nous Research. Il planifie, exécute et délègue le travail sur sa propre machine — et il est agnostique de fournisseur, donc vous apportez votre propre clé xAI, OpenAI ou Anthropic. Cette autonomie en fait un véritable outil de design une fois que vous lui donnez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open-source : votre clé, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Hermes en un agent de design local-first et open-source — votre propre clé xAI, OpenAI ou Anthropic, vos fichiers, une bibliothèque de skill et de design-system soigneusement sélectionnée autour de celui-ci.", "heroCtaActions": [{"label": "Utiliser Hermes dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Hermes est l'agent AI autonome open-source de Nous Research. Deux choses le rendent intéressant spécifiquement pour le design : il est véritablement agentique, donc il planifie une tâche, l'exécute et délègue des parties à des sous-agents isolés plutôt que de simplement compléter des lignes ; et il est agnostique de fournisseur, donc vous le pointez vers le modèle auquel vous faites confiance — xAI Grok par défaut, ou OpenAI et Anthropic via bring-your-own-key. Associé aux bonnes références, conventions et à une boucle de vérification, il construit une UI réelle et responsive sur votre propre machine. Ceci est un guide pratique de bout en bout pour utiliser Hermes pour l'UI, le frontend et le travail sur les design systems, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Hermes, pourquoi un agent autonome multi-fournisseurs convient au design, comment le configurer de zéro, la boucle capture d'écran vers interface, comment les skills et les sous-agents l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — un jumelage naturel, puisque les deux sont open-source et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/hermes-design/hermes-design-hero.webp", "alt": "Boucle de retour design Hermes : un agent terminal autonome lisant une image de référence, déléguant à des sous-agents, un navigateur rendant l'UI, et un espace de travail, avec une flèche de feedback bouclant en retour", "caption": "La boucle principale : Hermes lit vos références dans le terminal, planifie et délègue la construction, vérifie l'UI dans un vrai navigateur, et itère en se basant sur elles — avec le modèle que vous apportez."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-hermes", "label": "Ce qu'est réellement Hermes"}, {"id": "why-design", "label": "Pourquoi un agent autonome multi-fournisseurs convient au design"}, {"id": "setup", "label": "Configurer Hermes pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "Skills, sous-agents et fournisseurs"}, {"id": "vs", "label": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Hermes dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-hermes", "heading": "Ce qu'est réellement Hermes", "blocks": [{"kind": "p", "text": "Hermes est un agent AI autonome open-source (MIT) de Nous Research. Il s'exécute de manière persistante sur votre propre machine ou serveur, lit votre dépôt, modifie des fichiers, exécute des commandes shell, recherche sur le web et — de manière cruciale — planifie et exécute un travail multi-étapes de manière autonome, déléguant des parties à des sous-agents isolés. C'est un agent autonome, pas un copilote attaché à un IDE."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés se distinguent. Il est véritablement agentique, vous pouvez donc lui confier un objectif et il planifie, construit et vérifie plutôt que d'attendre des directives ligne par ligne. Et il est agnostique du fournisseur : vous apportez votre propre clé, par défaut xAI Grok mais libre de le pointer vers OpenAI, Anthropic, ou tout autre endpoint supporté — vous contrôlez donc quel modèle raisonne sur votre design."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes construit et réutilise des skills — une mémoire procédurale qu'il crée à partir de l'expérience — le lieu naturel pour capturer vos conventions de design, vos tokens et vos checklists de revue afin qu'ils persistent d'une exécution à l'autre."}, {"label": "Sous-agents + outils", "body": "Il génère des sous-agents isolés pour des flux de travail parallèles et fournit des outils de fichier, shell, web et navigateur, il peut donc recueillir des références et exécuter une boucle de construction et vérification sans quitter le terminal."}, {"label": "Apportez votre propre clé", "body": "Hermes utilise par défaut xAI Grok et prend en charge OpenAI, Anthropic, OpenRouter et de nombreux autres fournisseurs via BYOK — définissez une clé ou lancez un flux OAuth et choisissez votre modèle."}]}, {"kind": "ul", "items": ["Éditeur : Nous Research", "Identifiant : clé de fournisseur via BYOK — xAI (Grok, par défaut), OpenAI ou Anthropic — ajoutée avec hermes auth add", "Licence : MIT, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent autonome multi-fournisseurs convient au design", "blocks": [{"kind": "p", "text": "L'avantage de Hermes pour le design provient de deux propriétés — mais, comme avec chaque agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Planification et exécution autonomes", "body": "Parce que Hermes planifie, exécute et délègue de lui-même, il peut prendre un objectif de design — correspondre à cette référence, le rendre responsive — et itérer vers celui-ci au lieu d'avoir besoin que chaque étape soit détaillée."}, {"label": "Apportez le modèle en qui vous avez confiance", "body": "L'approche BYOK agnostique au fournisseur vous permet de choisir le modèle de raisonnement adapté au travail : xAI Grok par défaut, ou les modèles OpenAI et Anthropic quand vous souhaitez leurs atouts — sans enfermement dans l'esthétique d'un seul fournisseur."}, {"label": "Conventions dans skills", "body": "Les Skills (plus un serveur MCP comme Figma) orientent l'agent vers vos tokens, composants et spécifications réelles, pour qu'il travaille sur une marque plutôt qu'un style par défaut."}]}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Hermes n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Hermes pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine propre jusqu'à un Hermes capable de construire et vérifier l'interface utilisateur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Hermes (one-line installer from Nous Research)\ncurl -fsSL https://hermes-agent.nousresearch.com/install.sh | bash\n\n# 2. Run the setup wizard\nhermes setup\n\n# 3. Add a provider and authenticate (BYOK)\n#    default is xAI Grok; OpenAI / Anthropic also supported\nhermes auth add        # add a provider key or run its OAuth flow\nhermes model           # pick the provider and model (grok-4.3 by default)\n\n# 4. Wire a Figma MCP server (optional, for design handoff)\n#    configure it among Hermes' MCP / tool settings"}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, configurer un skill, ajouter un design system, vérifier", "caption": "La séquence de configuration : installation → ajout d'une clé fournisseur → capture des règles de design dans un skill → ajout d'un design system → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Capturez vos tokens, primitives et conventions dans un skill Hermes et pointez l'agent vers eux, pour que le résultat corresponde à une marque au lieu d'adopter par défaut un aspect générique."}, {"label": "Ajoutez une vérification par navigateur", "body": "Connectez un MCP Playwright ou navigateur pour que Hermes effectue le rendu dans un vrai navigateur et vérifie sa sortie sur tous les breakpoints au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Hermes consiste à transformer une image de référence en UI fonctionnelle et responsive et à itérer jusqu'à ce qu'elle corresponde — laissant l'agent autonome planifier la construction et comparer sa sortie à la référence."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et incluez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un modèle performant.", "Conservez votre système de design et vos conventions dans un skill, et indiquez à Hermes où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et faire effectuer le rendu par Hermes dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en demandant à Hermes de comparer son implémentation aux captures d'écran — pas seulement de confirmer que ça compile."]}, {"kind": "p", "text": "Dirigez Hermes vers vos références et donnez des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "hermes\n# in the prompt:\n> Use reference-desktop.png and reference-mobile.png in this folder.\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from my skill.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Hermes quand vous annulez), pour que chaque passe parte d'une base propre."}]}, {"id": "extend", "heading": "Skills, sous-agents et fournisseurs", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Hermes pratique pour un travail de design soutenu, et tous trois s'alignent parfaitement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes construit et réutilise des skills — une mémoire procédurale créée à partir de l'expérience. Elles constituent le lieu durable pour vos conventions de design, appliquées lors des exécutions ultérieures au lieu d'être réexpliquées à chaque fois."}, {"label": "Sous-agents et MCP", "body": "Il délègue le travail à des sous-agents isolés et prend en charge les serveurs MCP — le moyen portable d'intégrer du contexte de design et des outils externes, notamment un serveur Figma MCP, qui fonctionnent sur tous les agents, pas seulement Hermes."}, {"label": "Choix du fournisseur", "body": "Parce que Hermes est agnostique au fournisseur (xAI Grok par défaut, OpenAI et Anthropic via BYOK), vous pouvez faire correspondre le modèle à la tâche sans reconstruire votre workflow."}]}, {"kind": "p", "text": "Ce sont des capacités portables multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Hermes", "Agent autonome de planification-exécution-délégation ; BYOK agnostique au fournisseur (xAI Grok par défaut, OpenAI/Anthropic également) ; open-source et auto-hébergé", "Builds autonomes sans intervention sur le modèle de votre choix, maintenus en local"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; offre gratuite", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à Hermes ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Faites en sorte que Hermes effectue un rendu et une auto-vérification sur tous les breakpoints afin que les layouts ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles dans un skill", "body": "Placez des règles de style comme « pas de hero cards, maximum deux polices, hiérarchie brand-first » dans un skill que l'agent applique à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Hermes au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Hermes comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Hermes performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Les deux sont open-source et local-first, ce qui fait de cette association un choix naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Hermes comme agent.", "Authentifiez-vous avec votre propre clé de fournisseur (BYOK) — xAI Grok par défaut, ou OpenAI ou Anthropic — les identifiants restent sur votre machine et ne sont jamais relayés par nos serveurs.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Hermes, même clé — plus un véritable workflow de design open-source et portable autour de lui. Il est local-first et Apache-2.0, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Hermes peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies images de référence en contexte, Hermes produit une interface utilisateur responsive de qualité production, et en tant qu'agent autonome il peut effectuer le rendu et vérifier la sortie par rapport aux références de manière autonome. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Quels modèles et clés Hermes utilise-t-il ?", "text": "Hermes est agnostique de fournisseur et bring-your-own-key. Il utilise par défaut xAI Grok (par exemple grok-4.3) et prend également en charge OpenAI, Anthropic, OpenRouter et de nombreux autres fournisseurs — vous ajoutez une clé de fournisseur (ou lancez son flux OAuth) avec hermes auth add et choisissez un modèle avec hermes model. Open Design ne proxie jamais vos identifiants."}, {"name": "Qu'est-ce qui rend Hermes particulièrement adapté au design ?", "text": "Deux choses : il est véritablement autonome, donc il planifie, construit et vérifie l'UI plutôt que d'attendre des directives ligne par ligne ; et il est agnostique au fournisseur, vous pouvez donc utiliser le modèle de raisonnement auquel vous faites confiance. Les deux aident — mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Hermes ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de conception spécifiques et conscientes du codebase ; l'avantage de Hermes est son approche autonome plan-and-execute plus le choix du fournisseur — et vous pouvez même pointer Hermes vers une clé Anthropic. De nombreuses équipes utilisent les deux — Open Design vous permet de changer d'agents sans modifier votre workflow de conception."}, {"name": "Comment connecter Hermes à Figma ?", "text": "Ajoutez un serveur MCP Figma dans la configuration des outils d'Hermes. Hermes peut alors récupérer un vrai contexte design — composants, variables, données de mise en page — de sorte que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à Nous Research ?", "text": "Non. Hermes est un produit de Nous Research ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur de première partie. Hermes et Nous Research sont des marques de leur propriétaire respectif."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants de fournisseur sont utilisés directement par votre agent, jamais routés via les serveurs Open Design."}], "ctaTitle": "Concevez avec Hermes, la voie ouverte.", "ctaBody": "Apportez votre propre clé xAI, OpenAI ou Anthropic, conservez chaque fichier en local et profitez d'une bibliothèque de design organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Hermes dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'devin': {
        ...en['devin']!,
        title: "Devin for Terminal pour le design — Open Design",
        description: "Comment les gens utilisent Devin for Terminal — l'ingénieur logiciel IA autonome de Cognition en ligne de commande — pour le design UI et web, et comment Open Design le transforme en agent de design open-source et local-first avec une bibliothèque de skills et de design systems soigneusement sélectionnée.",
        breadcrumb: "Devin for Terminal",
        label: "Agent · Devin",
        heading: "Devin for Terminal pour le design.",
        lead: "Devin for Terminal est l'ingénieur logiciel IA autonome de Cognition, s'exécutant dans votre terminal. Il planifie et exécute des tâches multi-étapes de manière autonome et peut transférer une session à un agent cloud isolé — ce qui en fait une véritable solution pour livrer du travail front-end, une fois que vous lui fournissez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open-source : votre compte Devin, vos fichiers, local d'abord.",
        rich: {"heroCtaLead": "Open Design transforme Devin for Terminal en un agent de design local-first et open-source — votre compte Devin, vos fichiers, une bibliothèque de skill et de design-system soigneusement sélectionnée autour de celui-ci.", "heroCtaActions": [{"label": "Utiliser Devin dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Devin for Terminal est l'ingénieur logiciel IA autonome de Cognition, intégré à la ligne de commande locale. Deux aspects le rendent particulièrement intéressant pour le design : il est véritablement agentique, planifiant et exécutant une tâche multi-étapes de bout en bout plutôt que de simplement compléter des lignes ; et il peut transférer une session à un agent cloud isolé disposant de son propre ordinateur, permettant aux builds plus longs de continuer après la fermeture de votre ordinateur portable. Associé aux bonnes références, conventions et une boucle de vérification, il construit des interfaces utilisateur réelles et responsives. Voici un guide pratique et complet pour utiliser Devin for Terminal dans le travail d'interface utilisateur, de frontend et de design system, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Devin for Terminal, pourquoi un ingénieur logiciel autonome convient au travail de design, comment le configurer de zéro, la boucle capture d'écran vers interface, comment les règles de projet et les outils externes l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — un jumelage naturel pour tout agent capable de planifier et livrer du travail front-end."], "heroImage": {"src": "/agents/devin-design/devin-design-hero.webp", "alt": "Boucle de feedback design avec Devin for Terminal : un agent de terminal autonome lisant une image de référence, un navigateur affichant l'interface utilisateur et un espace de travail, avec une flèche de feedback bouclant en retour", "caption": "La boucle principale : Devin lit vos références dans le terminal, planifie et construit l'UI, la vérifie dans un vrai navigateur, et itère en se basant sur elles — déléguant les exécutions plus longues au cloud si nécessaire."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-devin", "label": "Ce qu'est réellement Devin for Terminal"}, {"id": "why-design", "label": "Pourquoi un ingénieur logiciel autonome convient au design"}, {"id": "setup", "label": "Configurer Devin pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "Règles de projet, outils et transfert cloud"}, {"id": "vs", "label": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Devin dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-devin", "heading": "Ce qu'est réellement Devin for Terminal", "blocks": [{"kind": "p", "text": "Devin for Terminal est la version en ligne de commande de Devin, l'ingénieur logiciel IA autonome de Cognition. Il fonctionne comme un agent de codage local avec accès à votre base de code, vos outils et votre environnement — lisant votre dépôt, modifiant des fichiers, exécutant des commandes shell, et planifiant et vérifiant le travail à partir d'une tâche en langage naturel plutôt que de simplement compléter des lignes. Cognition a développé une bibliothèque de rendu de terminal personnalisée en Rust pour maintenir l'interface rapide et réactive."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés se distinguent. Il est véritablement autonome, vous pouvez donc décrire un résultat et il exécute le chemin en plusieurs étapes pour y parvenir. Et quand une construction dépasse votre ordinateur portable, vous pouvez transmettre la session à un agent cloud qui s'exécute dans son propre environnement isolé et continue à travailler de manière asynchrone — vous pouvez donc revenir à une pull request terminée."}, {"kind": "steps", "items": [{"label": "Exécution autonome et agentique", "body": "Devin planifie et exécute une tâche multi-étapes de manière autonome — implémentant une fonctionnalité, construisant une interface utilisateur, l'exécutant et la testant — guidé par des prompts clairs avec des critères de complétion explicites."}, {"label": "Agent local, transfert cloud", "body": "Il s'exécute localement dans votre terminal et peut faire basculer une session vers un agent cloud isolé qui dispose de son propre ordinateur et poursuit le travail après que vous vous êtes éloigné."}, {"label": "Basé sur un compte, choix du modèle", "body": "Vous vous connectez avec un compte Devin (Cognition) ; Devin fonctionne sur des modèles de pointe — vous pouvez choisir parmi des options telles que le SWE-1.6 propre à Cognition et d'autres modèles de pointe."}]}, {"kind": "ul", "items": ["Fournisseur : Cognition", "Identifiant : compte Devin (Cognition) — connexion basée sur abonnement/compte, pas de clé personnelle", "Format : agent de terminal local avec transfert cloud isolé optionnel"]}]}, {"id": "why-design", "heading": "Pourquoi un ingénieur logiciel autonome convient au design", "blocks": [{"kind": "p", "text": "L'avantage de Devin pour le design vient de son fonctionnement — exécution autonome de bout en bout — mais, comme pour chaque agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Builds multi-étapes de bout en bout", "body": "Parce que Devin planifie et exécute des tâches entières, il peut créer la structure d'une page, connecter des composants, lancer un serveur de développement et tester le résultat en une seule fois au lieu de s'arrêter à un snippet."}, {"label": "Exécutions cloud sandboxées", "body": "Un travail front-end plus long — une page d'accueil complète, un flux multi-écrans — peut être transféré à un agent cloud en sandbox et continuer à construire, de sorte que l'itération ne soit pas bloquée par votre ordinateur portable."}, {"label": "Conventions dans les règles du projet", "body": "Dirigez l'agent vers vos tokens, composants et spécifications réelles via les règles et la documentation de votre projet, pour qu'il travaille avec une marque plutôt qu'un look par défaut."}]}, {"kind": "image", "src": "/agents/devin-design/devin-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Devin n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Devin pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine propre jusqu'à un Devin for Terminal capable de construire et vérifier l'interface utilisateur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Devin for Terminal\ncurl -fsSL https://cli.devin.ai/install.sh | bash\n\n# 2. Start it in your project and sign in on first run\ncd your-project\ndevin             # sign in with your Devin (Cognition) account\n\n# 3. Describe the task in natural language, with clear\n#    completion criteria, and let Devin plan and execute.\n\n# 4. When a build outgrows your laptop, hand the session\n#    off to a sandboxed cloud agent that keeps working."}, {"kind": "image", "src": "/agents/devin-design/devin-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, se connecter, encoder les règles de design, ajouter des références, vérifier dans un navigateur", "caption": "La séquence de configuration : installation → connexion → encodage de vos règles de design → fourniture de références → vérification dans un vrai navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Placez vos tokens, primitives et conventions là où l'agent les lit — dans les règles et la documentation de votre projet — pour que la sortie corresponde à une marque plutôt qu'un style générique par défaut."}, {"label": "Ajoutez une vérification par navigateur", "body": "Faites en sorte que Devin effectue un rendu dans un véritable navigateur et vérifie sa sortie sur tous les breakpoints, afin qu'il vérifie par rapport au design au lieu de simplement confirmer que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Devin consiste à transformer une image de référence en UI fonctionnelle et responsive et à itérer jusqu'à ce qu'elle corresponde — laissant l'agent autonome construire, exécuter et comparer sa sortie à la référence."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et incluez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Soyez précis dans le prompt et donnez des critères d'achèvement explicites ; des prompts vagues produisent une interface générique même avec un agent performant.", "Conservez votre système de design et vos conventions dans vos règles de projet, et indiquez à Devin où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et faire effectuer le rendu par Devin dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en demandant à Devin de comparer son implémentation aux références — pas seulement de confirmer que ça compile — et déléguez au cloud pour des passes plus longues."]}, {"kind": "p", "text": "Donnez à Devin les références et les contraintes concrètes, avec une définition claire de ce qui constitue la finalisation :"}, {"kind": "code", "lang": "bash", "code": "devin\n# in the prompt:\n> Implement the attached reference (desktop + mobile) in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints. Done = pixel-close on both\n  desktop and mobile with no console errors."}, {"kind": "p", "text": "Gardez les prompts concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Devin quand vous annulez), pour que chaque passe parte d'une base propre."}]}, {"id": "extend", "heading": "Règles de projet, outils et transfert cloud", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Devin for Terminal pratique pour un travail de design soutenu, et tous trois s'alignent parfaitement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Règles et contexte de projet", "body": "Conservez vos conventions de design, tokens et checklists de revue dans les règles et docs de votre projet, pour que l'agent les lise à chaque exécution et travaille selon votre marque."}, {"label": "Base de code, outils et environnement", "body": "Devin s'exécute comme un agent local avec accès à votre base de code, vos outils et votre environnement — il peut lancer un serveur de développement, exécuter le build et vérifier la sortie sans quitter le terminal."}, {"label": "Transfert cloud sandboxé", "body": "Déléguez une session à un agent cloud dans son propre sandbox pour exécuter des builds plus longs, des tests et la création de PR de manière asynchrone, puis revenez à une pull request terminée."}]}, {"kind": "p", "text": "Ce sont exactement le genre de capacités portables et adaptées aux agents qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Devin", "Ingénieur logiciel entièrement autonome ; planifie et exécute des builds multi-étapes et délègue à un agent cloud isolé", "Délégation de builds frontend de bout en bout qui continuent de s'exécuter après votre départ"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; open-source avec une offre gratuite", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à Devin ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Faites en sorte que Devin effectue un rendu et une auto-vérification sur tous les breakpoints afin que les layouts ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles dans le contexte du projet", "body": "Placez les règles de style « pas de hero cards, maximum deux typographies, hiérarchie brand-first » là où l'agent les lit à chaque exécution, avec des critères d'achèvement explicites."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Devin au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Devin for Terminal comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Devin performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Open Design est open-source et local-first, ce qui fait de cette association un choix naturel pour un agent que vous exécutez déjà dans votre terminal."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Devin for Terminal comme agent.", "Authentifiez-vous avec votre compte Devin (Cognition) — les identifiants sont utilisés directement par votre agent et ne sont jamais proxiés via nous.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Devin, même compte — plus un véritable workflow de design open-source et portable autour de lui. Open Design est local-first et Apache-2.0, donc rien concernant votre travail ou vos identifiants ne quitte votre machine via nous."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Devin for Terminal peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies images de référence en contexte, Devin produit une interface utilisateur responsive de qualité production, et en tant qu'agent autonome il peut construire, exécuter et vérifier le résultat par rapport à vos références. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Comment me connecter à Devin ?", "text": "Devin est basé sur un compte : vous vous connectez avec un compte Devin (Cognition) plutôt que d'apporter votre propre clé de modèle. Installez Devin for Terminal, exécutez-le dans votre projet et authentifiez-vous lors de la première exécution. Open Design ne proxie jamais vos identifiants — votre agent les utilise directement."}, {"name": "Qu'est-ce qui rend Devin particulièrement adapté au design ?", "text": "C'est un ingénieur logiciel totalement autonome : il planifie et exécute de bout en bout des développements front-end en plusieurs étapes, et peut transférer une session à un agent cloud isolé qui continue le travail après que vous vous êtes éloigné. Le goût provient toujours du système de design, du skill et des références que vous fournissez."}, {"name": "Devin ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de conception spécifiques et conscientes du codebase ; l'avantage de Devin est son exécution autonome de bout en bout avec un transfert cloud sandboxé. De nombreuses équipes utilisent les deux — Open Design vous permet de changer d'agents sans modifier votre workflow de conception."}, {"name": "Est-ce que Devin s'exécute dans un bac à sable ?", "text": "Devin for Terminal s'exécute localement avec accès à votre base de code et votre environnement, et il peut transférer une session à un agent cloud qui s'exécute dans son propre environnement isolé — utile pour des builds plus longs, des tests et la création de PR qui continuent de manière asynchrone."}, {"name": "Open Design est-il affilié à Cognition ?", "text": "Non. Devin for Terminal est un produit de Cognition ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur de première partie. Devin est une marque de Cognition."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Devin sont utilisés directement par votre agent, jamais routés via les serveurs Open Design."}], "ctaTitle": "Concevoir avec Devin, à la manière open.", "ctaBody": "Connectez-vous avec votre compte Devin, conservez tous les fichiers en local et bénéficiez d'une bibliothèque de design organisée autour de l'agent autonome que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Devin dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'pi': {
        ...en['pi']!,
        title: "Pi pour le design — Open Design",
        description: "Comment les gens utilisent Pi, l'agent de codage terminal open-source et multi-provider, pour le design UI et web — son routage any-model, ses clés provider BYOK, ses Skills et Extensions — et comment Open Design transforme Pi en agent de design open-source et local-first.",
        breadcrumb: "Pi",
        label: "Agent · Pi",
        heading: "Pi pour le design.",
        lead: "Pi est un agent de codage pour terminal open-source qui se connecte à n'importe quel modèle — Anthropic, OpenAI, Google et plus de 20 fournisseurs — avec vos propres clés API. Ce cœur agnostique du fournisseur en fait un outil de design flexible : choisissez le modèle qui lit le mieux les captures d'écran aujourd'hui, changez demain, gardez votre workflow. Open Design l'intègre dans un workflow de design open-source : vos clés de fournisseur, vos fichiers, local d'abord.",
        rich: {"heroCtaLead": "Open Design transforme Pi en un agent de design local-first et open-source — vos propres clés API de fournisseurs, vos fichiers, une bibliothèque de skill et de design-system soigneusement sélectionnée autour de celui-ci.", "heroCtaActions": [{"label": "Utiliser Pi dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Pi est un agent de codage IA open-source (MIT) pour le terminal. Ce qui le rend intéressant pour le design en particulier, c'est qu'il est agnostique du fournisseur : il normalise entre Anthropic, OpenAI, Google et plus de 20 autres fournisseurs derrière une seule interface, vous vous authentifiez donc avec vos propres clés API (BYOK) et choisissez le modèle qui convient à la tâche — et vous pouvez changer de modèle en cours de session sans réapprendre l'outil. Associé aux bonnes références, conventions et à une boucle de vérification, il construit une UI réelle et responsive. Il s'agit d'un guide pratique de bout en bout pour utiliser Pi pour l'UI, le frontend et le travail sur les design systems, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Pi, pourquoi un agent BYOK multi-fournisseurs convient au design, comment le configurer de zéro, la boucle capture d'écran vers interface, comment les Skills et Extensions l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — un jumelage naturel, puisque les deux sont open-source et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/pi-design/pi-design-hero.webp", "alt": "Boucle de retour de design Pi : un agent terminal lisant une image de référence, un navigateur affichant l'interface utilisateur, et un espace de travail, avec une flèche de retour bouclant en arrière", "caption": "La boucle principale : Pi lit vos références dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère en se basant sur elles — avec le fournisseur que vous lui indiquez."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-pi", "label": "Ce qu'est réellement Pi"}, {"id": "why-design", "label": "Pourquoi un agent multi-fournisseurs BYOK convient au design"}, {"id": "setup", "label": "Configurer Pi pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "Skills, Extensions et thèmes"}, {"id": "vs", "label": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Pi dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-pi", "heading": "Ce qu'est réellement Pi", "blocks": [{"kind": "p", "text": "Pi est un agent de codage IA open-source (MIT) pour le terminal, qui fait partie de la boîte à outils earendil-works pi. Il lit votre dépôt, modifie les fichiers et exécute des commandes shell — planifiant et vérifiant le travail à partir de tâches en langage naturel plutôt que de simplement compléter des lignes. Son cœur est délibérément petit : quatre outils par défaut — read, write, edit et bash — plus grep, find et ls intégrés."}, {"kind": "p", "text": "Pour le travail de design, la propriété remarquable est que Pi est agnostique du fournisseur. Il normalise Anthropic, OpenAI, Google et de nombreux autres fournisseurs derrière une API unifiée, vous apportez donc vos propres clés et choisissez le modèle par tâche — par exemple un modèle multimodal puissant pour lire des captures d'écran de référence — et changez avec /model ou Ctrl+L en cours de session sans modifier votre workflow."}, {"kind": "steps", "items": [{"label": "N'importe quel modèle, vos clés", "body": "Pi se connecte à plus de 20 fournisseurs dont Anthropic et OpenAI. Vous vous authentifiez avec vos propres clés API (BYOK), ou vous connectez à un abonnement Claude Pro/Max, ChatGPT Plus/Pro ou GitHub Copilot avec /login."}, {"label": "Skills + Extensions", "body": "Pi charge des Skills (packages de capacités Markdown suivant le standard Agent Skills) et des Extensions TypeScript — l'endroit naturel pour encoder vos conventions de design et ajouter des outils personnalisés."}, {"label": "Sessions avec branches", "body": "Les sessions sont stockées sous forme d'arbres JSONL, vous pouvez donc créer des branches d'exploration et naviguer dans l'historique au sein d'un seul fichier sans perdre les itérations antérieures."}]}, {"kind": "ul", "items": ["Éditeur : earendil-works (projet communautaire open-source)", "Identifiant : votre propre clé API de fournisseur (BYOK — Anthropic, OpenAI, Google, etc.) ou une connexion par abonnement via /login ; stocké localement dans ~/.pi/agent/auth.json (0600)", "Licence : MIT, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent multi-fournisseurs BYOK convient au design", "blocks": [{"kind": "p", "text": "L'avantage design de Pi est la flexibilité, pas un seul modèle intégré — mais, comme pour tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Choisir le bon modèle par tâche", "body": "Parce que Pi route vers n'importe quel fournisseur, vous pouvez recourir à un modèle multimodal performant pour lire des captures d'écran de référence, puis basculer vers un autre pour le refactoring — sans quitter l'agent."}, {"label": "Vos clés, aucun verrouillage", "body": "BYOK signifie que vous n'êtes pas lié à la tarification ou aux limites de contexte d'un seul fournisseur ; choisissez le modèle dont les forces correspondent au travail de design qui vous attend."}, {"label": "Conventions dans Skills", "body": "Un Skill (plus une source MCP comme un serveur Figma) oriente l'agent vers vos tokens, composants et spécifications réelles, de sorte qu'il travaille sur une marque plutôt qu'un style par défaut."}]}, {"kind": "image", "src": "/agents/pi-design/pi-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Pi n'a pas de goût par défaut, et aucun choix de modèle ne le fournit. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Pi pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine vierge jusqu'à un Pi capable de construire et vérifier une UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Pi coding agent CLI (Node)\nnpm install -g --ignore-scripts @earendil-works/pi-coding-agent\n\n# 2. Authenticate with your own provider key (BYOK)\nexport ANTHROPIC_API_KEY=sk-ant-...   # or OPENAI_API_KEY=sk-...\n#    (or run /login inside Pi for a Claude / ChatGPT / Copilot subscription)\n\n# 3. Start it in your project\ncd your-project\npi\n\n# 4. Switch models any time with /model or Ctrl+L"}, {"kind": "image", "src": "/agents/pi-design/pi-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, encoder les règles de design, ajouter un skill, vérifier", "caption": "La séquence de configuration : installation → authentification (BYOK) → encodage des règles de design dans un Skill → choix d'un modèle → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Placez vos tokens, primitives et conventions dans un Skill et orientez Pi vers eux, pour que la sortie corresponde à une marque plutôt qu'un style générique par défaut."}, {"label": "Ajoutez une vérification par navigateur", "body": "Connectez un MCP Playwright ou navigateur pour que Pi effectue le rendu dans un vrai navigateur et vérifie sa sortie sur tous les breakpoints au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Pi consiste à transformer une image de référence en interface utilisateur fonctionnelle et responsive, puis à itérer jusqu'à ce qu'elle corresponde — en s'appuyant sur un modèle multimodal pour comparer le résultat à la référence. Comme Pi est agnostique au fournisseur, orientez-le vers le modèle qui lit le mieux les images pour cette passe."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et incluez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Choisissez un modèle multimodal puissant pour la passe avec /model, car la compréhension d'image est ce qui détermine la qualité de la conversion capture d'écran vers UI.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un modèle performant.", "Conservez votre système de design et vos conventions dans un Skill, et indiquez à Pi où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et faire effectuer le rendu par Pi dans un vrai navigateur, en redimensionnant aux points de rupture, puis itérer en comparant son implémentation aux captures d'écran — pas simplement confirmer que ça compile."]}, {"kind": "p", "text": "Donnez à l'agent les références et les contraintes concrètes dès le départ :"}, {"kind": "code", "lang": "bash", "code": "pi\n# in the prompt:\n> Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see the Skill).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Pi quand vous annulez), pour que chaque passe parte d'une base propre. Les sessions JSONL branchées de Pi vous permettent aussi d'explorer une alternative sans perdre le fil d'origine."}]}, {"id": "extend", "heading": "Skills, Extensions et thèmes", "blocks": [{"kind": "p", "text": "Pi s'étend automatiquement au runtime à travers quelques couches, et elles correspondent clairement à un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Packages de capacités Markdown suivant le standard Agent Skills — le foyer durable et portable pour vos conventions de design, tokens et listes de vérification. Le même Skill fonctionne avec tous les agents compatibles, pas seulement Pi."}, {"label": "Extensions et modèles de prompts", "body": "Les extensions TypeScript ajoutent des outils personnalisés, des commandes et de l'UI ; les templates de prompts réutilisables s'exécutent via /name. Les deux permettent de scripter la boucle de vérification sans quitter le terminal."}, {"label": "MCP et thèmes", "body": "Pi se connecte aux serveurs MCP pour intégrer du contexte de design externe (plus particulièrement un serveur MCP Figma), et les thèmes se rechargent à chaud pour que l'interface du terminal reste lisible pendant que vous travaillez."}]}, {"kind": "p", "text": "Ce sont des capacités portables — Skills et MCP en particulier — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Pi", "Agnostique au fournisseur et BYOK — routage vers n'importe quel modèle (Anthropic, OpenAI, Google…) et changement en cours de session ; MIT, auto-extensible", "Choisir le meilleur modèle par tâche sans verrouillage fournisseur"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; offre gratuite", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "L'approche de Pi est orthogonale aux autres : c'est l'agent qui vous permet d'utiliser n'importe lequel de ces modèles sous-jacents avec vos propres clés. Le verdict récurrent de la communauté tient toujours — le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre, et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à Pi ou à un modèle particulier ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut — et comme c'est un Skill portable, il vous suit d'un modèle à l'autre."}, {"label": "Vérifier dans un véritable navigateur", "body": "Choisissez un modèle multimodal et faites en sorte que Pi rende et vérifie lui-même sur tous les breakpoints pour que les mises en page ne cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles là où Pi les lit", "body": "Placez des règles de style comme « pas de hero cards, maximum deux polices, hiérarchie brand-first » dans un Skill que l'agent charge à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné — indépendamment du fournisseur vers lequel vous vous dirigez. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Pi au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Pi comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Pi performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Les deux sont open-source et local-first, ce qui fait de cette association un choix naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Pi comme agent.", "Authentifiez-vous avec votre propre clé API de fournisseur (BYOK) ou une connexion par abonnement — les identifiants restent sur votre machine dans ~/.pi/agent/auth.json et ne sont jamais relayés par nos serveurs.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Pi, mêmes clés, même liberté de changer de modèles — plus un véritable workflow de design open-source et portable autour de lui. Il est local-first et MIT, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Pi peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies images de référence en contexte, Pi produit une interface utilisateur responsive de qualité production, et vous pouvez le router vers un modèle multimodal puissant pour vérifier la sortie par rapport aux références. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Dois-je payer pour concevoir avec Pi ?", "text": "Pi lui-même est gratuit et open source (MIT). Vous ne payez que pour le modèle sous-jacent — apportez votre propre clé API de fournisseur (BYOK), ou utilisez un abonnement Claude Pro/Max, ChatGPT Plus/Pro ou GitHub Copilot via /login. Open Design ne proxie jamais vos identifiants non plus."}, {"name": "Qu'est-ce qui rend Pi particulièrement adapté au design ?", "text": "Il est agnostique de fournisseur : vous apportez vos propres clés et routez vers l'un des 20+ fournisseurs, en choisissant le modèle dont les forces correspondent à la tâche et en changeant en cours de session. Mais le goût provient toujours du système de design, du skill et des références que vous fournissez, pas du modèle."}, {"name": "Quel modèle dois-je utiliser avec Pi pour le design frontend ?", "text": "Pi se connecte à de nombreux fournisseurs, alors choisissez selon la tâche — un modèle multimodal puissant lit bien les captures d'écran de référence, tandis que d'autres peuvent convenir à la refactorisation. L'avantage de Pi est que vous pouvez changer sans modifier votre workflow. Open Design vous permet de conserver le même contexte de design quel que soit le modèle que vous choisissez."}, {"name": "Comment connecter Pi à Figma ?", "text": "Pi prend en charge les serveurs MCP, vous pouvez donc ajouter un serveur MCP Figma et extraire le contexte de design réel — composants, variables, données de mise en page — pour que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à Pi ?", "text": "Non. Pi est un projet open-source indépendant d'earendil-works ; Open Design est un projet open-source indépendant distinct qui prend en charge Pi en tant qu'adaptateur first-party."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et open source. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et vos clés de fournisseur sont utilisées directement par Pi (stockées localement dans ~/.pi/agent/auth.json), jamais routées via les serveurs Open Design."}], "ctaTitle": "Concevez avec Pi, la voie ouverte.", "ctaBody": "Apportez vos propres clés de fournisseur, routez vers n'importe quel modèle, conservez tous les fichiers en local et obtenez une bibliothèque de conception organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Pi dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'kiro': {
        ...en['kiro']!,
        title: "Kiro CLI pour le design — Open Design",
        description: "Comment les gens utilisent le Kiro CLI d'Amazon pour le design UI et web — son développement piloté par specs, ses hooks d'agent, ses fichiers de pilotage et MCP — et comment Open Design transforme Kiro CLI en agent de design open-source et local-first.",
        breadcrumb: "Kiro CLI",
        label: "Agent · Kiro CLI",
        heading: "Kiro CLI pour le design.",
        lead: "Kiro CLI est l'agent terminal d'Amazon pour le développement piloté par spécifications — il transforme un prompt en spec d'exigences, un document de design et une liste de tâches avant d'écrire du code. Cette structure est exactement ce dont le travail de design a besoin : l'intention d'abord, puis la construction. Open Design l'intègre dans un workflow de design open source : votre Builder ID ou connexion, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Kiro CLI en un agent de design local-first et open-source — votre AWS Builder ID ou connexion, vos fichiers, une bibliothèque de skill et de design-system soigneusement sélectionnée autour de celui-ci.", "heroCtaActions": [{"label": "Utiliser Kiro CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kiro CLI est l'agent terminal d'Amazon pour le développement piloté par spécifications. Ce qui le distingue, c'est le workflow : au lieu de passer directement d'un prompt au code, Kiro formalise les exigences dans une spec, produit un document de design et une liste de tâches séquencées, puis seulement implémente — maintenant la construction responsable de l'intention déclarée. Il inclut également des hooks d'agent qui se déclenchent sur des événements comme la sauvegarde d'un fichier, des fichiers de pilotage qui portent vos standards et conventions dans chaque exécution, et la prise en charge du Model Context Protocol pour les outils externes. Kiro est en preview, disponible sous forme d'IDE, de CLI et d'interface web, et vous pouvez commencer gratuitement. Ceci est un guide pratique de bout en bout pour utiliser Kiro CLI pour l'UI, le frontend et le travail sur les design systems, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Kiro CLI, pourquoi un workflow piloté par spécification convient au design, comment le configurer de zéro, la boucle capture d'écran vers interface, comment le pilotage, les hooks et MCP l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first autour de celui-ci."], "heroImage": {"src": "/agents/kiro-design/kiro-design-hero.webp", "alt": "Boucle de feedback de design Kiro CLI : un agent terminal transformant une spec en design, un navigateur rendant l'UI et un espace de travail, avec une flèche de feedback bouclant en retour", "caption": "La boucle principale : Kiro CLI transforme votre intention en spécification et liste de tâches dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère en se basant sur vos références."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-kiro", "label": "Ce qu'est réellement Kiro CLI"}, {"id": "why-design", "label": "Pourquoi le développement piloté par spécification convient au design"}, {"id": "setup", "label": "Configurer Kiro CLI pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "Spécifications, pilotage, hooks et MCP"}, {"id": "vs", "label": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Kiro CLI dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kiro", "heading": "Ce qu'est réellement Kiro CLI", "blocks": [{"kind": "p", "text": "Kiro est une IA agentique d'Amazon qui se présente sous forme d'IDE, d'interface en ligne de commande et d'interface web, conçue pour vous faire passer du prototype à la production avec un développement piloté par spécifications. Le Kiro CLI apporte cet agent à votre terminal : vous pouvez démarrer une session de chat interactive, créer et gérer des agents, et exécuter des serveurs Model Context Protocol — tout depuis la ligne de commande. Kiro est en preview."}, {"kind": "p", "text": "Pour le travail de design, la propriété déterminante est le workflow. Plutôt que de transformer directement un prompt en code, Kiro écrit d'abord une spécification — exigences, document de design et liste de tâches séquencées — et implémente en s'y référant. Cela rend le plan de l'agent visible et vérifiable avant qu'aucune UI ne soit construite, ce qui correspond parfaitement à la façon dont les décisions de design doivent être prises : l'intention d'abord, puis l'exécution."}, {"kind": "steps", "items": [{"label": "Spécifications", "body": "Kiro transforme un prompt en spec structurée — exigences, document de design et tâches discrètes — avant d'écrire du code, de sorte que le plan soit révisable en amont."}, {"label": "Pilotage + hooks", "body": "Les fichiers de pilotage portent vos standards, conventions et outils préférés dans chaque exécution ; les hooks d'agent se déclenchent sur des événements comme une sauvegarde de fichier pour exécuter des tâches en arrière-plan automatiquement."}, {"label": "Gratuit pour commencer, compatible MCP", "body": "Connectez-vous avec un Builder ID, Google, GitHub ou votre organisation et commencez gratuitement ; Kiro CLI gère également les serveurs MCP pour intégrer du contexte externe."}]}, {"kind": "ul", "items": ["Fournisseur : Amazon (AWS)", "Identifiant : AWS Builder ID, Google, GitHub ou AWS IAM Identity Center via kiro-cli login (aucun compte AWS requis)", "Statut : En prévisualisation ; disponible en IDE, CLI et interface web"]}]}, {"id": "why-design", "heading": "Pourquoi le développement piloté par spécification convient au design", "blocks": [{"kind": "p", "text": "L'avantage de design de Kiro CLI vient de son workflow — mais, comme avec tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "L'intention avant les pixels", "body": "Parce que Kiro rédige d'abord une spécification et un document de design, vous pouvez corriger la mise en page, la hiérarchie et le périmètre à l'étape de planification — avant que l'agent ne se soit engagé dans une implémentation générique."}, {"label": "Le pilotage porte votre marque", "body": "Les fichiers de pilotage maintiennent vos tokens, composants et conventions devant l'agent à chaque exécution, afin que le résultat s'aligne sur une marque au lieu d'un look par défaut."}, {"label": "Les hooks font respecter la boucle", "body": "Les hooks d'agent peuvent exécuter des vérifications automatiquement à la sauvegarde — un endroit où brancher une étape de vérification ou de revue plutôt que de compter sur l'agent pour s'en souvenir."}]}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Kiro CLI n'a pas de goût par défaut. Une spécification maintient la construction sur la bonne voie, mais elle ne produit un bon design que lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Kiro CLI pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine propre jusqu'à un Kiro CLI capable de construire et vérifier l'interface utilisateur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kiro CLI (see kiro.dev/docs/cli for the macOS/Linux/Windows command)\n\n# 2. Authenticate — opens your browser to complete sign-in\nkiro-cli login   # choose Builder ID, Google, GitHub, or your organization\n\n# 3. Confirm you are signed in\nkiro-cli whoami\n\n# 4. Start an interactive session in your project\ncd your-project\nkiro-cli chat\n\n# 5. Wire MCP servers (optional, e.g. for design handoff)\nkiro-cli mcp add ..."}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, ajouter le pilotage, ajouter un skill, vérifier", "caption": "La séquence de configuration : installation → authentification → ajout du pilotage et d'une spec design → ajout d'un skill → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Placez vos tokens, primitives et conventions dans des fichiers de pilotage pour que l'agent les lise à chaque exécution, et que la sortie corresponde à une marque plutôt qu'un style générique par défaut."}, {"label": "Ajoutez une vérification par navigateur", "body": "Connectez un serveur MCP Playwright ou navigateur pour que Kiro effectue le rendu dans un vrai navigateur et vérifie sa sortie sur tous les breakpoints au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Kiro CLI consiste à transformer une image de référence en interface utilisateur fonctionnelle et responsive, puis à itérer jusqu'à ce qu'elle corresponde — en laissant d'abord la spécification capturer l'intention, puis en construisant par rapport à elle."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et incluez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Laissez Kiro écrire une spec et un document de design à partir de votre prompt, et révisez le plan avant qu'il ne construise — c'est là que vous détectez les problèmes de mise en page et de périmètre tôt.", "Conservez votre système de design et vos conventions dans des fichiers de pilotage, et indiquez à Kiro où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et faire effectuer le rendu par Kiro dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en demandant à Kiro de comparer son implémentation aux références — pas seulement de confirmer que ça compile."]}, {"kind": "p", "text": "Ouvrez une session interactive et donnez des contraintes concrètes dès le départ, afin que la spécification qu'il rédige reflète votre intention réelle :"}, {"kind": "code", "lang": "bash", "code": "kiro-cli chat\n# in the prompt:\n> Here are my references: reference-desktop.png and reference-mobile.png.\n  Write a spec, then implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see my steering files).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Gardez les tâches courtes et concentrées, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Kiro quand vous annulez), pour que chaque passe parte d'une base propre."}]}, {"id": "extend", "heading": "Spécifications, pilotage, hooks et MCP", "blocks": [{"kind": "p", "text": "Quatre points d'extension rendent Kiro CLI pratique pour un travail de design soutenu, et les quatre correspondent clairement à un flux de travail de design ouvert."}, {"kind": "steps", "items": [{"label": "Spécifications", "body": "Exigences, document de conception et liste de tâches séquencées — l'enregistrement durable de ce qu'une fonctionnalité doit être, révisable avant et pendant le développement."}, {"label": "Fichiers de pilotage", "body": "Ajoutez du contexte, des normes de code et des workflows ou outils préférés que l'agent lit à chaque exécution — le lieu naturel pour vos conventions design et vos tokens."}, {"label": "Hooks d'agent", "body": "Des automatisations qui se déclenchent sur des événements tels qu'une sauvegarde de fichier, exécutant des tâches en arrière-plan comme des vérifications ou de la documentation — un endroit pour imposer automatiquement une étape de vérification."}, {"label": "Serveurs MCP", "body": "Kiro CLI gère les serveurs Model Context Protocol, la manière portable d'intégrer du contexte et des outils de design externes qui fonctionnent avec tous les agents, pas seulement Kiro."}]}, {"kind": "p", "text": "Ce sont des capacités portables multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Kiro CLI", "Workflow piloté par spécifications — exigences, doc de design et liste de tâches avant le code ; les fichiers de pilotage et les hooks maintiennent les builds conformes à la marque", "Builds structurés et révisables où l'intention et le périmètre sont verrouillés avant l'implémentation"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un très large contexte ; open-source avec une offre gratuite", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à Kiro CLI ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé — une spécification maintient la construction sur la bonne voie, mais elle ne fournit pas le goût."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Effectuer le rendu et vérifier automatiquement sur tous les points de rupture — intégrez-le comme un hook si possible — afin que les mises en page ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles dans des fichiers de pilotage", "body": "Placez les règles de style « pas de hero cards, maximum deux typographies, hiérarchie brand-first » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Kiro CLI au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Kiro CLI comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Kiro performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Open Design est local-first, ce qui simplifie cette association : vos fichiers et votre connexion restent sur votre machine."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Kiro CLI comme agent.", "Authentifiez-vous avec votre Builder ID AWS ou autre connexion — les identifiants restent sur votre machine et ne sont jamais proxiés via nous.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent CLI Kiro, même connexion — plus un véritable workflow de design open-source et portable autour de lui. Open Design est local-first et Apache-2.0, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Kiro CLI peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies images de référence en contexte, Kiro CLI produit une interface utilisateur responsive de qualité production, et son workflow piloté par spécifications maintient la construction conforme à l'intention déclarée. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Ai-je besoin d'un compte AWS pour utiliser Kiro CLI ?", "text": "Non — Kiro vous permet de vous connecter avec un AWS Builder ID, Google, GitHub ou votre organisation (AWS IAM Identity Center), et vous n'avez pas besoin d'un compte AWS pour l'utiliser. Kiro est en prévisualisation et gratuit pour commencer. Open Design ne fait jamais transiter vos identifiants non plus."}, {"name": "Qu'est-ce qui rend Kiro CLI particulièrement adapté au design ?", "text": "Son workflow piloté par spécifications : Kiro rédige des exigences, un document de conception et une liste de tâches avant de coder, pour que vous corrigiez la mise en page et le périmètre avant que le build ne s'engage. Les fichiers de pilotage portent vos conventions et les hooks peuvent appliquer des vérifications — mais le goût vient toujours du design system, du skill et des références que vous fournissez."}, {"name": "Kiro CLI ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de conception spécifiques et conscientes du codebase ; l'avantage de Kiro CLI est son workflow spec-driven et vérifiable avec pilotage et hooks. De nombreuses équipes utilisent les deux — Open Design vous permet de changer d'agents sans modifier votre workflow de conception."}, {"name": "Comment connecter Kiro CLI à des outils de design externes ?", "text": "Kiro CLI gère les serveurs Model Context Protocol (MCP) — utilisez kiro-cli mcp pour les ajouter. Un serveur MCP peut apporter du contexte et des outils de design réels dans l'agent afin que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à Amazon ou AWS ?", "text": "Non. Kiro est un produit d'Amazon (AWS) ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur first-party. Kiro est une marque déposée d'Amazon."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et votre connexion Kiro est utilisée directement par votre agent, jamais routée via les serveurs Open Design."}], "ctaTitle": "Concevez avec Kiro CLI, la voie ouverte.", "ctaBody": "Apportez votre propre AWS Builder ID ou connexion, conservez tous les fichiers en local et obtenez une bibliothèque de conception organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Kiro CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'kilo': {
        ...en['kilo']!,
        title: "Kilo Code pour le design — Open Design",
        description: "Comment les gens utilisent Kilo Code — l'agent de codage IA open-source et model-agnostic — pour le design UI et web : ses modes Architect/Code, sa prise en charge MCP, BYOK sur de nombreux fournisseurs, et comment Open Design transforme Kilo en agent de design open-source et local-first.",
        breadcrumb: "Kilo",
        label: "Agent · Kilo",
        heading: "Kilo Code pour le design.",
        lead: "Kilo Code est un agent de codage IA open-source et agnostique au modèle pour votre IDE et CLI. Parce que vous pouvez le pointer vers presque n'importe quel modèle et apporter vos propres clés de fournisseur, il devient un véritable outil de design une fois que vous lui donnez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open-source : vos clés de fournisseur, vos fichiers, local d'abord.",
        rich: {"heroCtaLead": "Open Design transforme Kilo Code en un agent de design local-first et open-source — vos clés de fournisseurs, vos fichiers, une bibliothèque de skill et de design-system soigneusement sélectionnée autour de celui-ci.", "heroCtaActions": [{"label": "Utiliser Kilo Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kilo Code est un agent de codage IA open-source qui s'exécute dans VS Code, les IDE JetBrains et le terminal. Deux aspects le rendent particulièrement intéressant pour le design : il est agnostique au modèle, vous pouvez donc le piloter avec le modèle de pointe capable de vision qui lit le mieux une capture d'écran ; et il est BYOK sur de nombreux fournisseurs, vous gardez donc le contrôle des coûts et des identifiants. Associé aux bonnes références, conventions et une boucle de vérification, il construit des interfaces réelles et responsives. Voici un guide pratique et complet sur l'utilisation de Kilo Code pour le travail d'interface, de frontend et de système de design, et sur son intégration dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Kilo Code, pourquoi un agent ouvert et agnostique de modèle convient au design, comment le configurer de zéro, la boucle capture d'écran vers interface, comment les règles personnalisées et MCP l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — un jumelage naturel, puisque les deux sont open-source et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/kilo-design/kilo-design-hero.webp", "alt": "Boucle de feedback design Kilo Code : un agent dans l'IDE et le terminal lisant une image de référence, un navigateur affichant l'interface, et un espace de travail, avec une flèche de feedback bouclant en retour", "caption": "La boucle principale : Kilo Code lit vos références dans l'IDE ou le CLI, construit et vérifie l'UI dans un vrai navigateur, et itère en se basant sur elles — avec le modèle que vous choisissez."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-kilo", "label": "Ce qu'est réellement Kilo Code"}, {"id": "why-design", "label": "Pourquoi un agent ouvert et agnostique convient au design"}, {"id": "setup", "label": "Configurer Kilo Code pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow capture d'écran-vers-UI"}, {"id": "extend", "label": "Modes, règles personnalisées et MCP"}, {"id": "vs", "label": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Kilo Code dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kilo", "heading": "Ce qu'est réellement Kilo Code", "blocks": [{"kind": "p", "text": "Kilo Code est un agent de codage IA open-source développé par Kilo Code, Inc. Il s'exécute comme une extension VS Code, dans les IDE JetBrains, et en tant qu'interface en ligne de commande — lisant votre dépôt, éditant des fichiers, exécutant des commandes, et planifiant et vérifiant le travail à partir de tâches en langage naturel plutôt que de simplement compléter des lignes. Sa caractéristique distinctive est qu'il est agnostique au modèle : vous choisissez quel modèle le pilote, et vous apportez vos propres clés de fournisseur."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés se distinguent. Parce qu'il est agnostique du modèle, vous pouvez le pointer vers n'importe quel modèle puissant capable de vision qui lit le mieux une capture d'écran de référence et raisonne sur la mise en page. Et parce qu'il est open-source et BYOK, vous pouvez inspecter exactement quel contexte est envoyé et garder les identifiants et les coûts sous votre propre contrôle."}, {"kind": "steps", "items": [{"label": "Modes d'agent", "body": "Kilo propose des modes spécialisés — Architect pour la planification, Code pour la construction, Debug pour la correction et Ask pour les questions — ainsi que des modes personnalisés, afin que vous puissiez planifier un design puis l'implémenter en passes séparées et ciblées."}, {"label": "Règles personnalisées + MCP", "body": "Il lit des règles personnalisées au niveau du projet pour un contexte persistant et prend en charge les serveurs MCP (avec une marketplace MCP), vous pouvez donc ajouter un contexte externe comme un fichier Figma actif ou un outillage de design."}, {"label": "Apportez vos propres clés", "body": "Kilo est BYOK sur de nombreux fournisseurs — Anthropic, OpenAI, Google, OpenRouter, et plus — ou vous pouvez utiliser la passerelle propre de Kilo, qui expose plus de 500 modèles au coût du fournisseur."}]}, {"kind": "ul", "items": ["Éditeur : Kilo Code, Inc. (open source)", "Identifiant : votre propre clé API de fournisseur (BYOK — Anthropic, OpenAI, Google, OpenRouter, et plus) ou la passerelle propre de Kilo", "Licence : open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent ouvert et agnostique convient au design", "blocks": [{"kind": "p", "text": "L'avantage design de Kilo Code vient de son ouverture et du choix du modèle — mais, comme pour tout agent, le goût doit toujours être fourni."}, {"kind": "steps", "items": [{"label": "Agnostique vis-à-vis des modèles par conception", "body": "Parce que vous choisissez le modèle, vous pouvez piloter Kilo avec le modèle capable de vision qui lit le mieux les captures d'écran de référence — et changer quand un meilleur apparaît, sans modifier votre workflow."}, {"label": "Ouvert et inspectable", "body": "Kilo est open-source, vous pouvez donc voir exactement quel contexte et quels prompts sont envoyés — utile lorsque vous voulez que l'agent réutilise vos véritables primitives de design plutôt que d'inventer des styles ponctuels."}, {"label": "Conventions dans les règles personnalisées", "body": "Les règles personnalisées de projet (plus un serveur MCP pour Figma) orientent l'agent vers vos tokens, composants et spécifications réelles, pour qu'il travaille selon une marque plutôt qu'un style par défaut."}]}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Kilo Code n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Kilo Code pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine propre jusqu'à un Kilo Code capable de construire et vérifier l'interface utilisateur."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Kilo Code extension from the VS Code\n#    (or JetBrains) marketplace, or install the CLI.\n\n# 2. Open your project and sign in / add a provider key\ncd your-project\nkilo              # connect your provider (BYOK) or Kilo's gateway\n\n# 3. Add project context\n#    create custom rules for this project's design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it from the MCP marketplace / MCP settings"}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, ajouter des règles personnalisées, ajouter un skill, vérifier", "caption": "La séquence de configuration : installation → connexion d'un fournisseur → ajout de règles personnalisées → ajout d'un skill → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Placez vos tokens, primitives et conventions dans les règles personnalisées de Kilo et orientez l'agent vers elles, pour que la sortie corresponde à une marque plutôt qu'un style générique par défaut."}, {"label": "Ajoutez une vérification par navigateur", "body": "Connectez un MCP Playwright ou navigateur pour que Kilo effectue le rendu dans un vrai navigateur et vérifie sa sortie sur tous les breakpoints au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow capture d'écran-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Kilo Code consiste à transformer une image de référence en UI fonctionnelle et responsive et à itérer jusqu'à ce qu'elle corresponde — en s'appuyant sur un modèle capable de vision pour comparer la sortie à la référence."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et incluez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un modèle performant.", "Conservez votre design system et vos conventions dans les règles personnalisées de Kilo, et indiquez à l'agent où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et faire effectuer le rendu par Kilo dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en demandant à Kilo de comparer son implémentation aux captures d'écran — pas seulement de confirmer que ça compile."]}, {"kind": "p", "text": "Utilisez le mode Architect pour planifier la construction, puis basculez en mode Code et attachez vos références avec des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "# Plan in Architect mode, then build in Code mode:\n> Implement this design from @reference-desktop.png and\n  @reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens\n  from the custom rules.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Kilo quand vous annulez), pour que chaque passe parte d'une base propre."}]}, {"id": "extend", "heading": "Modes, règles personnalisées et MCP", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Kilo Code pratique pour un travail de design soutenu, et tous trois s'alignent parfaitement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Modes (Architect → Code)", "body": "Planifiez la structure d'un écran en mode Architect, puis implémentez-la en mode Code et corrigez les problèmes en mode Debug — séparant l'intention de design de l'implémentation. Les modes personnalisés vous permettent d'encoder une passe de revue de design qui vous est propre."}, {"label": "Règles personnalisées", "body": "Les règles personnalisées de projet constituent le référentiel durable de vos conventions de design — tokens, primitives et checklists de révision — lues à chaque exécution pour que l'agent travaille selon votre marque."}, {"label": "Serveurs MCP", "body": "Kilo prend en charge les serveurs MCP via sa marketplace — la manière portable d'intégrer du contexte de design et des outils externes, notamment un serveur MCP Figma, qui fonctionnent avec tous les agents, pas seulement Kilo."}]}, {"kind": "p", "text": "Ce sont des capacités portables multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Kilo Code", "Open-source et agnostique au modèle avec BYOK pour de nombreux fournisseurs ; modes Architect/Code et MCP", "Choisir votre propre modèle par tâche tout en gardant le contrôle des coûts et des identifiants"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à Kilo Code ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Utilisez un modèle capable de vision pour rendre et auto-vérifier à travers les breakpoints afin que les layouts ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles dans des règles personnalisées", "body": "Placez les règles de style « pas de hero cards, maximum deux typographies, hiérarchie brand-first » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Kilo Code au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Kilo Code comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Kilo performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Les deux sont open-source et local-first, ce qui fait de cette association un choix naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Kilo Code comme agent.", "Authentifiez-vous avec votre propre clé de fournisseur (BYOK) ou la passerelle Kilo — les identifiants restent sur votre machine et ne sont jamais relayés par nos serveurs.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent Kilo Code, mêmes clés — plus un véritable workflow de design open-source et portable autour de lui. Il est local-first et open-source, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Kilo Code peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies images de référence en contexte, Kilo Code produit une interface utilisateur responsive de qualité production, et un modèle doté de vision vérifie la sortie par rapport aux références. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Dois-je payer pour concevoir avec Kilo Code ?", "text": "Kilo Code est open-source et gratuit à installer. Vous apportez votre propre clé API de fournisseur (BYOK) et payez directement ce fournisseur, ou utilisez la passerelle propre de Kilo au coût du fournisseur. Open Design ne proxie jamais vos identifiants dans les deux cas."}, {"name": "Qu'est-ce qui rend Kilo Code particulièrement adapté au design ?", "text": "Il est agnostique de modèle et open-source, vous pouvez donc le piloter avec le modèle capable de vision qui lit le mieux les captures d'écran de référence, inspecter exactement quel contexte est envoyé, et garder coût et identifiants sous votre contrôle. Le goût provient toujours du système de design, du skill et des références que vous fournissez."}, {"name": "Kilo Code ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de conception spécifiques et conscientes du codebase ; l'avantage de Kilo Code est d'être open-source et model-agnostic avec BYOK, vous choisissez donc le modèle. De nombreuses équipes utilisent les deux — Open Design vous permet de changer d'agents sans modifier votre workflow de conception."}, {"name": "Comment connecter Kilo Code à Figma ?", "text": "Ajoutez un serveur MCP Figma depuis la marketplace MCP de Kilo ou les paramètres MCP. Kilo peut alors récupérer un vrai contexte design — composants, variables, données de mise en page — de sorte que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à Kilo Code ?", "text": "Non. Kilo Code est un produit de Kilo Code, Inc. ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur first-party. Tous deux sont open-source, mais ce sont des projets distincts."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et open-source. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants de fournisseur sont utilisés directement par votre agent, jamais routés via les serveurs Open Design."}], "ctaTitle": "Concevez avec Kilo Code, la voie ouverte.", "ctaBody": "Apportez votre propre clé de fournisseur, conservez tous les fichiers en local et obtenez une bibliothèque de conception organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Kilo Code dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'vibe': {
        ...en['vibe']!,
        title: "Mistral Vibe CLI pour le design — Open Design",
        description: "Comment les gens utilisent le Vibe CLI de Mistral pour le design UI et web — ses modèles de codage open-weights Devstral, son édition multi-fichiers agentique, config.toml, MCP et ACP — et comment Open Design transforme Vibe CLI en agent de design open-source et local-first.",
        breadcrumb: "Mistral Vibe CLI",
        label: "Agent · Mistral Vibe CLI",
        heading: "Mistral Vibe CLI pour le design.",
        lead: "Mistral Vibe CLI est l'agent de codage terminal open-source de Mistral AI, alimenté par la famille de modèles Devstral. Il édite des fichiers, exécute des commandes et fonctionne via l'Agent Client Protocol — ce qui en fait un véritable outil de design une fois que vous lui fournissez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open-source : votre clé API Mistral (BYOK) ou modèles locaux, vos fichiers, local d'abord.",
        rich: {"heroCtaLead": "Open Design transforme Mistral Vibe CLI en un agent de design local-first et open-source — votre clé API Mistral ou modèles Devstral locaux, vos fichiers, une bibliothèque de skill et de design-system soigneusement sélectionnée autour de celui-ci.", "heroCtaActions": [{"label": "Utiliser Vibe CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Mistral Vibe CLI est l'agent de codage open-source (Apache-2.0) de Mistral AI pour le terminal. Il analyse la structure de fichiers de votre projet et le statut Git pour le contexte, puis explore, édite et exécute des modifications dans votre base de code à partir de tâches en langage naturel. Deux éléments le rendent particulièrement intéressant pour le design : il est alimenté par les modèles de codage Devstral de Mistral, faisant partie d'un écosystème open-weights que vous pouvez exécuter localement ou dans le cloud ; et il parle l'Agent Client Protocol (ACP), ce qui lui permet de s'intégrer dans les éditeurs et outils plutôt que de vivre uniquement dans un terminal. Associé aux bonnes références, conventions et une boucle de vérification, il construit des interfaces utilisateur réelles et réactives. Ceci est un guide pratique de bout en bout pour utiliser Vibe CLI pour l'interface utilisateur, le frontend et le travail sur les systèmes de design, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Vibe CLI, pourquoi un agent de codage open-weights convient au design, comment le configurer de zéro, la boucle référence vers interface, comment config.toml, MCP et ACP l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first — un jumelage naturel, puisque les deux sont open-source et s'exécutent sur votre propre machine."], "heroImage": {"src": "/agents/vibe-design/vibe-design-hero.webp", "alt": "Boucle de retour design Mistral Vibe CLI : un agent terminal lisant une référence, un navigateur affichant l'interface utilisateur et un espace de travail, avec une flèche de retour bouclant en arrière", "caption": "La boucle principale : Vibe CLI lit vos références dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère en se basant sur elles — alimenté par les modèles de codage Devstral de Mistral."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-vibe", "label": "Ce qu'est réellement Mistral Vibe CLI"}, {"id": "why-design", "label": "Pourquoi un agent de codage à poids ouverts convient au design"}, {"id": "setup", "label": "Configurer Vibe CLI pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow référence-vers-UI"}, {"id": "extend", "label": "config.toml, MCP, et ACP"}, {"id": "vs", "label": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Vibe CLI dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-vibe", "heading": "Ce qu'est réellement Mistral Vibe CLI", "blocks": [{"kind": "p", "text": "Mistral Vibe CLI est un agent de codage open-source (Apache-2.0) que Mistral AI fournit pour le terminal. Il offre une interface de chat interactive avec des outils pour la manipulation de fichiers, la recherche de code, le contrôle de version et l'exécution de commandes, et il analyse automatiquement la structure de fichiers de votre projet et le statut Git pour donner un contexte pertinent à l'agent. Il est alimenté par les modèles de codage Devstral de Mistral — planifiant et vérifiant le travail à partir de tâches en langage naturel plutôt que de simplement compléter des lignes."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés se distinguent. Il fonctionne sur la famille Devstral à poids ouverts de Mistral (Devstral 2 et le plus petit Devstral Small 2), vous pouvez donc exécuter l'agent contre l'API Mistral dans le cloud ou contre des modèles locaux — utile pour un travail de design sensible à la confidentialité ou hors ligne. Et il parle le Agent Client Protocol, le même agent peut donc piloter des éditeurs et des outils, pas seulement une session de terminal."}, {"kind": "steps", "items": [{"label": "Fichiers de configuration", "body": "Vibe CLI se configure via un fichier config.toml (niveau projet ./.vibe/config.toml, avec un repli sur ~/.vibe/config.toml). C'est un emplacement pratique pour encoder vos fournisseurs, le choix de modèle et les paramètres du projet."}, {"label": "Outils intégrés + MCP", "body": "Il fournit des outils de fichier, recherche, contrôle de version et exécution de commandes, et prend en charge les serveurs MCP (configurés sous une section [[mcp_servers]]) pour ajouter un contexte externe comme un fichier Figma actif."}, {"label": "BYOK ou local", "body": "Authentifiez-vous avec une clé API Mistral depuis la console Mistral, ou pointez-le vers des modèles locaux/compatibles pour qu'il fonctionne entièrement hors ligne."}]}, {"kind": "ul", "items": ["Éditeur : Mistral AI", "Identifiant : clé API Mistral (BYOK) depuis la console Mistral, ou modèles locaux / compatibles", "Licence : Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Pourquoi un agent de codage à poids ouverts convient au design", "blocks": [{"kind": "p", "text": "L'avantage design de Vibe CLI vient de sa famille de modèles à poids ouverts et de sa portée protocolaire — mais, comme pour tout agent, le goût doit encore être fourni."}, {"kind": "steps", "items": [{"label": "Modèles de codage Devstral", "body": "Vibe fonctionne sur la famille Devstral de Mistral, des modèles ajustés pour le code et conçus pour un travail agentique multi-fichiers — l'agent édite donc à travers une vraie base de code frontend plutôt que d'émettre des extraits isolés."}, {"label": "À poids ouverts et compatible local", "body": "Devstral Small 2 est suffisamment petit pour fonctionner sur du matériel grand public, permettant au travail de design de rester entièrement local et hors ligne — les références et le code n'ont jamais à quitter votre machine."}, {"label": "Conventions dans config.toml + contexte", "body": "La configuration de projet et vos propres instructions orientent l'agent vers vos tokens, composants et spécifications réelles, pour qu'il travaille selon une marque plutôt qu'un style par défaut."}]}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Vibe CLI n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Vibe CLI pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine vierge jusqu'à un Vibe CLI capable de construire et vérifier une UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Mistral Vibe CLI\nuv tool install mistral-vibe\n# or: pip install mistral-vibe\n\n# 2. Run the setup wizard to register your API key\nvibe --setup     # saves config to ~/.vibe/config.toml and ~/.vibe/.env\n#    or set it directly:  export MISTRAL_API_KEY=...\n\n# 3. Start Vibe in your project\ncd your-project\nvibe\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add an [[mcp_servers]] entry in your config.toml"}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, configurer config.toml, ajouter un skill, vérifier", "caption": "La séquence de configuration : installation → authentification → configuration de config.toml → ajout d'un skill → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Conservez vos tokens, primitives et conventions là où l'agent les lit et pointez Vibe vers eux, afin que le rendu corresponde à une marque plutôt que de recourir par défaut à un aspect générique."}, {"label": "Ajoutez une vérification par navigateur", "body": "Connectez un MCP Playwright ou navigateur pour que Vibe effectue le rendu dans un vrai navigateur et vérifie sa sortie sur tous les breakpoints au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow référence-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Vibe CLI consiste à transformer une référence claire en interface utilisateur fonctionnelle et responsive, puis à itérer jusqu'à ce qu'elle corresponde — en s'appuyant sur les outils de l'agent pour rendre, inspecter et corriger sa propre sortie."}, {"kind": "ol", "items": ["Partez des références les plus claires que vous avez — et décrivez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un modèle performant.", "Conservez votre système de design et vos conventions là où Vibe les lit, et indiquez-lui où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et faire effectuer le rendu par Vibe dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en demandant à Vibe de comparer son implémentation aux références — pas seulement de confirmer que ça compile."]}, {"kind": "p", "text": "Référencez des fichiers avec @ (Vibe autocompléte les chemins de fichiers) et pilotez les commandes slash avec /, puis donnez des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "vibe\n# in the prompt:\n> @design-spec.md @tokens.css\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until\n  it matches the references across breakpoints."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Vibe quand vous annulez), pour que chaque passe partie d'une base propre."}]}, {"id": "extend", "heading": "config.toml, MCP, et ACP", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Vibe CLI pratique pour un travail de design soutenu, et tous trois s'alignent parfaitement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "config.toml", "body": "Les règles de projet et les paramètres de fournisseur/modèle résident dans un config.toml (au niveau projet, avec repli sur ~/.vibe). C'est le référentiel durable de la façon dont l'agent est connecté à votre projet, lu à chaque exécution."}, {"label": "Serveurs MCP", "body": "Configurez les serveurs MCP dans votre config.toml ([[mcp_servers]], avec les transports HTTP, streamable-HTTP et stdio) — la manière portable d'intégrer le contexte de design et les outils externes, notamment le serveur MCP Figma, qui fonctionnent entre agents, pas seulement avec Vibe."}, {"label": "Agent Client Protocol", "body": "Vibe parle ACP, donc le même agent peut être piloté depuis les éditeurs et d'autres clients ACP. C'est exactement ainsi qu'Open Design l'intègre — via ACP par le binaire vibe-acp."}]}, {"kind": "p", "text": "Ce sont des capacités portables multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Mistral Vibe CLI", "Modèles de codage Devstral à poids ouverts que vous pouvez exécuter localement ; Apache-2.0 et natif ACP", "Travail de design sensible à la vie privée ou hors ligne et pile open-weights"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et une très large fenêtre de contexte", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus fréquente concernant le design généré par IA est qu'il paraît générique — dégradés doux, panneaux flottants, coins arrondis surdimensionnés, ombres dramatiques, une ambiance Inter-and-purple qui « crie qu'une IA l'a fait ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui fuient dans le texte d'interface. Aucun de ces défauts n'est propre à Vibe CLI ; ce sont les conséquences de tout agent qui tourne sans contexte de design soigné."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Faites en sorte que Vibe effectue un rendu et une auto-vérification sur tous les breakpoints afin que les layouts ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles dans la config et le contexte", "body": "Placez les règles de style « pas de hero cards, maximum deux typographies, hiérarchie brand-first » là où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Vibe CLI à l'intérieur d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Mistral Vibe CLI comme un adaptateur first-party — en le pilotant via ACP via le binaire vibe-acp — et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale. Ainsi, le contexte de conception qui rend Vibe performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Les deux sont open-source et local-first, ce qui fait de cette association un choix naturel."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Mistral Vibe CLI comme agent.", "Authentifiez-vous avec votre clé API Mistral (BYOK) ou pointez Vibe vers des modèles locaux — les identifiants restent sur votre machine et ne sont jamais proxiés via nous.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent CLI Vibe, même clé — plus un véritable workflow de design open-source et portable autour de lui. Il est local-first et Apache-2.0, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Mistral Vibe CLI peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies références en contexte, Vibe CLI produit une interface utilisateur responsive de qualité production, et ses modèles Devstral éditent à travers une vraie base de code frontend. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Comment authentifier Vibe CLI ?", "text": "Exécuter l'assistant de configuration avec vibe --setup pour enregistrer une clé API Mistral (depuis la console Mistral), ou définir MISTRAL_API_KEY dans votre environnement. Il peut également fonctionner avec des modèles locaux ou compatibles, entièrement hors ligne. Open Design ne proxie jamais vos identifiants, de toute façon."}, {"name": "Qu'est-ce qui rend Vibe CLI particulièrement adapté au design ?", "text": "C'est un agent Apache-2.0, natif ACP, propulsé par les modèles de codage open-weights Devstral de Mistral — vous pouvez donc l'exécuter localement pour un travail sensible en confidentialité et éditer sur une base de code réelle. Mais le goût provient toujours du système de design, du skill et des références que vous fournissez."}, {"name": "Vibe CLI ou Claude Code pour le design frontend ?", "text": "Les deux sont solides. Claude Code est reconnu pour ses décisions de conception spécifiques et conscientes du codebase ; l'avantage de Vibe CLI est une stack Devstral open-weights que vous pouvez exécuter localement et une licence Apache-2.0. De nombreuses équipes utilisent les deux — Open Design vous permet de changer d'agents sans modifier votre workflow de conception."}, {"name": "Comment connecter Vibe CLI à Figma ?", "text": "Ajoutez le serveur MCP Figma comme entrée [[mcp_servers]] dans votre config.toml. Vibe peut alors récupérer un vrai contexte design — composants, variables, données de mise en page — de sorte que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à Mistral AI ?", "text": "Non. Mistral Vibe CLI est un produit de Mistral AI ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur first-party, piloté via ACP. Mistral est une marque déposée de Mistral AI."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Mistral sont utilisés directement par votre agent, jamais routés via les serveurs Open Design."}], "ctaTitle": "Concevez avec Mistral Vibe CLI, la voie ouverte.", "ctaBody": "Apportez votre propre clé API Mistral ou modèles locaux, conservez tous les fichiers en local et obtenez une bibliothèque de conception organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Vibe CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
      'qoder': {
        ...en['qoder']!,
        title: "Qoder CLI pour le design — Open Design",
        description: "Comment les gens utilisent Qoder CLI — la plateforme de codage agentique d'Alibaba — pour le design UI et web : ses modes agent et quest, sa compréhension approfondie du dépôt et son wiki de repo, et ses niveaux de modèles Lite/Efficient/Auto — et comment Open Design transforme Qoder CLI en agent de design open-source et local-first.",
        breadcrumb: "Qoder CLI",
        label: "Agent · Qoder CLI",
        heading: "Qoder CLI pour le design.",
        lead: "Qoder CLI est l'agent terminal de Qoder, la plateforme de codage agentique d'Alibaba. Il comprend un dépôt entier — architecture, motifs et conventions capturés dans son wiki de dépôt — et exécute du travail autonome piloté par spécification, ce qui en fait un véritable outil de design une fois que vous lui fournissez des références, des conventions et une boucle de vérification. Open Design l'intègre dans un workflow de design open-source : votre compte Qoder, vos fichiers, local-first.",
        rich: {"heroCtaLead": "Open Design transforme Qoder CLI en un agent de design local-first et open-source — votre compte Qoder, vos fichiers, une bibliothèque de skill et de design-system soigneusement sélectionnée autour de celui-ci.", "heroCtaActions": [{"label": "Utiliser Qoder CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qoder CLI est l'agent terminal de Qoder, la plateforme de codage agentique d'Alibaba. Deux aspects le rendent particulièrement intéressant pour le design : il construit un contexte approfondi sur votre dépôt — architecture, motifs de design et conventions qu'il distille dans un wiki de dépôt — afin de réutiliser vos véritables primitives au lieu d'inventer des styles ponctuels ; et il exécute des quêtes autonomes pilotées par spécification qui planifient, implémentent et vérifient une tâche de bout en bout plutôt que de simplement compléter des lignes. Associé aux bonnes références, conventions et une boucle de vérification, il construit de véritables UI responsives. Ceci est un guide pratique de bout en bout pour utiliser Qoder CLI dans le travail d'UI, de frontend et de design system, et pour l'intégrer dans un workflow de design structuré avec Open Design.", "Il couvre ce qu'est réellement Qoder CLI, pourquoi sa compréhension du dépôt et ses quests agentiques conviennent au design, comment le configurer de zéro, la boucle référence vers interface, comment les règles, MCP et le wiki du dépôt l'étendent, comment il se compare à Codex, Claude Code, Cursor et Gemini CLI, les écueils qui donnent un aspect générique aux sorties IA, et comment Open Design comble l'écart en tant que couche de design ouverte et local-first autour de l'agent que vous utilisez déjà."], "heroImage": {"src": "/agents/qoder-design/qoder-design-hero.webp", "alt": "Boucle de feedback design Qoder CLI : un agent terminal lisant une image de référence avec le contexte du wiki du dépôt, un navigateur rendant l'UI, et un espace de travail, avec une flèche de feedback bouclant en retour", "caption": "La boucle principale : Qoder CLI lit vos références et le contexte du dépôt dans le terminal, construit et vérifie l'UI dans un vrai navigateur, et itère en se basant sur elles."}, "tocLabel": "Sur cette page", "toc": [{"id": "what-is-qoder", "label": "Ce qu'est réellement Qoder CLI"}, {"id": "why-design", "label": "Pourquoi agentique + contexte repo conviennent au design"}, {"id": "setup", "label": "Configurer Qoder CLI pour le design (à partir de zéro)"}, {"id": "screenshot-workflow", "label": "Le workflow référence-vers-UI"}, {"id": "extend", "label": "Règles, MCP et wiki du dépôt"}, {"id": "vs", "label": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pièges et l'aspect « contenu IA générique »"}, {"id": "open-design", "label": "Concevoir avec Qoder CLI dans Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qoder", "heading": "Ce qu'est réellement Qoder CLI", "blocks": [{"kind": "p", "text": "Qoder est une plateforme de codage agentique d'Alibaba — un environnement de développement IA, disponible en application desktop et en CLI, qui comprend de véritables codebases et gère les tâches de développement de bout en bout. Qoder CLI apporte ce moteur au terminal : il lit votre dépôt, modifie des fichiers, exécute des commandes shell et traite les tâches à partir du langage naturel plutôt que de simplement compléter des lignes. Il se connecte avec un compte Qoder."}, {"kind": "p", "text": "Pour le travail de design, deux propriétés se distinguent. Qoder construit un contexte approfondi sur votre dépôt — architecture, modèles de design et conventions distillées dans un wiki de dépôt — il ancre donc la production dans vos véritables primitives. Et il exécute un workflow agentique piloté par spécification : vous décrivez ce que vous voulez et il planifie, implémente et vérifie le travail, y compris sur plusieurs étapes."}, {"kind": "steps", "items": [{"label": "Modes Agent et Quest", "body": "Le mode Agent est une programmation en binôme conversationnelle avec des points de contrôle humains ; le mode Quest délègue un travail plus long et multi-étapes à un agent autonome qui planifie, implémente et s'auto-vérifie — l'endroit naturel pour confier une tâche design pilotée par des specs."}, {"label": "Wiki du dépôt + MCP", "body": "Qoder distille votre codebase dans un wiki de dépôt d'architecture et de conventions, et prend en charge les serveurs MCP pour apporter du contexte externe comme un fichier Figma en direct."}, {"label": "Niveaux de modèles", "body": "Qoder CLI expose les paliers Lite, Efficient et Auto ; Auto laisse son planificateur choisir un modèle par tâche, vous n'avez donc pas à gérer la sélection de modèle manuellement."}]}, {"kind": "ul", "items": ["Fournisseur : Alibaba", "Identifiant : compte Qoder (connexion via navigateur, ou jeton d'accès personnel Qoder pour usage non interactif)", "Niveaux de modèles : Lite, Efficient, Auto"]}]}, {"id": "why-design", "heading": "Pourquoi un agent agentique et conscient du repo convient au design", "blocks": [{"kind": "p", "text": "L'avantage design de Qoder CLI vient de deux propriétés — mais, comme avec tout agent, le goût doit encore être fourni."}, {"kind": "steps", "items": [{"label": "Compréhension approfondie du dépôt", "body": "Parce que Qoder construit du contexte sur l'ensemble de votre base de code et le distille dans un wiki de dépôt, l'agent réutilise vos composants et tokens existants au lieu d'inventer des styles ponctuels pour chaque écran."}, {"label": "Quests autonomes pilotées par spécifications", "body": "Le mode Quest transforme une spécification écrite en un résultat planifié, implémenté et auto-vérifié, de sorte qu'une tâche de design s'exécute de bout en bout plutôt que de s'arrêter à un premier brouillon."}, {"label": "Conventions que l'agent lit", "body": "Les règles de projet (plus le serveur MCP Figma) orientent l'agent vers vos tokens, composants et spécifications réelles, pour qu'il travaille selon une marque plutôt qu'un style par défaut."}]}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-taste-triangle.webp", "alt": "Diagramme montrant le design system, le skill et l'image de référence convergeant vers un bon résultat de design", "caption": "Le goût provient de trois éléments que vous fournissez : un système de design, un skill et des images de référence réelles."}, {"kind": "p", "text": "La leçon est la même que celle enseignée par chaque agent : Qoder CLI n'a pas de goût par défaut. Il produit un bon design lorsque vous lui donnez des contraintes — un design system, un skill esthétique et des références concrètes. Open Design regroupe exactement ces entrées, c'est pourquoi les deux s'assemblent si bien (plus de détails ci-dessous)."}]}, {"id": "setup", "heading": "Configurer Qoder CLI pour le travail de design, à partir de zéro", "blocks": [{"kind": "p", "text": "Voici le chemin complet depuis une machine vierge jusqu'à un Qoder CLI capable de construire et vérifier une UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qoder CLI (Node 20+)\nnpm install -g @qoder-ai/qodercli\n# (macOS/Linux via Homebrew also available)\n\n# 2. Verify the install\nqodercli --version\n\n# 3. Start it in your project and sign in on first run\ncd your-project\nqodercli          # then /login — sign in via browser or a Qoder access token\n\n# 4. Pick a model tier for the session\n#    Lite, Efficient, or Auto (Auto lets the scheduler choose per task)"}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-setup-flow.webp", "alt": "Flux de configuration en cinq étapes : installer, s'authentifier, configurer les règles, ajouter un skill, vérifier", "caption": "La séquence de configuration : installation → connexion → configuration des règles projet → ajout d'un skill → activation de la vérification navigateur."}, {"kind": "steps", "items": [{"label": "Encodez vos règles de conception", "body": "Placez vos tokens, primitives et conventions là où l'agent les lit, pour que la sortie corresponde à une marque plutôt qu'un style générique par défaut. Le wiki du dépôt de Qoder aide à maintenir ce contexte à jour."}, {"label": "Ajoutez une vérification par navigateur", "body": "Connectez un MCP Playwright ou navigateur pour que Qoder effectue le rendu dans un vrai navigateur et vérifie sa sortie sur tous les breakpoints au lieu de confirmer seulement que le build passe."}]}]}, {"id": "screenshot-workflow", "heading": "Le workflow référence-vers-UI", "blocks": [{"kind": "p", "text": "La boucle de design la plus efficace avec Qoder CLI consiste à transformer une référence en interface utilisateur fonctionnelle et responsive, puis à itérer jusqu'à ce qu'elle corresponde — en s'appuyant sur le contexte du dépôt de l'agent et une véritable boucle de vérification pour comparer le résultat à la référence."}, {"kind": "ol", "items": ["Partez des références visuelles les plus claires que vous avez — et incluez plusieurs états (desktop et mobile, hover, vide, chargement), pas seulement un seul écran héroïque.", "Soyez précis dans le prompt ; des prompts vagues produisent une interface générique même avec un agent capable.", "Dirigez Qoder vers votre design system et vos conventions, et indiquez-lui où se trouvent les tokens et les primitives canoniques.", "Lancer un serveur de développement et faire effectuer le rendu par Qoder dans un vrai navigateur, en redimensionnant aux points de rupture pour vérifier le résultat.", "Itérez en demandant à Qoder de comparer son implémentation aux références — pas seulement de confirmer que ça compile."]}, {"kind": "p", "text": "Rédigez la tâche sous forme de spécification claire et laissez un quest la mener à bien, en donnant des contraintes concrètes :"}, {"kind": "code", "lang": "bash", "code": "qodercli\n# in the prompt:\n> Implement this design from reference-desktop.png and\n  reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Gardez les prompts courts et concentrés, commitez les bonnes itérations et annulez les mauvaises (en indiquant à Qoder quand vous annulez), pour que chaque passe parte d'une base propre."}]}, {"id": "extend", "heading": "Règles, MCP et wiki du dépôt", "blocks": [{"kind": "p", "text": "Trois points d'extension rendent Qoder CLI pratique pour un travail de design soutenu, et tous trois s'alignent parfaitement sur un workflow de design ouvert."}, {"kind": "steps", "items": [{"label": "Règles de projet", "body": "Encodez vos conventions de conception sous forme de règles de projet durables que l'agent lit à chaque exécution — le référentiel pour les tokens, les primitives et les listes de vérification de revue."}, {"label": "Serveurs MCP", "body": "MCP est le moyen portable d'apporter du contexte de design et des outils externes, notamment le serveur MCP Figma, et il fonctionne avec tous les agents, pas seulement Qoder."}, {"label": "Le wiki du dépôt", "body": "Le wiki de dépôt de Qoder distille automatiquement l'architecture et les conventions, de sorte que l'agent continue de réutiliser vos vrais composants au lieu de réapprendre la codebase à chaque tâche."}]}, {"kind": "p", "text": "Ce sont des capacités portables multi-agents — exactement le genre de choses qu'Open Design est conçu pour orchestrer, plutôt que de recréer par projet."}]}, {"id": "vs", "heading": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI pour le design", "blocks": [{"kind": "p", "text": "Il n'y a pas de gagnant unique pour le travail de design — chaque agent a une force différente, et les équipes expérimentées les superposent. Un résumé équitable :"}, {"kind": "table", "columns": ["Agent", "Force de conception", "Best for"], "rows": [["Qoder CLI", "Compréhension approfondie du dépôt avec un wiki de dépôt et des quêtes autonomes pilotées par spécifications ; niveaux Lite/Efficient/Auto", "Travail fortement contextuel au dépôt et délégation de builds multi-étapes pilotés par spécifications"], ["Codex", "Finition visuelle soignée avec un skill frontend ; builds asynchrones en sandbox", "Builds asynchrones délégués et règles AGENTS.md portables"], ["Claude Code", "Décisions de design précises (hex, espacement, typo) et UX tenant compte du codebase", "Raisonnement frontend et refactorisations à large contexte"], ["Cursor", "Boucle visuelle construire-et-voir avec aperçu en direct et éditions en ligne", "Itération rapide et observation du travail UI dans un IDE"], ["Gemini CLI", "Forte compréhension multimodale des images et un contexte de 1M tokens ; offre gratuite", "Travail riche en captures d'écran et maintien d'un design system complet en contexte"]]}, {"kind": "p", "text": "Le verdict récurrent de la communauté est que le goût vient des humains : tous adoptent par défaut une esthétique générique sans skills, références et contraintes. C'est le vrai problème à résoudre — et il a la forme d'un outil de design, pas d'un modèle."}]}, {"id": "pitfalls", "heading": "Pièges, et comment éviter l'aspect « contenu IA générique »", "blocks": [{"kind": "p", "text": "La plainte la plus courante concernant le design généré par IA est qu'il a l'air générique — des dégradés doux, des panneaux flottants, des coins arrondis surdimensionnés, des ombres dramatiques, une ambiance Inter-et-violet qui « crie qu'une IA l'a créé ». D'autres problèmes signalés incluent des mises en page mobiles cassées et des instructions qui se glissent dans le texte de l'interface. Aucun de ces éléments n'est propre à Qoder CLI ; c'est ce qui se produit lorsque n'importe quel agent s'exécute sans contexte de design organisé."}, {"kind": "steps", "items": [{"label": "Ajoutez un skill esthétique", "body": "Un skill design organisé force l'agent à s'engager vers une direction réelle plutôt que le style par défaut."}, {"label": "Vérifier dans un véritable navigateur", "body": "Effectuer le rendu et vérifier automatiquement sur tous les points de rupture afin que les mises en page ne se cassent pas silencieusement sur mobile."}, {"label": "Fournir des tokens et des références", "body": "De véritables tokens de design et des captures d'écran de référence constituent le levier le plus important sur la qualité de sortie."}, {"label": "Encoder les règles que l'agent lit", "body": "Placez des règles de style comme « pas de hero cards, maximum deux polices, hiérarchie brand-first » dans les règles de projet et le wiki du dépôt, où l'agent les lit à chaque exécution."}]}, {"kind": "p", "text": "Notez que chaque mesure d'atténuation consiste à fournir à l'agent un contexte de conception soigné. Maintenir ce contexte manuellement, projet par projet, est la corvée qu'Open Design supprime."}]}, {"id": "open-design", "heading": "Concevoir avec Qoder CLI au sein d'Open Design", "blocks": [{"kind": "p", "text": "Open Design est la couche de conception open-source que le workflow ci-dessus ne cesse de demander. Il traite Qoder CLI comme un adaptateur first-party et l'enveloppe dans une bibliothèque de skill et de système de conception soignée, un pipeline de rendu structuré et une interface de bureau locale — de sorte que le contexte de conception qui rend Qoder performant est là dès la première exécution, sans être assemblé manuellement à chaque fois. Open Design est local-first, vos travaux restent donc sur votre propre machine."}, {"kind": "ol", "items": ["Installez Open Design et sélectionnez Qoder CLI comme agent.", "Authentifiez-vous avec votre compte Qoder — les identifiants restent sur votre machine et ne sont jamais proxiés via nous.", "Choisissez un design system et un skill, puis générez des decks, des prototypes et des landing pages avec un goût cohérent.", "Chaque artifact et fichier DESIGN.md réside dans votre propre dépôt, pas dans un cloud hébergé."]}, {"kind": "p", "text": "Même agent CLI Qoder, même compte — plus un véritable workflow de design open-source et portable autour de lui. Il est local-first et Apache-2.0, donc rien concernant votre travail ou vos identifiants ne quitte votre machine."}]}], "faqTitle": "Questions fréquemment posées", "faq": [{"name": "Qoder CLI peut-il vraiment faire du travail de design ?", "text": "Oui — avec un skill esthétique, un système de design et de vraies images de référence en contexte, Qoder CLI produit une interface utilisateur responsive de qualité production, et sa compréhension approfondie du dépôt l'aide à réutiliser vos vrais composants. Sans ce contexte, il a tendance à adopter un aspect générique, ce qui est le fossé que Open Design comble."}, {"name": "Comment authentifier Qoder CLI ?", "text": "Exécuter qodercli et utiliser /login pour vous connecter avec votre compte Qoder via le navigateur, ou fournir un jeton d'accès personnel Qoder pour les environnements non interactifs. Open Design ne proxie jamais vos identifiants — l'agent les utilise directement."}, {"name": "Qu'est-ce qui rend Qoder CLI particulièrement adapté au design ?", "text": "Deux éléments : il construit un contexte approfondi de votre dépôt — architecture, conventions et wiki du dépôt — afin de réutiliser vos véritables primitives, et ses quests pilotées par spécifications exécutent une tâche de design de bout en bout. Les deux aident, mais le goût provient toujours du design système, du skill et des références que vous fournissez."}, {"name": "Que sont les niveaux de modèles Lite, Efficient et Auto ?", "text": "Qoder CLI vous permet de choisir un palier de modèle : Lite, Efficient ou Auto. Auto laisse le planificateur de Qoder choisir un modèle par tâche, vous n'avez donc pas à gérer la sélection de modèle manuellement. Choisissez le palier qui correspond au travail ; Auto est un choix par défaut sensé."}, {"name": "Comment connecter Qoder CLI à Figma ?", "text": "Ajoutez le serveur MCP Figma à la configuration MCP de Qoder. Qoder peut alors récupérer un vrai contexte design — composants, variables, données de mise en page — de sorte que le code généré corresponde à la source au lieu de l'approximer."}, {"name": "Open Design est-il affilié à Qoder ou Alibaba ?", "text": "Non. Qoder est un produit d'Alibaba ; Open Design est un projet open-source indépendant qui le prend en charge en tant qu'adaptateur first-party. Qoder est une marque déposée de son propriétaire respectif."}, {"name": "Mes fichiers et identifiants sont-ils en sécurité ?", "text": "Oui — Open Design est local-first et Apache-2.0. Vos fichiers, artifacts et DESIGN.md restent dans votre propre dépôt, et vos identifiants Qoder sont utilisés directement par votre agent, jamais routés via les serveurs Open Design."}], "ctaTitle": "Concevez avec Qoder CLI, la voie ouverte.", "ctaBody": "Apportez votre propre compte Qoder, conservez tous les fichiers en local et obtenez une bibliothèque de conception organisée autour de l'agent que vous utilisez déjà.", "ctaActions": [{"label": "Utiliser Qoder CLI dans Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Star sur GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Télécharger l'application de bureau", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Voir tous les agents pris en charge"},
      },
    },
  };
}
